insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='MARTIN'and apellido2='CALLE'),'2017-05-18','Llama la hija,Puerto t/c 661 273 204, necesita el DNI de la madre tutelada para hacer la declaración de herederos puesto que la abuela ha fallecido. Indica que se lo requieren en la notaría, también nos dice que ya había llamado anteriormente para comunicar el fallecimiento de la madre de Mª Jesús. Le indicamos que como tutor es la Comisión quien debe de realizar esa gestión. Nos ponemos en contacto con la notaría de Plasencia donde nos dice se están realizando las gestiones, Francisco de Asís Jiménez Velasco t/c 927 411 447, dicen no necesitar el DNI, les basta con el número o bien fotocopia. Cuando necesiten la firma de Mª Jesús se pondrán en contacto con nosotros.','2');
