insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2017-05-22','Conversación con Carmen, T. Soc. ESM Valdepasillas (42853): +++La CITA en el ESM se ADELANTA al 16 de junio a las 11:10h. +++Ir ese mismo día para hablar con María .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2017-05-22','Conversación con Dª Araceli (924 575077) y D. Luis, madre y hermano de Ildefonso : +++Su madre comenta que hace un año que no va la ESM de ZAfra, aunque sí se pone la inyección todos los meses...pero los otro medicamentos se los toma cuando quiere. +++El viernes llamron a la Guardia Civil y el Juzgado nº 1 de Zafra decretó Órden de Alejamiento (nos dicen). +++Desde entonces está viviendo en casa de un amigo próxima a la Ermita de Belén y, segúin dice su madre, envía al amigo "como él no se puede acercar..." para malmeter al hermano. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con María, T. Soc.del ESM de Zafra: +++Informo de la conversación con la madre y hermano de Ildefonso. +++Idelfonso tiene cita en Enfermería para inyectable mañana, 23 de mayo y el día 29 de mayo consulta de Psiquiatría. +++Pendiente de hablar mañana sobre evolcuión de dichas citas. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Gema, T. Soc. del SSB de Puebla. +++Está elaborando el informe solicitado. Le informo de los trámites seguidos con el ESM y la conversación con la familia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='SOLIS'and apellido2='BERMEJO'),'2017-02-11','SALIDA El 11/02/2017. Convivencia Hospitalidad Lourdes en Cáceres. Hora salida: 11 horas, hora regreso: 19 horas. Transporte en el autobús de la Hospitalidad. Acompañada por Voluntarios.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='SOLIS'and apellido2='BERMEJO'),'2017-03-15','SALIDA El 15/03/2017. Actividad Musical en Cáceres. Hora salida: 9 horas, hora regreso: 14 horas. Transporte con el autobús del centro. Acompañada por Andrés Torres, Viki Román, Javier Sancho, Jesús Arriero, Luismi Herrero, Candela Martín, Juanjo Sánchez, Maribel Gutiérrez, Juana de Andrés, Nandi Prieto, Felipe Cantero y Cuadalupe Gallego. Desayunan a las 8 horas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2017-05-22','Conversación con Clemen: +++Se le envía el Acta de la Subcomisión Regional de Casos. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Juzgado nº 2 de Castuera: +++SE le renite también el Acta de dicha Subcomisión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2017-05-23','Llama María Jesús Moro, t/c 924 21 61 67, maria-jesus.moro@seg-social.es, de la Seguridad Social en referencia a la petición de la pensión de orfandad. Necesita certificado literal de matrimonio de Carmen para saber si en el año del fallecimiento de su padre, 1997, estaba ya divorciada. Indica también que de oficio va a comprobar los años que el padre estuvo trabajando en Alemania para ver si tiene el mínimo de años que ayude a la concesión de la pensión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FERNANDEZ'and apellido2='BERMEJO'),'2017-05-23','Llama Maribel, T.S. de la residencia, t/c 927 24 44 21, indicando que Rafael va a tener que ir a diálisis dos veces por semana en lugar de una como hasta ahora. Quiere saber si necesita ir acompañado siempre, pues supondría incrementar los gastos. En la actualidad paga a una auxiliar 25€ por viaje.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2017-05-23','PRESTACIÓN El 12/05/2017. Concedida PF por hijo o menor a cargo. Importe: 368.90€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2017-05-23','Conversación con María, T.Soc.del ESM de Zafra: +++Ildefonso ha acudido a la consulta de Enfermería esta mañana a ponerse el inyectable. LO ha visto también el Psiquiatra y le mantiene la consulta del día 29 de mayo. VALORACIÓN: NO SE ENCUENTRA EN FASE DELIRANTE NI SE APRECIAN MOTIVOS DE INGRESO +++DE motu propio les ha informado de la denuncia que la pasada semana hicieron su madre y hermano, quitándose él toda responsabilidad sobre lo ocurrido. +++ESTÁ VIVIENDO EN ZAFRA, en el HOSTAL "ARIAS" (25€/noche porque no le han querido alquilar un apartamento). En el Hostal me han confirmado que esta mañana ha reservado habitación. +++SUS PLANES: alquilar una casa, no quiere un piso porque se agobia mucho en ellos. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamada de Dª Araceli, hermana de Ildefonso que vive en Manacor (971-559603): +++Manifiesta una gran preocupación por la situación en la que se encuentra su hermano, porque "MI HERMANO TENÍA QUE ESTAR INGRESADO DESDE QUE MURIÓ MI PADRE HACE 20 DÍAS..." +++SE informa de las gestiones que desde la Comisión se están haciendo, pero cree que lo que necesita su hermano es un seguimineto en el día a día mientras está bien y un ingreso cada vez que entre en crisis. "...YO LO QUE LE DIGO ES QUE SI A MI HERMANO NO LO INGRESAN, ALGO GORDO VA A PASAR Y A VER QUIÉN ES ENTONCES EL RESPONSABLE..." ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++LLamo a Dª Araceli, madre de Ildefonso, a petición de su hija Araceli porque considera esta que la información que le he dado a ella puede tranquilizar a su madre: +++Informo a Dª Araceli de que su hijo ha ido esta mañana al ESM y se ha puesto la inyección, y que seguimos atendiendo a su situación. Dª Araceli agradece que la hayamos llamado y se queda algo más tranquila. +++SE le inoforma de que su hijo ahora está viviendo en Zafra, a lo que responde que esta misma mañana lo han visto en Puebla. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llama D. Luis, hermano de Ildefonso: +++"Como se acerque por aquí lo denuncio, pero es que no quiero perjudicarlo..." La Comisión apoyaría esa decisión encaso necesario. +++Se aconseja LLAMAR AL 112 informando de la ÓRDEN DE ALEJAMIENTO EXISTENTE Y SOLCITANDO LA PRESENCIA DE LA GUARDIA CIVIL Y LOS SERVICIOS SANITARIOS, "PERO YO NO QUIERO DARLE ESE DISGUSTO A MI MADRE."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FERNANDEZ'and apellido2='BERMEJO'),'2017-05-24','Conversación con Maribel: +++Es una persona con ciertas dificultades de movilidad pero que podría ir solo en la ambulancia. +++TEMOR: dada su insistencia a marcharse de nuevo a su pueblo podría suceder que, una vez en el hospital, se marchase por su cuenta. +++LO COMENTARÁ CON EL EQUIPO MÉDICO Y LA Comisión apoyará su posición.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2017-05-24','Llamo a Idefonso, al teléfono 625-245891: +++Salta el contestador de Orange indicando que tiene las llamadas entrantes restringidas. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a Gema, T.Soc. SSB (924-575709 y 673-595805): +++Le informo de los pasos dados y la inofrmación recibida en la mañana de ayer. +++Ha llegado la Orden de Alejamiento al Jefe de la Policía Local pero todavía no a los Servicios Sociales, como es lo habitual. +++Enviará el Informe solicitado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2017-05-24','DEPENDENCIA El UGRDS informa que "figura como solicitante del reconocimiento de la situación de ependencia y del erecho a las prestaciones del sistema desde el 29/12/2014, con número de expediente CMI-04971-14, habiendo sido reconocido con un Grado III GRAN DEPENDENCIA."************* Así mismo, le renoció, con fecha 10/01/2017, el derecho al SAR en el CR El Cuartillo.*********************************ACTUALMENTE NO RESIDE ALLÍ (ABANDONÓ EL CENTRO EL 20/02/2017). SEGÚN PARECE VOLVIÓ A SU PUEBLO (ALCUÉSCAR). SE ESTÁ A LA ESPERA DE LA CONTESTACIÓN DE LOS SSB, A LOS QUE SE LE SOLICITÓ INFORME PARA EL INVENTARIO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2017-05-24','Conversación con Toni (Futuex): +++Tienen pendiente una visita a José Mª. +++SE pondrán en contacto con la Inmobiliaria Domus.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2017-05-24','Convesración con Toni (Futuex): +++La venta de los lechones tiene que esperar a que pongan 10Kg de peso. Está de acuerdo en que se realice en jueves, que es cuando Silvia acude a la visita. +++Lolo, el primo de Ramón, está dispuesto a cuidar de los animales por 100€/mes. Quedó con Silvia en que cuando empezase a cuidarlos nos enviaría el número de cuenta donde ingresarlos. Hasta entonces nada.','2');
