insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TERESA'and edp.apellido1='NEVADO'and apellido2='MARTIN'),'2017-05-25','Llamada de Dª Marta Nevado, hermana, (615-501169): +++Volverá a hablar con su hermana para que llame a la Notaría de Valencia de Alcántara o que nos llamen desde allí a la CTAEx (no hemos podido contactar últimamente).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2017-05-25','Llamada desde el 927-424828: +++SE trata del teléfono de D. Carlos Flores LLorente. Dice ser amigo de Jairo ( su jefe en la tienda de ropa) y que le deja el teléfono de vez en cuando para llamar. Dice que quería habalr conmigo esta mañana pero que no me ha localizado. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a Mariví al CSS de Plasencia para valorar esta situación: +++Confirma que conocen a los padres de D. Carlos, dueños de una tienda de ropa en la que Jairo estuvo "ayudando" hace unos años. Esta familia siempre le ha ayudado todo lo que ha podido y en esta ocasión seguramente se trata también de ayudarlo. +++HAN PASADO A JAIRO a LARGA ESTANCIA: es una Unidad con un menor nivel de exigencia. Ahora se ocupa de él ALBA, T. Soc.','2');
