insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCA'and edp.apellido1='POLO'and apellido2='CORTES'),'2017-05-31','ARCHIVO Se procede a archivar la Def. Jud. El Juzgado, mediante Sentencia 9/17, de 23 de enero, nombra Tutora, de Dña. Francisca, a Dña. Milagrosa Preciado Polo.******************Mediante Diligencia de Ordenación, de 18/05/2017, el juzgado confirma la firmeza de la Sentencia, pero deja constancia, también, de que el cargo no había sido aceptado, aún, por Dña. Milagrosa.','2');
