insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-05-31','Pendiente de aceptar el cargo. +++Médico de Atención Primaria (MAP): Dr. Francisco Guerra Pecero. Tel. C. Salud Huerta de Ánimas: 927-322363).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CARDOSO'and apellido2='SILVA'),'2017-06-01','Llaman de la residencia de Barcarrota para que nos pongamos en contacto con MªJosé para proceder al pago del servicio de acompañamiento a Francisco en el hospital. Llamamos a Mª José, nos mandará factura para hacerle la transferencia. (Iciar)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2017-06-01','Conversación con Mariola: +++Juan, hermano, quiere un certificado para el SSB para justificar la unidad de convivencia. Ha presentado declaración jurada en Ayto. +++Ramón sigue en casa, aunque el sábado volvieron a activar el 112, pero al parecer la ambulacia no llegó porque tuvo algún problema.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2017-06-01','Nos llama Mª Luisa solicitando 500€ para ir durante un mes con su hermana a San Fernando (Cádiz) comentando que la van a operar y quiere estar con ella. Contactamos con su hermana Carolina para corroborar la información y nos indica que ninguna de las hermanas se tienen que operar de nada ni tampoco tienen familia en esa localidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2017-06-01','Convresación con Eva, T. Soc. de la Residencia de la Hermanas de los Ancianos Desamparados: +++se envía por correo-e modelo de Informe Médico para su cumplimentación , a fin de tramitar ingreso en residencia. +++fax:924-258106 +++correo-e: tsbadajoz@hhaadd.org','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2017-06-02','Hablo con María Barrasa T.S. del Sociosanitario. Le indico necesitamos certificado de residencia en el centro de Ramón a petición del Jdo nº 1 de Jerez de los Caballeros al que hemos llamado esta mañana en relación al procedimiento 463/2014. Nos lo envía, pero dice el juzgado debería ya saberlo pues vino derivado del Infanta Cristina. Comenta que Ramón llegó sin ropa ni artículos de aseo.La familia quedó en llevarle algo pero no lo hicieron pues todo lo que tenía era inservible, por lo que ante la imposibilidad de contactar con nosotros han hecho un reintegro de la cuenta de Ramón de 500€ el día 24 de mayo, con una autorización previa, para comprarle lo que necesita. También pide información sobre la posibilidad de que Ramón pueda vivir en un piso tutelado una vez que deje el centro. Se ha adaptado perfectamente a la UME, y es una persona entrañable. Iciar','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='MENDO'and apellido2='RODRIGUEZ'),'2017-05-12','SE informa a Blanca, T. Sodc. del CSS de Mérida, de la contestación del Juzgado a la demanda planteada por D. Pedro, para que se le comunique a él. +++Cuando vayamos al CSS hablaremos de ello con él personalmente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NELSON JOSE'and edp.apellido1='CAMPOS'and apellido2='DIAZ'),'2017-06-05','FUGA El 01/06/2017. El CSS de Merida informa, vía fax, que Nelson José se ausentó del centro sin permiso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NELSON JOSE'and edp.apellido1='CAMPOS'and apellido2='DIAZ'),'2017-06-05','REGRESO El 02/06/2017. El CSS de Mérida, informa, vía fax, que Nelson José ha regresado al centro tras ausentarse el día anterior.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2017-06-05','Conversación con Pilar, Psicóloga del C.Educación Especial: +++Joaquín no ha trabajado nunca. +++Se dió de alta en el SEXPE hace poco para poder hacer un curso de la ONCE. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Mª Ángeles, Directora Apba 8 Montijo: +++Incidente en el que Joaquín ha sido la víctima: agresión en la calle. Enviará por correo-e la denuncia interpuesta. +++Solicitará reunión un poco más adelante (segunda quincena de junio).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2017-06-05','Llama Maribel, T.S. del Sociosanitario de Mérida, indica que mañana día 6/6/17 Francisco va al CRR de Plasencia para hacer una entrevista para ver si podría ingresar allí. Iciar','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2017-04-24','FUGA El 24/04/2017. Se fuga a las 18.40hs. Le trae la policía a las 01.30hs.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2017-04-27','SALIDA El 27/04/2017. Acude a CEDEX. El médico del CEDEX llama al CSS de Plasencia y le informan de que no aceptan su ingreso. Se comunica este hecho a la Comisión Tutelar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2017-05-01','FUGA El 01/05/2017. Se escapa a las 20.15Hs. A las 22.50Hs. llama la Policía Local para informarnos de que está siendo atendido por servicio médico enla calle y va a buscarle un educador del Centro. Al regreso es atendido por Enfermería del centro encontrándose muy bebido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2017-05-02','INTENTO DE FUGA Y FUGA El 02/05/2017. A las 6.45Hs. intenta saltar la valla. Después de pasar la mañana muy cansado, tumbado en el taller, se escapa a las 19.05Hs. Por la noche, sele recoge en el Hospital de Don Benito a las 1.50 Hs.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2017-05-07','FUGA El 07/05/2017. Se escapa a las 20.50Hs. Le trae la policía a las 23.05Hs. Regresa bebido, no quiere acostarse ni dejarse explorar. A la 1.10Hs. sigue despierto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2017-05-11','INCIDENCIA El 11/05/2017. A las 20.15Hs. está en la estación de RENFE, van a buscarle y le encuentran muy borracho.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2017-05-27','INCIDENCIA CON DROGAS El 27/05/2017. Va a tomar un café a un bar muy próximo al centro, donde le gusta ir. Le acompaña un educador. Al regreso al Centro pide fumar y los educadores, al contrarle con actitud extraña, le registran y le encuentran MARIHUANA, que, según explica, le han proporcionado en el bar sin que el educador haya podido percatarse de ello.*****Este hecho es indicativo de las relaciones que Hermenegildo tiene en Don Benito, tanto porque tiene familiares, como conocidos de su familia, que están dispuestos a ofrecerle drogas y alcohol en cualquier momento, incluso en presencia de los educadores del Centro, por lo que reiteramos que consideramos imprescindible, para su recuperación, que sea trasladado a otra localidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2017-04-24','ANOTACION Tras reunión de la Subcomisión Regional de Casos, el 21 d abrio, en Mérida, en la que se plantean dos posibles vías (ingreso por orden judicial en Unidad de Alcoholismo del Centro Sociosanitario de Plasenica y de ahí a UDAC un tiempo para volver a nuestro Centro y, paralelamente, solicitud al CEDEX de informe para derivación voluntaria a esta misma Unidad), desde el centro se inicia este segundo camino, mientras que la Comisión Tutelar se encargará de solicitar la primera vía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-06-05','Conversación con MARA, T. Soc. de la D.G. Infancia y Familia (SS. Territoriales).CONTACTO:927-004349........fax: 927-004354. +++DIRECCIÓN de Dª BEATRIZ: C/ LANCHA VIEJA Nº 21, HUERTAS DE ÁNIMA (TRUJILLO). C.P:10290 +++Envió por fax solicitud de informe del S. de Infancia y Familia de Cáceres. +++CONTACTO EN SSB: MERCEDES, T. Soc. que lleva el caso de Dª BEATRIZ. Y Mª Jesús, T. Soc. SSB que lleva el caso de D. ANTONIO BENITEZ CARRASCO (33% discapacidad), pareja actual de Dª Beatriz y "supuesto" padre del bebé.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-06-06','Conversación con el Médico de Familia D. Francisco Carrasco (51002): +++Solicitar por escrito y por fax (927-323332) la información requerida del C. Salud, indicando la información que se considere más relevante. +++La matrona de Beatriz es Pilar, del C. Salud de Trujillo. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Enrique, T. Social del C. Salud de Trujillo (54503). +++Paco, Médico de Planificación Familiar de Trujillo (54501).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2017-06-06','Conversación con Mª Ángeles, directora de Apba. 8: +++Preocupada por no existir vacantes en C.O. para Joaquín en estos momentos. +++Plantea, de no darse dicha vacante, dejarlo un año más en el CEE: ni a mª ängeles ni a mí (Pedro) nos parece una alternativa, dado que podría considerarse una "vuelta atrás" para él. +++Plantea si se sabe si va a haber alguna adenda próximamente (consultado con Maite, comenta que no hay ninguna prevista hasta octubre, pero quedo con ella en que lo hablará con Manuela. En cualquier caso, Joaquín está el primero en la lista de espera cuando se produzca dicha vacante). Informo a Mª Ángeles de lo referido por Maite. +++SOLICITA (por correo-e)REUNIÓN CON LA CTAEx PARA EL 19 DE JUNIO A LAS 9:30h.Adjunta denuncia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CIPRIANO'and edp.apellido1='MIGUEL'and apellido2='BAZAGA'),'2017-06-06','Recibimos resolución PIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2017-06-06','Visita a la CTAEx de los padres y hermano de Ramón. +++Consideran la situación de muy urgente. +++Solicitan ingreso inmediato en el CSS de Mérida y de manera indefinida. +++Los médicos de familia, cuando llaman al 112 -dicen- "...Ya no nos hacen caso. Nos han dicho que ya no volvamos a llamar ni a llevar a Ramón por allí..." +++Se les plantea la posibilidad de denunciar a Ramón en caso de agresiones, pero su madre no quiere porque teme que se lo vuelvan a llevar al Psquiátrico penitenciario de Sevilla. +++El tema del dinero (los gastos que ocasiona) solo lo plantea D. Manuel al final de la entrevista, pero intenta que la Comisión les dé más dinero por ello. +++COMPROMISO: hablar con el ESM de Jerez de los Caballeros y también con Soraya. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Mariola, T. Soc. ESM (Fabiola está en consulta). +++SE expone la visita de la familia de Ramón a la Comisión. +++Se reitera la situación de riesgo que manifiesta la familia en su relación con ramón. +++Compartimos la necesidad de ingreso en Recurso de Salud mental como el más adecuado para Ramón y no en Centro de Discapacidad. +++HABLARÁ CON FABIOLA para saber si ya se ha solicitado la subcomisión regional de casos y volverá a llamar, ella o Fabiola, al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2017-06-06','Conversación con Mariví (T.Soc. CSS Plasencia): +++Riesgo de fuga de D. Juan. Se está "impacientando" por la falta de respuesta desde los pisos tutelados. +++Consultado con la Sección de Salud Mental, actualmente se encuentra el nº 12 en la lista de espera, si bien existen 4 ó 5 personas por delante de él que, dado que solicitan recursos fuera de Plasencia, supondría un avance de ese número de posiciones en la lista. +++PROPUESTA: reaslizarán informe sobre la situación descrita para remitir al Juzgado (el CSS o bien remitirlo a la Comisión para enviarlo) y tartar de agilizarla resolución de nuestra propuesta de ampliación de la incapacidad formulada el pasado 26 de abril al Juzgado, solicitando en dicho informe al Juzgado las directrices a seguir en caso de fuga o de cualquier otro riesgo que se pueda dar...)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORO'and edp.apellido1='MORGADO'and apellido2='SANCHEZ'),'2017-06-06','Llamada de Mara: +++Ha enviado un nuevo informe de incidentes por correo ordinario. +++NOVEDAD: Dª Antonia (695-010360), hermana de D. Isidoro que vive en Alburquerque, le ha dicho a él que está hablando con el Alcalde de esta localidad para llevárselo a la residencia que hay allí. Le pido a Mara que nos envíe por escrito esta incidencia para ponerla en conocimineto del Juzgado. +++IMPORTANTE:el Juzgado de 1ª Instancia nº 4 de Badajoz se HA INHIBIDO en beneficio del de Llerena.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FERNANDO'and edp.apellido1='FEBLES'and apellido2='GONZALEZ'),'2017-06-07','PENSION Se recibe certificado, de PNC,indicando que José percibe una pensión cifrada en 553.35€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='MORENO'and apellido2='MOVILLA'),'2017-06-05','SALIDA El 04/06/2017. Excursión diurna a Monfragüe, con motivo del día mundial del medioambiente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='ORTEGA'and apellido2='APARICIO'),'2017-06-02','REMOCION DEL CARGO Con f/ de registro 02/06/2017, se recibe Auto, nº. 48/17, de 25 de abril, por el que se remueve a la Comisión Tutelar de Adultos de Extremadura del cargo de Curador de Vanesa. Así mismo, se nombra tutor a la Fundación Malagueña de Tutelas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOFIA FLORENTINA'and edp.apellido1='COLLADO'and apellido2='ESTEBAN'),'2017-06-07','Llamada de Juan Carlos, T. Soc. REs. Deleitosa (927-540149): +++Dª Sofía quiere hablar con nosotros. SE pone al teléfono y, entre lo que se le puede entender es que su sobrina no la llama (no sabe que falleció hace algún tiempo y creemos que es mejor no darle esa noticia, opinan en la Residencia y seguramente sea lo mejor). +++Comenta que han ido del juzgado por la venta de la finca y que ella no quiere vender. +++Le explico al T. Social la situación de la finca y el motivo de haber solicitado al juzgado autorización para su venta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2017-06-07','Convesración con Mª Jesús(INSS): +++Pendiente de conocer la cotización internacional del padre de Dª Carmen para que,si con posterioridad al 23 de noviembre de 2005 ella estaba soltera o ya divorciada, si tuviera derecho a la P.O. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Convesración con Paco (924-216150) (INSS): +++No optar ahora pendiente de la resolución de orfandad. +++Si denegartoria, hacer reclamación minetras Carmen sigue percibiendo la PNC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MATEOS'and apellido2='DELGADO'),'2017-06-07','FALLECIMIENTO Tras la reiterada solicitud de la firmeza de la sentencia, se procede a comunicación telefónica con el Jzdo. Éste, nos infoma que Dña. María falleció el 27/04/2017.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2017-06-07','Llama Estrella, madre T/C 927 32 19 92, indica que VAnesa se ha comprado unas gafas por valor de 300€, no lo ha comunicado a la Comisión, y las paga con la asignación semanal de 100€ con lo cual se queda sin dinero para comer. Se le pide envíe factura de la compra por fax. Además dice que Vanesa ha recibido una citación del Juzgado de Trujillo para el día 20 de junio por un altercado que tuvieron Vanesa y su hermano con una vecina a raiz de unos perros. Esa citación ha llegado al domicilio del hermano por lo que no tenemos constancia. La enviará también por fax','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2017-06-07','Convesración con María, T. Soc. del ESM de Zafra: +++Acudió a consulta y no se apreciaron indicios que hicieran plantearse un posible internamiento. +++Comentó que quería alquilar una casa (500€/mes) y tener allí unas gallinas para "entretenerse". +++Enviarán por correo informe de la visita. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a Idefonso, al teléfono 625-245891 y de nuevo salta el contestador de Orange indicando que tiene las llamadas entrantes restringidas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORO'and edp.apellido1='MORGADO'and apellido2='SANCHEZ'),'2017-06-06','INCIDENCIA El 06/06/2017. Una hermana de Isidoro, Antonia, llamó por teléfono a la residencia para hablar con él. Al parecer está haciendo gestiones con el alcalde de su pueblo, Alburquerque, para que se traslade a una residencia de allí. El tfno. de contacto de la hermana es: 695010360','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIONISIA'and edp.apellido1='ESPINO'and apellido2='ROMAN'),'2017-06-02','INCIDENCIA E INGRESO Del Hospital Provincial Virgen de la Montaña de Cáceres, se recibe llamada telefónica indicando en ingreso de Dña. Dionisia. Así mismo, se solicitaba información por un posible fallecimiento de ésta. Al parecer entró en el hospital sola, en una ambulancia y con una nota para que se nos llamara a la Comisión.***************************************************Puestos en comunicación con la directora del centro nos informa que le fue imposible dar con nosotros telefónicamente y que, por estar el Ayto. Cerrado -según parece fue su Dr. de cabecera quien la envió al Hospital con la ambulancia y que todo esto ocurrió sobre las 14:30 Hs. del viernes- no nos remitió, tampoco, correo electrónico informando de lo sucedido.**********************Se le da el número de fax para futuras ocasiones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-06-07','Envío de Fax solcitando Informe Médico de Dª Beatriz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIONISIA'and edp.apellido1='ESPINO'and apellido2='ROMAN'),'2017-06-07','RETORNO 07/06/2017, 11:43 Hs. "El motivo de la presente es para comunicarles que acaba de llamarnos el Hospital y viene ya de alta Dionisia Espino Román, para que quede constancia que a a partir de esta tarde ya está de nuevo entre nosotros".','2');
