insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MAXIMILIANO'and edp.apellido1='BAZAGA'and apellido2='CARRERA'),'2017-06-08','Correo-e de Laura (PIA): Os informo que se va a cerrar el PIA de este señor con el MANTENIMIENTO de plaza pública en el Centro Sociosanitario de Plasencia. Comentaros que este señor lleva desde el año 2008, según los registros del centro, con ingresos y altas en el hospital y el último que consta fue el 27/08/2013. En estos momentos está en la Unidad de Larga Estancia, en crónicos, y le he pedido a la Trabajadora Social de la Unidad que valorase con su psiquiatra la posibilidad de tramitar solicitud de plaza pública en Piso Supervisado, tal y como hablé con Amalia por teléfono, pero su psiquiatra, según informa la T. S., no prevé darle el alta ni considera que tenga perfil para ese recurso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='VALADES'and apellido2='DIAZ'),'2017-06-08','Reunión programada con Isabel Valadés: +++Objetivo: que tome conciencia de que su nivel de gastos no permite seguir manteniendo un reintegro de 80€/semana y que se lo tenemos que rebajar a 55€/semana.Los gastos más elevados son luz, agua y tabaco.','2');
