insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA PRISCILA'and edp.apellido1='SAQUERO'and apellido2='SANCHEZ'),'2017-06-08','Llama Longina T.S. de Madrigalejo, nos pide pensiones que recibe Ana Priscila para que introducirlas en la base de datos del Centro de Salud de Zorita al que pertenece, con objeto de que aparezcan allí para cuando sea necesario, y luego la Seguridad Social le pase el coste de la atención a la compañía de Ana P.','2');
