insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2017-06-08','Estamos pendientes de recibir el certificado literal de matrimonio del registro civil de Portugalete. De todas formas hemos hablado con Carmen que nos dice se divorció en 1979 en Herrera del Duque.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='FERNANDEZ'and apellido2='SANCHEZ'),'2017-06-08','Conversación con los Juzgados 1 (Maite) y 2 (Félix)de Zafra. +++EL Nº 2 ha dictado Sentencia declarando CURADORA a la hermana de D. Manuel, Dª Eladia Fernández Sánchez. +++A raiz de estas conversacones remiten por fax dicha Sentencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRESCENCIO'and edp.apellido1='HERNANDEZ'and apellido2='PEREZ'),'2017-06-08','FALLECIMIENTO Y ARCHIVO Se recibe, del GJ, Decreto nº. 210/17, de 1 de junio, que acuerda el archivo de las Medidas Cautelares contempladas para D. Crescencio. Según el Decreto, se dictó el archivo de la Incapacitación, proc. 970/16, por fallecimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORO'and edp.apellido1='MORGADO'and apellido2='SANCHEZ'),'2017-06-12','Llamo a Mara, Directora de la R. "Fuente Atenor": está de vacaciones. Estará el 19,20 y 21 de junio. Hablo con Puri, Animadora Sociaocultural: +++No han recibido contestación de los SS. Territoriales. +++Cuando han llamado al 112 acude el médico y lo estabiliza, pero en ningún momento se han planteado el ingreso en UHB. +++Volveré a llamar la semana que viene.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2017-06-12','Llama Luis GArcía, hermano de Ildefonso, para informar uqe su hermano, está vivendo como un vagabundo en la calle en Zafra. Le comento que hemos intentado localizarle pero nos es imposible. Él dice que va a ir a los Servicios Sociales de Zafra para hablar con la trabajadora social. Ildefonso tiene una orden de alejamiento de su hermano Luis, por lo que no puede contactar con él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2017-06-12','Enviamos certificado de prestaciones por correo electrónico al ayto de Jaraicejo a la atenciónd e la T.S. de la residencia María Jesús Gómez para actualizar la mensualidad como nos habían solicitado','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='FERNANDEZ'and apellido2='SERRANO'),'2017-06-12','Conversación con Manoli Almazán, de SOMIMA (927 35 43 82): +++Dª Josefa se dió de baja del Centro hará cosa de 2 meses. Al parecer fue su cuñada Pilar la que firmó la baja. +++Se le informa a Manoli que esa baja solamente la puede firmar la Comisión, al estar Dª Josefa tutelada. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a Longina, T. Soc. de Madrigalejo (X, J y V en el teléfono 927-354002): +++No sabía nada sobre ello. +++Citará a la cuñada para enterarse de lo que ha pasado y me llamará (le dejo teléfono y correo-e).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2017-06-12','Conversación con Toni (Futuex): +++Ingresó en la UHB del Infanta Cristina el pasado jueves 8 de junio. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a Loli, T. Soc. UHB Infanta Cristina (): +++Confirma el ingreso. Su Psiquiatra es el Dr. Bolívar. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Comunico el ingreso a Soraya por correo-e.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2017-06-12','Conversación con Toni (Futuex): +++Dada la negativa del propietario del piso para su alquiler, pido que sigan buscando otras alternativas. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a la Inmobiliaria Domus. Hablo con Esmeralda: +++AVALISTA: refiere que lo que el propietario lo que quiere es que, además de la firma de José Mª figura una tercera que le dé más garantía. Se le explica que la firma que va a constar en el contrato es la de la persona que figura como vicepresidenta de la Comisión Tutelar, dado que la firma de José Mª por sí sola carece de valor jurídico. Y se incide explícitamente en que la persona que figura como vicepresidenta de la Comisión en modo alguno es avalista del tutelado. +++TITULAR de SUMINISTROS (luz y agua): no podemos dar de alta en este aspecto a nuestro tutelado, pero su abono está asegurado desde el momento en que la Comisión tiene el control de las cuentas.Solo tendría que hacernbos llegar los recibos (correo-e, fax) e indicarnos nº de cuenta donde abonarlo. +++INVENTARIO: en este aspecto, el realizarlo es una garantía para el propietario más que para el inquilino. VOLVERÁ A HABLAR con el propietario para explicarle todo ello y ver si es posible firmar el contrato con estas explicaciones. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Desde la inmobiliaria DOMUS, CONFIRMAN LA ACEPTACIÓN por parte del propietario del alquiler de la vivienda. Lo comunico a Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUVIGIS'and edp.apellido1='FUENTES'and apellido2='TORNERO'),'2017-06-13','Llama Juan Carlos, director de la Residencia “Los Pinos” de Plasencia, solicitando información sobre la situación económica de Dª Eduvigis con la siguiente finalidad: +++terminar el trámite de revisión del Grado de Dependencia. +++abonar la plaza residencial que no se ha abonado desde el año pasado. +++abonar otros gastos también pendientes como peluquería, podología, etc. Paso la gestión a Alberto para que se ponga en contacto con él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN'and edp.apellido1='GUTIERREZ'and apellido2='RONCERO'),'2017-06-13','Llama otra hermana de Julián, Tere T/C 980 53 44 49 - 686 368 544, por el tema de la venta del piso. Se le indica mande por correo electrónico la tasación del piso para poder pedir la autorización al juzgado, y que no puede ser tan rápido como ellos quieren pues es un proceso que toma su tiempo.','2');
