insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LEON'and edp.apellido1='LEAL'and apellido2='PEREZ OLAGUE'),'2017-06-13','Conversación con Inmobiliaria "Cecilia Calderón": +++Tienen un posible comprador que vive en la misma calle y estaría interesado en comprarlar. +++Quiere limpiarla antes de eneseñarla: nos enviará presupuesto (+/-240€) antes de hacerlo. Se le inoforma que habrá que esperar a la venta de la casa para abonar la limpieza. EN CONVERSACIÓN CON Dª Mª LUISA (hermana de León) se compromete a abonar dicha limpieza DEBIÉNDOSELE REEMBOLSAR, JUNTO CON LAS DOS MENSUALIDADES DE LA PLAZA, una vez vendida la vivienda. +++Quedarán con Futuex para ir a ver la casa, limpiarla y luego enseñarla. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++RESIDENCIA SANTA ANA: 927-276471.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2017-06-13','Remiten fax desde el HIC. Loli, T. Soc: +++Mañana, 14 de junio, D. Ramón Ingresará en la UME de Mérida. +++El día 21 se reune la subcomisión regional de casos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='VITA'and apellido2='GIL'),'2017-06-13','Se cita a David, en la sede dle Juzgado de 1ª. Instancia e Instrucción nº 1, de Villareal (Castellón), el dí a 29/9/2017, a las 10 horas, para tomarle declaración en el procedimiento 72/2017. Solicitamos al Juzgado que la declaración se haga mediante videoconferencia en los Juzgados de Llerena y que le designen abogado de oficio en este procedimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2017-06-13','Conversación con María, T. Soc. C.Salud de Zafra (45970) y con Ildefonso. Ildefonso se encuentra viviendo en la calle desde hace unos días: dejó el hostal porque dice que era muy caro. Por la noches se queda en un parque que se cierra al público y donde dice no le importa dormir. +++Llamo al C. "Padre Cristóbal". Hablo con Tomás, Un Voluntario: no hay plazas para esta noche, pero mañana esperan dos vacantes. Ildefonso debe llamar a las 8:00 para decir que va a ir al centro.Doy a Ildefonso el teléfono +++Llamo también al Centro hermano de Badajoz pero no cegen el teléfono. +++Mañana tiene que acudir al Forense, pero pasado mañana le digo que se pase por la CTAEx para hablar personalmente de su situación. +++Quiere alquilar un piso en Zafra porque "es más barato que en Mérida...". Tenemos que hablar del control del gasto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORA'and edp.apellido1='LEAL'and apellido2='ROMAN'),'2017-06-13','CADEX No constan antecedentes en el CADEX de Cáceres.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2017-06-13','Se envía al ESM de Valdepasillas fax (924-218005) la última carta remitida por la madre de María.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORA'and edp.apellido1='LEAL'and apellido2='ROMAN'),'2017-06-07','PENSIÓN PNC nos informa que Dña. Isidora no cobra: PNC, FAS, LISMI.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='VAZQUEZ'and apellido2='GUERRERO'),'2017-06-13','En relación con la herencia de su madre, acudimos ayer a la comparecencia en el Juzgado de Zafra. La fiscal no se opone. Estamos a la espera de recibir la autorización judicial. Con respecto a la herencia de su hermano Fernando, tenemos la autorización judicial para aceptar la herencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2017-06-14','Llamo a Mª Jesús, para informarle que hemos recibido el cdo literal de matrimonio de Carmen pero no indica la fecha de su divorcio, que nos hemos puesto en contacto con registro y juzgado de Herrera del Duque donde supuestamnete se separó en el año 1979 pero no nos pueden facilitar ninguna información. Me comenta que va abrir un expediente de reglamento comunitario a ver si a través de ahí se el podría conceder la prestación de orfandad, para ello el padre de Carmen debería haber trabajado en España más de un año pues en Alemania sí trabajó muchos años.Va a pedir esa información a sus compañeros del País Vasco. El plazo de 30 días que aparece en la resolución denegando la orfandad no se aplicaría al abrir ese nuevo expediente.','2');
