insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2017-06-15','Conversación con Mª Barrasa: +++Ramón dice que está muy preocupado por sus animales. +++...que necesitan más dinero para el pienso porque han criado ¿y los que Manuel iba a vender?. +++Ramón quiere vender los animales, por lo menos unos cuantos. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a Silvia (Futuex): +++Hoy no ha podido hablar con Manolo (hermano) pero es cierto que han criado las cerdas. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Hablo con Manuel, (hermano de Ramón): +++NO se puede quedar con el vendedor del pienso en que nos mande factura para poder pagarlo desde aquí (ya se intentó con Ramón). +++Le propongo enviarle dinero para termninar el pienso del mes, pero no me sabe decir cuánto necesita. Plantea vender algunos animales y dedcicar el dinero a comprar pienso.Enviará facturas ¿?.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2017-06-15','Hablo con Mª Barrasa: +++Ramón no ingresó ayer en la UME porque tuvieron una avería en el aire acondicionado de varios pabellones (habitaciones) y los aparatos se descargaron. Además, el gas que usaban era ilegal y ha habido que encargar otro. +++Por lo tanto, se ha aplazado el ingreso de Ramón, que será el primero en hacerlo una vez solventado el problema.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2017-06-16','Hablo con Paula, Terapeuta ocupacional del CRR de Plasencia, indica que Francisco ya está residiendo en el CRR, enviará documentación para que se firme.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2017-06-16','Llama Carmen indica que el martes 20 de junio María quiere hablar con Pedro a las 12h antes de que Pedro hable con el psiquiatra a las 12:40, a esa hora porque es la que mejor le viene por el horario de la furgoneta que le lleva a su casa en el campo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2017-06-19','Llamo al Cadex. Hablo con Mª Ángeles, Directora (924-009500/20422) +++Entró la solicitud en eñl Cadex el 13 de junio. +++Pendiente de citar: no podrá ser antes de la segunda quincena de julio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-06-19','Acudimos el 16/6/2017, al Juzgado de 1ª. Instancia e Instrucción nº 2 de Zafra, para acompañar a Beatriz, a la declaración mediante videoconferencia, con motivo del procedimiento Previa 400/2015, seguido en el Juzgado de Instrucción nº 5, de Mollet del Vallés (Barcelona). La citación la teníamos a las 12:45. Tras media hora esperando, nos atiende una trabajadora del Juzgado de Zafra y nos dice que se ha puesto en contacto con el Juzgado de Mollet del Vallés, y le dicen que han SUSPENDIDO la videoconferencia, SIN notificar, ni al Juzgado de Zafra, ni a nosotros.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2017-06-19','Acudimos el 16/6/2017, al Juzgado de 1ª. Instancia e Instrucción nº 2 de Zafra, para acompañar a Beatriz, a la declaración mediante videoconferencia, con motivo del procedimiento Previas 400/2015, seguido en el Juzgado de Instrucción nº 5, de Mollet del Vallés (Barcelona). La citación la teníamos a las 12:45. Tras más de media hora esperando, nos atiende una trabajadora del Juzgado de Zafra y nos dice que se ha puesto en contacto con el Juzgado de Mollet del Vallés, para preguntar por qué se está retrasando tanto la videoconferencia y le dicen que desde el Juzgado de Mollet del Vallés han SUSPENDIDO la videoconferencia, SIN notificar, ni al Juzgado de Zafra, ni a nosotros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2017-06-16','INTERVENCIÓN El Centro informa: "Causó alta en el Hospital San Pedro de Alcántara el día 15/06/2017. Habiendo sido intervenida, con resultado favorable, y a la espera de resultados."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2017-06-19','Entrevista con Mª Ángeles (Coordinadora de Apba. 8) e Irene, Educadora. Posteriormente se incorpora Joaquín. +++RECONOCIMIENTO MÉDICO-FORENSE EL 27 DE JUNIO DE 2017a las 10:30h en el Juzgado de 1ª Instancia e Instrucción nº 2 de MONTIJO. +++Conveninecia o no de mantener el contacto con su madre. +++Apertura de nueva cuenta de ahorros en una entidad con sede en Montijo: se están llevando a cabo los trámites correspondientes (Belen). +++Se ha enviado ya el contrato de admisión. +++Una vez que acabe el curso, dado que no está disponible la plaza en C.O., acudirá por las mañanas a la residencia donde se le asignará alguna tarea (desde la Comisión se le "gratificará" con un incremento de su dinero de bolsillo, según indicación de la Dirección de Aprosuba 8). ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Respecto de las relaciones madre-hijo, cuando se le pregunta a él parece tener más un temor a la reacción de enfado de su madre si algún día no va a verla que un deseo agradable ade acudir a dichas visitas: "Sé que si no voy a verla se va a enfadar...A mi padrastro no lo trago...". Se le hace entender que en ningún momento se trata de impedir la relación con su madre, sino de tratar de garantizar que la misma es positiva y adecuada para él: libre de obligaciones y de chantajes emocionales como parece ser que está siendo en estos momentos. CONCERTAREMOS ENTREVISTA CON LA MADRE, a ser posible el mismo día del reconocimineto forense.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2017-06-19','Hablamos con la hija, Mª Carmen T/C 659 33 59 22, nos comenta que han robado puertas y ventanas de la casa de Valdecaballeros, se lo ha dicho una vecina.La casa cada vez se deteriora por días. Además,mirará a ver si tuviera la sentencia de separación/divorcio de sus padres que nos solicitan de la seguridad social para tramitarle otra pensión a Carmen.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORO'and edp.apellido1='MORGADO'and apellido2='SANCHEZ'),'2017-06-19','Conversación con Mara: enviará el informe médico. Dr. Idilio Glez.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2017-06-19','Visita de Ildefonso a la CTAEx: +++Ha estado esta mañana en la Comisión a primera hora. Se le ha derivado al C. "Padre Cristóbal" para ver si tenían plaza para él durante unos días. +++TIENE PLAZA en dicho centro (llamo para confirmar y hablo con Carlos). Mañana llamar para hablar con Inma o Montes (las T. Sociales). +++CONVERSACIÓN: +++++Se le plantean los problemas económicos, familiares y legales que tiene. +++++SE le insiste en que hay que limitar su cuenta para que pueda tener unos ahorros:me pide que le deje seis meses para demostrar que es capaz de ahorrar...Le digo que no, que tiene dos meses: si a finales de agosto no tiene dinero ahorrado la limitación de su cuenta será un hecho. +++++BUSCARÁ ALQUILER EN ZAFRA: nos traerá el contrato. No quiere en Mérida porque "los pisos son más caros". +++++DE MOMENTO SE QUEDARÁ EN EL "PADRE CRISTÓBAL"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2017-06-20','Conversación con Inmaculada, T. Soc. del C."Padre Cristóbal" (924-302618): +++SE le pone al corriente de las últimas circunstancias de Ildefonso. +++Seguimos en contacto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2017-06-20','Llama Eugenia, T.S. de Servicios Sociales de Jerez, indica Manuel ha vendido los cochinos de Ramón. Le han dado 80€, y pregunta por el medio para justificar dicha venta.','2');
