insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DANIEL'and edp.apellido1='MONTAÑO'and apellido2='RANGEL'),'2017-06-20','HAblo con Caty, T.S. de Aprosuba 3, indica les ha llegado una notificación del Jdo que ha sido enviada al domicilio de la madre de Daniel en la calle Berna nº 53. Nos envía el escrito por correo electrónico, en el mismo se dice que debe pasarse por el jdo a recoger documentación judicial. Nos ponemos en contacto con el Jdo nº 2 de Badajoz, 924 28 43 43, hablamos con Juan GAvira sobre este procedimiento, JVB684/17, nos dice que es por un accidente de tráfico y que además del escrito recibido debería de haber llegado por correo certificado la demanda contra Daniel, pero que a él no le ha llegado el acuse de recibo. Le envio por correo electrónico el escrito que ha recibido Daniel para que él lo vea. Llamo a Caty para confirmar que no les ha llegado la carta certificada con la demanda y nos confira que efectivamente no la han recibido.','2');
