insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='ROMERO'and apellido2='VERA'),'2017-06-21','Se le ha hecho un contrato de trabajo en el Centro Especial de empleo del Ayto de Llerena durante 3 meses a jornada completa, comenzando el 19 de junio. Desde Plena InclusiónLlerena, mercedes Rubio T.S., nos envían contrato para revisar y pasar a la firma. Llamamos al servicio de las PNC para que nos indiquen cómo actuar para dar de baja la PNC mientras Manuel esté trabajando.Les mandamos comunicación, como nos indican, del comienzo del contrato, y deberemos enviarles, cuando lo tengamos, la primera nómina y el contrato de trabajo. Devolvemos firmado el contrato a Mercedes Rubio, T.S. de Plena Inclusión Llerena','2');
