insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2017-06-21','Hablo con Toni de Futuex, le comento que tenemos ya el contrato de alquiler de José María puesto a la firma para enviárselo a la inmobiliaria Domus (ESmeralda 924.30.45.44),y hacer la transferencia. Mañana día 22 de junio José María entra a vivir en el piso, desde futuex van a llamar a la inmobiliaria para acordar con ellos hora de entrega de llaves y acompañarle al piso.','2');
