insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2017-06-23','Llamada a Elena (T. Soc. Las Cumbres. 920-269527): +++Va todo bien con Margarita. Sigue con su ambivalencia "..me quiero ir ...me quiero quedar..." +++ADEUDOS: DEL 20 AL 30 DE ABRIL (266.02€) Y MAYO (1649.32€). +++"...Tengo una guitarra, pero la toca un compañero por mí..."','2');
