insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2017-06-23','Resolución de la Dirección Gerencia del SEPAD de 14 de junio de 2017: PUNTUACIÓN para INGRESO en CENTRO DISCAPACIDAD: 70.5 puntos en provincia de Cáceres; 69.5 puntos en provincia de Badajoz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2017-06-23','Entrevista concertada en las dependencias del ESM de Valdepasillas. Presentes: Carmen Díaz, T. Social, María, su madre y Pedro como Jefe de Sección de CTAEx. +++DEMANDA DE MARÍA: un piso para vivir sola con su perro. +++CUALQUIER OTRA PROPUESTA: era respondida con una enorme agresividad verbal, acompañada de insultos y ademanes de agresión física se llegar a producirse, Además, amenzas de muerte tanto a la T. Social como a mí: "...Si me intentas ingresar voy a ir a por tí...pero no creas que voy a ser yo, sino que enviaré a unos "gitanos" que conozco para que te encuentren y te..." +++No acepta nada que no sea un "techo bajo el que vivir con su perro": no acepta C. terapéutica, no acepta ingreso en centro de manera temporal para tratamiento. +++Esta reacción fue inmediata nada más comenzar la reunión y se prolongó durante la hora larga de duración de la misma. +++Al despedirnos, pidió disculpas. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversasción con el Dr. Samino, su psiquitra: se trata de una caso de difíciol resolución, dado que no existe un recurso adecuado para ello. Enviará Informe Clínico y propuestas de intervención.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='FAGUNDEZ'and apellido2='CORTES'),'2017-06-23','PIA Se recibe Aceptación PIA para el cambio de RAE a la USAD del C.R. Ntra. Sra. de las Cruces de Don Benito. Se pasa a firma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2017-06-23','María, Educadora de la Mancomunidad (609-382439): informa de agresión física y verbal hacia Dª Felisa por parte de su hijo (Aitor). +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Hablo con José Mª Hurtado, Jefe de Sección de Infancia y Familia (927-004306). La Educadora que autorizó el permiso de salida para el hijo de Dª Felisa está de vacaciones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2017-06-26','Llamada a María, Educadora Social de la Mancomunidad. El móvil está dswconectado. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a José Mª Hurtado: no me cogen el teléfono.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2017-06-26','Conversación con Mariví (T. Soc. del CSS de Plasencia): +++No existe recurso a decuado para D. Juan dada la persistencia de escasa conciencia de enfermedad que sigue demostrando. Ha empezado con amenazas a los propios profesionales del centro manifestando su deseo de marcharse. +++En estos momentos Mariví refiere que está el 3º en lista de espera para Pisos Tutelados, pero cree (y la Comisión también) que espera su traslado a dicho recurso como trampolín para marcharse de nuevo a Guadalupe 8dado el antecendente de los Pisos Tutelados de Zafra). +++En opinión de Mariví, es un paciente que debe estar ingresado en un recurso residencial, pero él no acepta esta medida, por lo que cierra cualquier alternativa viable para ello.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2017-06-26','Reunión mantenida con los padres de Ramón y con su hermano Juan: +++el traslado se ha realizado hoy desde la UHB de Badajoz a la UME de Mérida (en principio estaba previsto para mañana). +++ACEPTAN LAS SIGUIENTES CONDICIONES: +++++NO VISITAR a Ramón en un periodo de tiempo largo al principio (al menos 1 mes o hasta que el Psiquiatra indique) +++++NO LLAMAR por teléfono durante dicho tiempo, a como mucho una vez al mes. +++++Pueden llamar para preguntar por él tanto al centro como a la Comisión, pero no para hablar con él. +++Se explica la conveniencia de mantener incialmente estas condiciones, que se irán modificando en función de la evolución de Ramón.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2017-06-26','Conversación mantenida con Pilar, T. Social del CSS de Plasencia. +++Hemos recibido Informe de su Psiquiatra, el Dr. Daniel Gómez Pizarro. +++Le comentó que lo podía enviar al Juzgado pero al parecer no lo ha hecho (al menos todavía). Hablaré con él por si prefiriese enviarlo él o lo hacer la Comisión. +++Pilar considera, y esta Comisión está de acuerdo, en que José María es un paciente que, dado que ni en la red de discapacidad (ASINDI) ni cuando estuvo en CRR se obtuvieron resultados aceptables, sino todo lo contrario (en el primer caso fue denunciado por agresión a los residentes y en el segundo fue expulsado por alteraciones de conducta), es susceptible de ser paciente de Larga Estancia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2017-06-26','Llamada a María, Educadora Social de la Mancomunidad. El móvil está dswconectado. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a José Mª Hurtado: no me cogen el teléfono. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con María, Educadora Social Mancomunidad Tajo-Salor (609-382439). +++El viernes se llevaron a Aitor (hijo de Dª Felisa" al Centro de Menores de Valcorchero. +++No precisa de momento ningún cuidado especial en relación al caso. +++Plantean la necesidad de que alguien vaya a visitarla de vez en cuando porque desde el Programa de Familia están muy limitados (también la Comisión). Se valorará posible visita de Futuex en coordinación con el programa de familia. +++NECESIDAD: UNAS GAFAS. Eniviarán uno o dos presupuestos para valorar y aprobar el gasto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='FERNANDEZ'and apellido2='SANCHEZ'),'2017-06-26','SE retira la visita de Futuex al no estar ya curatelado por la Comisión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SANTOS'and apellido2='BREÑA'),'2017-06-26','FALLECIMIENTO Se nos informa, desde el centro, que el óbito tuvo lugar el 11/06/2017, a las 11:20 Hs.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2017-06-27','Se envía correo-e a Soraya ante la futura alta de D. José María, con Informe adjunto del Dr. Daniel Gómez Pizarro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2017-06-27','Se envía correo-e a Soraya ante la futura alta de D. Juan, con Informe adjunto del Dr. Herrero Sánchez.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2017-06-26','INCIDENCIA El pasado 23/06/2017, rfiere encontrarse mal durante la tarde, tras intervenciones con profesionales se tranquila y sale a pasear.**********************************************Tras la insistencia de los profesionales en repetidas ocasiones de tomarse la medicación, ésta cede a la 1.30 horas de la madrugada, ppues permanecía dormida hasta entonces, siendo imposible, por parte de los profesionales, despertarla.*****Tras la toma de la medicación, se va a fumar a la terraza y, posteriormente, regresa a su habitación.*************************************************A las 3.20 horas, pide que se la acompañe a su habitación. Comenta que ha ingerido Metamizol, mostrando a los profesionales varias cajas de este medicamento, el cual no se incluye en su pauta, no teniendo conocimiento por parte del CRR de esto.********************************************Seguidamente se avisa al 112 y presencia policial a las 3.20 horasm, pues sigue mostrando ciscurso agresivo. Se presencian en el centro a las 3.40 y la trasladan a urgencias****************Durante todo el tiempo Luisa permanece consciente y sin aparente síntomas de sobremedicación, aún así, la quedan ingresada para hacerle lavado de estómago. Actualmente, sigue en UHB, encontrándose en buen estado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2017-06-27','Hablamos con Luli, Trabajadora Social del Hospital San Pedro de Alcántara - tlf 56348, para saber el estado y las necesidades de Ventura, ingresado de urgencia ayer tarde 26/6/17 en la planta 4ª. Nos llamará ella al final de la mañana pues todavía no han hecho las visitas diarias.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL MAR'and edp.apellido1='GORDILLO'and apellido2='SANTANA'),'2017-06-27','Llama Maribel, T.S. del CSS de Mérida - tlf. 24013, indica que María del Mar va el jueves a los Pisos Tutelados de Zafra durante un mes de prueba. Necesita dinero, comprobamos que su pensión todavía no ha sido ingresada en la cuenta de Ibercaja. El Centro le adelantará el dinero al menos hasta el día 1 de julio cuando comprobaremos si ha sido ingresada la pensión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2017-06-27','Hablamos con Luli de nuevo, comenta que Ventura ha tenido una hemorragia gástrica pero ya se encuentra bastante bien, se levanta, anda... No necesita ningún tipo de acompañamiento y seguramente mañana miércoles o jueves le darán el alta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='CASTAÑO'and apellido2='CARDENAS'),'2017-06-27','INFORMACIÓN: correo-e: +++Buenos días, simplemente informaros que una de nuestras usuarias tuteladas, en concreto Sandra Castaño Cárdenas SE HA CONTAGIADO DE PAPAERAS (parotiditis), al estar vacunada los síntomas son más suaves y atenuados por lo que su evolución es bastante favorable, incluso con ausencia de fiebre. En cuanto a nuestra otra usuaria tutelada Carmen Castaño Cárdenas en principio no presenta el cuadro vírico aunque estaremos en continua vigilancia. Debido al pequeño brote surgido,el pasado viernes estuvo el Servicio de Epidemiología en nuestro Centro y además de vacunar a todos nuestros usuarios también procedieron con la vacunación de la mayoría de los profesionales. A día de hoy está todo controlado aunque habrá que esperar de 8 a 10 días par cercionarnos por completo de la desaparición del riesgo. Para cualquier duda o información que requieran no duden en contactar con nosotros y se las resolveremos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL CARMEN'and edp.apellido1='CASTAÑO'and apellido2='CARDENAS'),'2017-06-27','infromación. Correo-e: +++Buenos días, simplemente informaros que una de nuestras usuarias tuteladas, en concreto Sandra Castaño Cárdenas se ha contagiado de paperas (parotiditis), al estar vacunada los síntomas son más suaves y atenuados por lo que su evolución es bastante favorable, incluso con ausencia de fiebre. En cuanto a nuestra otra usuaria tutelada CARMEN Castaño Cárdenas en principio no presenta el cuadro vírico aunque estaremos en continua vigilancia. Debido al pequeño brote surgido,el pasado viernes estuvo el Servicio de Epidemiología en nuestro Centro y además de vacunar a todos nuestros usuarios también procedieron con la vacunación de la mayoría de los profesionales. A día de hoy está todo controlado aunque habrá que esperar de 8 a 10 días par cercionarnos por completo de la desaparición del riesgo. Para cualquier duda o información que requieran no duden en contactar con nosotros y se las resolveremos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIO'and edp.apellido1='VAQUERO'and apellido2='PEREZ'),'2017-06-27','Llaman de Servicios Sociales de Montijo, nos indican que Julio tiene cita el 29 de junio a la 1:20 h enel Infanta en aparato digestivo. Necesita un acompañante para ir con él, la ambulancia ya ha sido pedida. Hablamos con Futuex y nos dicen que ellos ya lo tenían previsto pues en las anteriores ocasiones ya han ido también con él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2017-06-27','Reconocimineto médico-forense en el Juzgado nº 2 de Montijo. ENTREVISTA con la madre de Joaquín, Dª Mª Carmen, y su padrastro, D. Paulo, en Aprosuba 8 de Montijo. Asisten también MªÁngeles (Directora) e Irene (Terapeuta). Objetivo: +++Conocer a los padres de Joaquín, explicarles las funciones y atribuciones de la Comisión Tutelar y tratar de llevar una línea de trabajo con él de manera coordinada con los profesionales que lo atienden. +++La autoirización de salidas a casa de la familia para pernoctar o para pasar periodos progresivamente más largos estrá en función de la evolución de Joaquín en todas sus facetas, quedando de momento relegadas a visitas puntuales diarias, especialmente durante el periodo de adaptación al nuevo Piso Supervisado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2017-06-28','Llama Maite la T.S. del Centro Penitenciario de Cáceres para indicar que José María salió el viernes 23 de Junio a las 3 de la tarde del centro e ingresó en el Psiquiátrico de Plasencia. Para que nos conste y así dejar de pasar el dinero de bolsillo a la cárcel.TAmbién dice que se envió un correo electrónico el lunes 26 por parte de la subdirectora del centro pero no sabe a qué dirección.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LEON'and edp.apellido1='LEAL'and apellido2='PEREZ OLAGUE'),'2017-06-28','Acudimos ayer a la firma de la escritura de compraventa del local sito en Mora de Rubielos, 3, puerta 14-6, de Valencia, por 24.000 euros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-06-28','Hablamos con Mercedes Prieto, T.S. de SS de Trujillo. Nos informa que Beatriz ya ha vuelto de Sevilla con su madre, y se encuentra de nuevo viviendo en casa de sus padres con su novio. Comenta la situación de descontrol en la casa. Su madre en agosto se va a ir a vivir con el novio a Huelva. Le proponemos la solicitud de un ingreso de Beatriz en un centro por emergencia social, y ella nos dice que el ingreso en un centro es la opción que ella considera mejor para Beatriz. Lo va a gestionar hablando con Dependencia. Se pondrá en contacto con nosotros. Además nos enviará el informe social que se le requirió, que no había enviado antes pues estaba esperando que el padre de Beatriz le facilitase la información sobre cuentas, seguro de decesos, nº de la SS... Le indicamos que nos envie solo el informe social pues lo necesitamos con mas urgencia y luego ya nos enviará el resto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AURORA'and edp.apellido1='PAREJO'and apellido2='MORENO'),'2017-06-28','Llama Rosa, T.S., nos dice que la relación de Aurora con sus hermanos es mala, sobre todo a finales de mes cuando suspuestamente ella ya no tiene dinero y se lo pide a sus hermanos. Los vecinos son los que oyen las discusiones. El piso se encuentra en muy mal estado a pesar de que tiene ayuda a domicilio. El problema esque Aurora no quiere estar en un centro y estar con sus hermanos es la "mejor" opción.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='RETAMAL'and apellido2='GONZALEZ'),'2017-06-28','llama Cándido para decirnos que ya ha vuelto de sus vacaciones en Barcelona con su hermano. Todo ha ido muy bien.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2017-06-28','Conversación con José Mª Tovar. +++Quiere que Tomás vaya al centro de COCEMFE en Cáceres,para continuar con su rehabilitación y mantener la relación afectiva tanto con su hermana como con el resto de la familia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CAMPA'and apellido2='SILGUERO'),'2017-06-29','Recibimos autorización judicial para in greso en centro. Esta pendiente de valoración por dependencia, que se realizará próximamente (conversación con Montse, T. Soc. de Cilleros). Esperaremos valoración para ver cuál es el centro más adecuado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GABRIEL'and edp.apellido1='MENDO'and apellido2='PALACIOS'),'2017-06-27','SOLICITUD CI El hospital Campo Arañuelo, Navalmoral de la Mata, remite fax con el siguiente texto: "comunico a esa entidad que se encuentra ingresado en nuestro Centro Hospitalario: Gabriel Mendo Palacios. Dicho paciente esta tutelado por esa Comisión. Necesitamos implantar en el enfermo sonda PEG para lo que necesitaríamos su consentimiento".**************Se realiza llamada telefónica para que envíen, vía fax, modelo de CI. Una vez recibida se les devuelve firmado, también por fax.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2017-06-29','Conversación con Nati, T. Soc. Hospital de P. de Toledo. +++Solicito los informes en realción a la situación de Tomás.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GABINA'and edp.apellido1='GOMEZ'and apellido2='SANCHEZ'),'2017-06-27','FALLECIMIENTO El Ctro. nos comunica el fallecimiento, el día 22/06/2017,de Dña. Gabina. Junto con el oficio se nos hacen entrega de: CERTIFICADO DEFUNCIÓN, DNI, LIBRETA C/C, LIBRETA PLAZO FIJO, LLAVES DE SU CASA y PENDIENTES.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2017-06-29','LLamada de D. Fernando Acedo, Técnico de la Universidad Popular de Cáceres (670-081299): +++preocupado por este último ingreso de D. Ventura, plantea la posibilidad de su ingreso en un centro. +++dada su preocupación, se le solicita que, en la medida de sus posibilidades, puedan hablar con él sobre dicha posibilidad que ya en otras ocasiones, desde esta Comisión se ha planteado, siendo siempre rechazada por él...teniendo en cuenta, al margen de situaciones de salud como esta, la amplia actividad social desarrollada por D. Ventura y su negativa rotunda a abandonar su piso.','2');
