insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='VAZQUEZ'and apellido2='GUERRERO'),'2017-06-30','Hemos recibido la autorización judicial para aceptar la herencia de su madre, Francisca Guerrero Monzú.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2017-06-30','Llama J.F. diciendoq que desde el día 4 de julio hasta el 20 denoviembre tendrá que desplazarse diariamente al Hospital Infanta Cristina de Badajoz en referencia al accidente en la cara que tuvo con la moto. Le pedimos que nos envie el volante donde lo indica. Nos manda un fax en el que no se indica tal hecho. Llamamos al centro de salud de Olivenza y hablamos con su médico de atención primaria el cual nos dice que esa misma mañana ha estado en su consulta para que le derivase al maxiliofacial de Badajoz pero que le ha dicho que directamente no puede hacerelo, primeramente tiene que verlo el odontólogo del centro de salud, Dr Llimar, para lo cual tendrá que pedir cita y que si este lo considera le derivará él. HAblamos con la auxiliar admvo del centro de salud que nos dice que tiene cita para el día martes 4 de julio con el odontólogo. NAda de lo que nos dijo en la primera llamada era cierto. Según nos indica el médico el fax que nos ha enviado J.F. no era lo que él había escrito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JORGE'and edp.apellido1='FERNANDEZ'and apellido2='CERECINOS'),'2017-06-30','Citados para comparecencia en el Juzgado de 1º Instancia e Instrucción nº 1 de Mérida,a las 10:30h, para aceptar o no ser parte en el procedimiento a favor de Jorge.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2017-06-30','Visita la Comisión en el día de hoy: quiere marcharse a una residencia de Almendralejo. +++Hablar con CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2017-06-30','SE envía al CADEX solcitud de revisión de Grado de Discapacidad y solicitud de ingreso en Centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-06-30','Llama Mercedes Prieto, t.s de trujillo, como tiene un grado 1,se le va a solicitar la revisión para que pueda acceder al centro por urgencia. Se le reenviará por correo ordinario el impreso firmado por Consolación','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2017-07-03','Se recibe en la CTAEx Informe de la Residencia "Padre Damián" de Plasenzuela. SE ha enviado al Juzgado desde la Residencia el pasado día 30 de junio. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llama Alfredo Moreno, de la Residencia (619-459281) para comentar lo siguiente: +++Dª Rosa NO HA RECIBIDO VISITA alguna desde su ingreso en la Residencia. Solamente la llama de vez en cuando una sobrina desde Sevilla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2017-07-03','Conversación con Servicios Sociales de Portugalete. Contacto D. Javier Ruiz (Director de SS). Teléfono 944-729272. +++El Ayuntamiento no está pagando ninguna cantidad periódica a Dª Carmen (como esta comentó en la Comisión hace unos días). Está dada de baja en los Servicios Sociales de Portugalete desde hace años, sin ningún contacto con ella. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Mª Jesús (ISS).924-216167. +++Comunica que la denegación de la P.O. es correcta, por carecer su padre de las cotizaciones necesarias, a pesar de haber cotizado un tiempo en el retiro obrero. +++Optamos entonces por la PNC y no por la PF.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='SANCHEZ'and apellido2='GONZALEZ'),'2017-07-03','Llega a la Comisión el DNI, original y permanente de D. Antonio, procedente del CSS de Mérida. Al parecer lo ha solicitado algún familiar para un tema de herencias. +++Se queda con Maribel, T. Soc., en que si lo quieren que lo pidan a la Comisión, pero que no se entregará nada hasta que tengamos la aprobación de la Rendición Final de Cuentas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GONZALEZ'and apellido2='GONZALEZ'),'2017-07-03','CITADA en el ESM de Coria el próximo día 12 de julio a las 11:30h. Psiquiatra Dr. Juan José Mora Mesa. +++Contactar con el ESM tras la consulta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AIDA MARIA'and edp.apellido1='MARTIN'and apellido2='DE PIÑOL'),'2017-07-03','Futuex presenta tres presupuestos de seguro de hogar: "la agencia que más tranquilidad nos aportó en las visitas fue AXA, puesto que nos dieron la opción de actuar de forma inmediata ante cualquier problema de la vivienda. +++AXA.........119.80€ +++CASER.......117.64€ +++ATLANTIS....203.09€ +++ Su hermana se ha encargado de dar de baja el seguro anterior.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2017-07-03','Conversación con Mª Jesús (ISS).924-216167. +++Comunica que la denegación de la P.O. es correcta, por carecer su padre de las cotizaciones necesarias, a pesar de haber cotizado un tiempo en el retiro obrero. +++Optamos entonces por la PNC y no por la PF.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2017-07-03','Llamo a D. Ventura (622-356104) para ver cómo se encontraba y comprobar que le habían dado el alta el pasado viernes: +++Le dieron el alta el viernes 30 de junio. SE encuentra bien y, en le momento de la llamada se encontraba en el hospital porque le tenían que hacer unas pruebas. +++AMENAZAS: vuelve a decir que ha estado en el Juzgado y que el juez le ha dicho que todo es suyo y que se lo tenemos que dar: "...Si no, van a ir a por vosotros y a por tí..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='MUÑOZ'and apellido2='CAMACHO GARCIA'),'2017-07-03','Llama Ana, T.S. de Esparragosa de Lares 616 17 92 55, para preguntar por la situación de la incapacitación de Juan,que en la actualidad se encuentra en los pisos tutelados santa Catalina, se le indica que ya se ha aceptado el cargo. Nos comenta que Manuel está desaseado y no quiere cambiarse de ropa. Hoy va al hospital Infanta cristina en Badajoz para una consulta por una herida en la boca que según ella va a tener que ser operada. Nos facilita el teléfono de la directora de los pisos tutelados Mª CArmen 619 51 07 46','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='ALONSO'and apellido2='SEGOVIA'),'2017-07-03','Llamamos a la REsidencia Ntra. Sra. de la Piedad de Almendralejo por las facturas de peluquería que han enviado, no nos dicen el número de cuenta bancaria donde hacer la transferencia. Nos dice el administrativo, Juan, que tenemos que hablar con la directora, Verónica, que no vuelve de vacaciones hasta el lunes 10/7/17. Quedamos en volver a llamar el lunes','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='MUÑOZ'and apellido2='CAMACHO GARCIA'),'2017-07-04','Hablamos con la directora de los pisos tutelados, Carmen, nos comenta que el viernes 7 de julio le van a hacer a Juan una biopsia por la herida de la boca en el hospital de Badajoz. Necesitará acompañamiento. Ella ha enviado a Ana Luque, la T.S. de Esparragosa, el consentimiento informado para que nos lo envie. Se le facilita dirección de correo electrónico y telefónos de la comisión para que directamente se pueda ella poner en comunicación con nosotros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='VALADES'and apellido2='DIAZ'),'2017-07-04','Reunión con Isabel: +++Ha hablado con su familia-dice- y su ex-marido comenta que no le ha cogido el teléfono y su madre no le "puede" ayudar más.Tampoco quieren que se vaya a vivir a Don Benito. +++Ayer sacó 80€ que dice se gastó en pagar deudas que tenía (tabaco pendiente, etc) y que apenas tiene comida salvo para cenar...Pide 50 € para esta semana y, tras mucho hablar con ella, se le autoriza a sacr ese dinero, advirtiéndole que debe comprar solo comida y que traerá los comprobantes de compra. +++A partir del 15 de julio sacará 110€ cada quince días (115€/dos semanas). No quiere sacar 55€ por semana porque dice que "no me encuentro segura con tan poco dinero...". En caso de que esto no funcione se pasará a los 55€/semana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2017-07-04','Comunican desde el CSS de Mérida la fuga de D. Antonio en la mañana de hoy. +++Refieren que ha sacado 100€ en una sucursal de Badajoz. +++COMUNICO al Juzgado de Instrucción nº 4 de Badajoz la situación, de la que ya eran conocedores (por el CSS) y quedan en, si tuviesemos algo más que hacer desde la CTAEx, nos llamarán mañana porque hoy están de guardia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2017-07-04','Llamada de D. José Florencio: +++Según comenta, esta mañana ha ido al C. Salud y su médico le ha dicho que tiene que ir a un dentista particular. Dice tener cita la próxima semana. +++SE le indica que, antes de hacer nada, le pida un presupuesto para ver los gastos que su intervención va a suponer.Una vez que lo tenga, nos lo enviará.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL MAR'and edp.apellido1='GORDILLO'and apellido2='SANTANA'),'2017-07-04','Llama el gerente de los pisos tutelados de Zafra, Ramón, para indicar que Mª del Mar, necesita algo más de dinerodel que llevó en mano. Serían 60€ mas, en total 370. Nos envía un correo electrónico. En principio comenta que Mª del Mar se quedaría en los pisos mas del mes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2017-07-05','Hablo con la inmobiliaria "LA Oficina"- Esther- le indico que tal como establece el contrato de alquiler los recibos de luz y agua del piso se van a abonar mediante transferencia al propietario como se establece en el contrato. Habíamos recibido un correo electronico de Beatriz indicando que el propietario le reclamaba los importes de los suministros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2017-07-05','Llama Gisela para comentar que José Manuel sin autorización se ha dado de alta en una línea de móvil. Están gestionando desde el centro la baja. Además debido al mal comportamiento que está teniendo el dinero extra - 100€ para ropa- que tenía para sacar hoy no lo va a tener hasta que ellos nos escriban un correo autorizando el reintegro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='ANTUNEZ'and apellido2='SANZ'),'2017-07-05','llama Montse de Servicios Sociales de Villafranca, -tlf 924 52 78 22- para indicar que de la casa social que Josefa tiene en la calle López de Ayala 22 se están recibiendo quejas por parte de los vecinos ya que vuelve a acumularse basura, y está habitada por gatos, ratas... Nos pide que se lleve a cabo alguna actuación como ya se realizó en el pasado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2017-07-05','Hablamos de nuevo con María por el tema del teléfono móvil que el hijo de Felisa, Aitor Moreno, ha estado utilizando y cómo gestionar la deuda que ha generado con Orange. Nos facilita el número móvil ( 635 180 094)de Emilio González Julián, exnovio de Felisa y que era el titular de la línea de teléfono. le llamamos para que nos facilite su DNI y el nº del teléfono para poder hacer la transferencia a Orange por los 107,57 €, no contesta. Además nos informa que el hijo, después de los altercados con la madre volvió a Valcorchero pero el fin de semana después de otro incidente en el centro la Fiscalia le ha ingresado en el centro Marcelo Nessi durante 4 meses. Nos comentan que igual sería bueno que Felisa pudiera visitarle una vez al mes. HAn enviado dos presupestos de gafas enviarán la factura con nº cuenta para transferencia del presupuesto más bajo pues creen que con esas es suficiente. Enviarán también correo electrónico con precio del abono mensual de la piscina pues creen que sería beneficioso para Felisa pues así no estaría todo el día en casa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2017-07-05','Llama Pilar Bueno, tl 927 42 88 00 T:S. del Sociosanitario de Plasencia. Indica que como terapia recomendada por el psiquiatra ´sería bueno que pudiera comprar un mp3 pues el que tiene tiene grabadora y en el centro no está permitido. Como Jose Mª no puede salir a comprarlo por riesgo de fuga sería aconsejable enviar a alguien de futuex para que lo comprara y pagarles en el centro','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2017-07-06','(Pedro).Se envía al Juzgado de D. Benito solicitud de aplazamiento de la videoconferencia prevista para el 10 de julio en Mérida, al estar D. Francisco residiendo en el CRR de Plasencia. Se remite por fax.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='MUÑOZ'and apellido2='CAMACHO GARCIA'),'2017-07-06','(ICIAR) Hablo con Ana la T.S. de Esparragosa, nos envia por mail el consentimiento informado y la cita de Juan para el viernes, se lo hemos devuelto firmado. Ella se encarga de que la acompañante de Juan lo lleve al hospital. Ana ha buscado a alguien de confianza para que acompañe a Juan el viernes, me dice lo va a comentar con Carmen, la directora. Le comento que el precio sería de 10€/hora. Queda en llamarnos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2017-07-06','(Pedro). Conversación con María, Educadora Social: +++Dª Felisa no quiere perjudicar a su hijo y por lo tanto no quiere que seamos parte en el procedimiento abierto. +++Pedir a Futuex seguimiento del caso y coordinar con ellos las visitas a su hijo, en estos momentos en el Marcelo Nesi, una vez al mes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2017-07-06','(Iciar).Se recibe auto 135/2017 por la modificación de medidas supuesto contencioso 655/2016 donde indica el jda nº 3 de cáceres que se archiva el procedimiento por falta d capacidad procesal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-07-07','Llamada de Mercedes. T. Soc. de Trujillo (927-659391): +++La madre de Betariz se ha vuelto a marchar de casa. Está ahora sola con el padre y su pareja. +++Tiene dificultades para ir sola al médico y para otras gestiones. Pediremos a Futuex que haga el seguimineto. +++Todavía desconocemos los datos sobre cuentas, etc.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2017-07-07','(Pedro)LLama D.Alfoncso Serrano (918-459013), abogado de la familia de Dª Antonia para tratar el tema de la herencia. +++Se le indica el correo-e de la CTAEx para que se ponga en contacto con nosotros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SAUL'and edp.apellido1='RODRIGUEZ'and apellido2='RAMOS'),'2017-07-07','Llama el padre de Saul, D. Manuel Rodríguez y un amigo de éste, preguntando "por los papeles de la herencia" ya que les dijimos que los habíamos enviado al juzgado. +++Le pido que llamen cuando esté el compañero que lleva el tema.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PAULA'and edp.apellido1='SOLANA'and apellido2='GUERRA'),'2017-07-10','ICIAR: Enviamos por correo con acuse al Jdo de 1ª instancia nº 4 de Cáceres oficio contestando a su Providencia para la posible rehabilitación del derecho de sufragio, adjuntando sentencia e informes, indicando que la Comisión se atendrá a lo que el médico forense determine.','2');
