insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JUANA'and edp.apellido1='VECINO'and apellido2='GARCIA'),'2017-07-11','Se envía a Juan Mora (Convenios Internacionales ISS, 924-216169 y correo-e: juan-bautista.mora@seg-social.es) documentación de Alemania sobre la pensión que Dª María percibe de allí, para su traducción.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GABINA'and edp.apellido1='GOMEZ'and apellido2='SANCHEZ'),'2017-07-11','Conversación con Lola, Alcaldesa de valle de Matamoros (627-581535 y correo-e: valledematamoros@hotmail.com): +++Enviará presupuesto para la lápida de Dª Gabina y nos lo enviará por correo-e.Una vez aprobado, enviará la factura para su pago. +++¿Quién debe abrir el testamento de Dª Gabina? Una sobrina lejana dice que no quiere saber nada y creen que todo lo deja a un vecino.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIANA PAULA'and edp.apellido1='CENTENO'and apellido2='RODRIGUEZ'),'2017-07-11','ICIAR: Nos ponemos en contacto con Futuex para que pasen por la Residencia Care donde reside Juliana Paula y recojan las llaves de la vivienda de la que es inquilina pues según nos dicen por teléfono y correo electrónico la administradora de la Comunidad de Propietarios, Gemma Martín Porras, se están produciendo filtraciones de agua y humedad a los pisos inferiores.Acompañarán a la administradora en la visita a la vivienda en la fecha que acuerden con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2017-07-11','Conversación con Inmaculada Gema Pérez Dorado, Departamento de Trabajo Social del Hospital Nacional de Parapléjicos de Toledo (925-247753 y correo-e: igperez@sescam.jccm.es). +++Se le inofmra del trámite para valorar si COCEMFE es el centro adecuado para Tomás. +++RUEGA se agilice todo lo posible y se le inoforme del centro al que trasladarlo lo antes posible para preparar dicho traslado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUCAS'and edp.apellido1='DIAZ'and apellido2='VAZQUEZ'),'2017-07-12','(Pedro)Conversación con Clemen, directora del CAMP de Don Benito (924-021562): +++No han enviado todavía el consentimiento para intervención de criptorquidia, ni el Informe médico valorando la posibilidad de inyección intracavernosa. +++Retomará el tema y nos informrá.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2017-07-12','(Pedro) Conversación con Clemen, Directora del CAMP de Don Benito (924-021562). +++Lleva una temporada que se está portando bastante bien. +++DUDA actual: permitirle irse de vacaciones con su familia y que pueda volver a consumir y al comportamineto anterior o no permitirle salir, con el riesgo de que se pueda escapar. +++POSIBLES ATERNATIVAS: que la familia vaya a pasar un fin de semana a Cabeza del Buey (aunque sea Hermenegildo el que tenga que pagar el hostal a algún familiar); que algún cuidador del CAMP lo acompañe a su pueblo durante ese fin de semana (pagándole la estancia), cosa poco viable seguramente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICENTE'and edp.apellido1='MARQUEZ'and apellido2='CABEZA'),'2017-07-11','PENSIÓN Se recibe resolución del INSS reconociendo el complemento de mínimos. Atrasos: 86.70€. Nueva pensión: 617.79€+19.91€=637.70€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2017-07-12','(Pedro)Conversación con Mariola, T. Soc. ESM de Jerez de los Caballeros (41610): +++La familia de Ramón le ha comentado que le dan el alta a finales de mes. +++En visita domiciliaria refiere que la casa es un síndrome de Diógenes, y que no está para que Ramón vuelva a ella de alta.Lo ha comunicado al Ayto. para que se procedsa a la limpieza lo antes posible. Enviará Informe a la CTAEx. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Taciana (CSS Mérida, 24065): +++Confirma que el alta está prevista para finales de mes. La semana que viene se reunen con él y si todo sigue igual se le dará el alta la siguinete. +++Informan de que van a prohibir las visitas de la familia a Ramón, porque el otro día trataron de vender droga a los pacientes. +++Se le informa de la situación de la vivienda, pero el paciente está para alta médica. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Se envía por fax al Juzgado respuesta a la Providencia de 29 de junio de 2017.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='ROMERO'and apellido2='VERA'),'2017-07-12','TRABAJO Se recibe el contrato de trabajo y primera nómina. Prestará sus servicios en el Ctro. Especial de Empleo de Llerena. Se procede a remitir copia, de ambos dos documentos, a PNC. Salario: 728.93€/mes brutos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TERESA'and edp.apellido1='MANGAS'and apellido2='DE LA CRUZ'),'2017-07-12','(Pedro)Llamada de María, T. C. Salud de Zafra (45970): +++Pregunta ¿quién se hace cargo del traslado de Dª Teresa? No pued ser desde el C. salud con ambulancia porque no es un traslado sanitario. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Consulto con Curro y no sabe, ya que al ser solamenten Defensores Judiciales no nos correspondería. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con la Jueza del caso: Al no haber familiares, debe ser el Defensor Judicial el que se encargue del traslado. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamada al 112: no se pueden hacer cargo de dicho traslado al no ser de carácter sanitario. Sí se les puede llamar en caso de que la persona se resista al mismo a la hora de cumplir con la medida cautelar, poniéndose ellos en contacto con el Médico de Familia y en su caso con la Guardia Civil.','2');
