insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2017-07-12','ICIAR: Hablamos el jueves-viernes con Emilio González Julián, el exnovio de Felisa, para que nos facilite su nº de DNI y el nº de teléfono móvil que utiliza el hijo de Felisa, Aitor, y cuyo titular es Emilio, para poder pagar la factura pendiente de 107,57€ que ha dejado Aitor, pues es quien supuestamente lo utiliza. Me es imposible porque no atiende a razones y me cuelga el teléfono. Me pongo en contacto con María del programa familia, Tl. 609 38 24 39, y ella me consigue el teléfono - 675578976 y el DNI de Emilio- 06983514 R. Hablo con Orange y nos confirman la deuda y también nos dicen que el recibo de julio ha sido devuelto por el banco por 53,92€.HAremos transferencia bancaria y enviaremos justificante de pago al fax 91 838 27 06','2');
