insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2017-07-18','Acudimos hoy al Juzgado de 1ª. Instancia e Instrucción nº 2 de Trujillo, al Juicio sobre delitos leves 18/2017. Se presenta Vanesa con su hermano Ricardo. Se suspende el juicio porque, según el Juzgado, no tienen constancia formal de citación a la otra parte. Hablo con su señoría y le transmito nuestro malestar por hacernos acudir al Juzgado, conociendo éste esta circunstancia. Su señoría nos transmite sus disculpas. Volverán a citarnos para nueva vista.','2');
