insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2017-05-22','SALIDA El 22/05/2017 (MAP). Acude para revisar la medicación que actualmente toma, saber si tiene fecha la cita que tiene pendiente del oftalmólogo y cambiar el domicilio de la tarjeta sanitaria.* Nos entrega la hoja de tratamiento, pero tampoco coincide con lo que dice Joaquín, ahora nos da la dosis (1/2)-1/(2-1), lo ha mirado del informe de la neuróloga de 2014, pero Joaquín dice que el psiquiatra se lo bajó a (1/2)-1/(2-1)/2 en la última visita.****************************************El médico hace hincapié en que es alérgico al ibuprofeno y a la aspirina.***************************************************No se puede cambiar el domicilio porque no llevan el DNI. No aparece que esté pendiente ninguna cita con el oftalmólogo, debe ir a su Médico de Atención Primaria y pedir volante.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2017-06-04','SALIDA El 04/06/2017 (Urgencias). Joaquín recibe un golpe en la cara en una agresión que recibe de un chico que su familia ha tenido problemas con la madre de Joaquín. Acude a urgencias y le hacen un parte de lesiones para hacer la denuncia. Tiene el labio hinchado y parte de la cara.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2016-06-12','SALIDA El 12/06/2017 (Psiquiatra). Joaquín le comenta el altercado que ha tenido con el chico que le pegó. Le comenta que quiere irse de Montijo porque sus amigas ya no quieren estar con él y tiene miedo de salir a la calle. Le sube el Risperdal de la noche a 1 y quedaría (1/2)-1/(2-1). Keppra se queda igual. Vuelve a revisión el 15/11/17, a las 13.10 Hs. Si le notamos angustiado podemos darle 1/4 más de Risperdal. Joaquín le comenta si puede dejar de tomar Keppra y le dice que eso tiene que decírselo el neurólogo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2017-04-07','SALIDA Entre el 07/04/2017 y el 17/04/2017. Viaja a Badajoz a casa de su hermana para pasar las vacaciones de Semana Santa. El viaje lo realiza en autobús.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2017-05-29','SALIDA Entre el 29/05/2017 y el 02/06/2017. Viaja a Madrid en una escursión organizada por el centro. El viaje lo hacen en tren.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2017-06-12','SALIDA Entre el 12/06/2017 y el 16/06/2017. Viaja a Mazagón con motivo de la escursión a la playa que organiza P. I. Montijo todos los años. El viaje lo hacen en autobús.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2017-03-27','SALIDA El 27/03/2017 (Neumólogo). Le realizan espirometría de pie y tumbado. Le resulta extráño que tiene mejores resultados tumbado que de pie. Le dan de baja en el uso de la máquina para dormir porque le comentamos que no la usaba. Entregamos la máquina y nos dan una ficha que asegura que ya la hemos entregado. Entrega informe de la espirometría. Próxima cita: 26/04/2018, a las 12.40 Hs.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2017-04-05','SALIDA El 05/04/2017 (MAP). Tiene una contractura lumbar. Le manda ibuprofeno por si le duele. Es debido a las malas posturas porque pasa mucho tiempo sentado con el móvil y la tablet. Nos da información sobre higiene postural y le recomienda unos ejercicios para cuando se levante. Le recomienda dejar el baile activo y que haga yoga o pilates. Cada hora que pase sentado tiene que andar y levantar la vista. También debería andar de lunes a viernes 30 minutos. Paracetamos 4000 1-1-1 durante 5 días.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2017-04-26','SALIDA El 26/04/2017 (MAP). Se nota fata de audición en el oído izquierdo. Su doctora lo explora y tiene otitis. Tiene que echarse 2 gotas cada 12 horas de 8 a 10 días (Otix). Si no remite hay que volver.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2017-05-29','SALIDA Entre el 29/05/2017 y el 02/06/2017. Viaja a Madrid en una excursión organizada por el centro. El viaje lo hace en tren.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2017-06-12','SALIDA Entre el 12/06/2017 y el 16/06/2017. Viaja a Mazagón con motivo de la excursión a la playa que organiza P. I. Montijo todos los años. El viaje lo hacen en autobús.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2017-07-18','SALIDA En el aspecto sanitario, este segundo trimestre de 2017 acude a sumédico de cabecera para comentarle que tiene tos y pitos y, después de examinarla, observa que tiene infección, le dice que puede ser de la alergia. Le receta MEIACT (1-0-1), Deflazacort (según pauta por escrito hasta el jueves 25) y omeprazol (uno al día). Revisión: 05/06/2017, a las 10.40 Hs. Cuando va a revisión la reconocen y le dice que ya no se le escuchan pitos.*********Tiene revisión con la Podóloga. En consulta de enfermería se hace analítica y se inyecta TREVISTA. Próxima cita: 24/08/2017, 9 Hs.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2017-07-18','SALIDA Relativo a la salud las visitas médicas que ha tenido en este segundo trimestre, a parte de acudir a su médico de familia porque le duelen muchos las varices, pero le dicen que no las tiene muy profundas. Le recomienda duchas frías de abajo a arriba, poner los pies en alto cuando se siente, caminar, nadar o andar en bicicleta, en invierno usar medias de compresión y para trabajar ponerse zuecos ortopédicos. Si todo esto no funciona tiene que tomar diosmina 100 (1-0-1). No nos da receta con lo cual habría que volver. También ha acudido a la podóloga para tratamiento del pie.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2017-07-18','(Pedro) Se pide el último Informe de Psiquiatría de Familia en el que se produce un cambio en el diagnóstico de D. ramón. +++Lo enviarán a la CTAEx (corre-e y/o fax) o directamente a María Barrasa.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2017-04-18','SALIDA El 18/04/2017. (Inyectable COPF). Se pone el inyecable anticonceptivo. Próxima cita: 18/07/2017, a las 12 Hs.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2017-04-26','SALIDA El 26/04/2017 (Psiquiatría). Mantiene medicación. Dice que los cambios que tiene de humor son normales, siempre que sean puntuales. Próxima cita: 20/09/2017, a las 12.30 Hs.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2017-05-04','SALIDA El 04/05/2017 (dentista). Una vez finalizado el tratamiento de la piorrea le dicen que ha mejorado bastante y que ya no tiene las encías tan inflamadas. Tiene muelas picadas y que está en muy mal sitio porque están bajo la encía. La solución que proponene es quitar el último diente (está picado) ya que se le mueve y luego ver si le podrían empastar el otro diente, sino habría que quitarlo también. Si no se solucionan las cries puede afectar a las piezas de al lado. Le hacen limpieza para quitarle el sarro. Debe lavarse mejor los dientes. Tiene que volver a revisión en noviembre la icta para extraer la pieza es el 10/05/2017, a las 11 Hs.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2017-05-10','SALIDA El 10/05/2017 (dentista). Le extraen una muela y valoran si le pueden hacer un empaste en la pieza que tiene mal al lado y aunque es complicado porque la caries está por debajo de la encía creen que podrán. No debe hacer buches de agua ni comer cosas calientes en las primeras horas. Si tiene dolor debe tomar paracetamol o ibuprofeno. Próxima cita el 14/06/2017, a las 17.30 Hs.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2017-06-14','SALIDA El 14/06/2017 (dentista). Le realizan un empaste y tiene que volver a revisión de la piorrea en noviembre. Hay que pedir cita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2017-07-18','(Pedro) Hoy ha venido Dora Salamanca (620226363), madre de Javier. Yo estaba de viaje. +++Concierto entrevista para mañana a las 10:00h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2017-07-18','(Pedro)Comparecencia en el Juzgado nº 1 de Zafra para revisión médico-forense. +++No teníamos notificación alguna al respecto, indicándonos dicha citación la propia tutelada. Esta misma mañana he pedido al juzgado nos enviaen la ciatción por fax, comoa sí ha sido. +++Ya en el Juzgada nº 1 hemos realizado una comparecencia a los efectos de que cualquier tema relacionada con Dª Beatriz nos sea comunicada a la dirección de CTAEX, además de a la propia interesada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JORGE'and edp.apellido1='FERNANDEZ'and apellido2='CERECINOS'),'2017-08-05','SALIDA El 05/08/2017. Visita a su hermano, acogido en el centro APROSUBA - 9, de Villanueva de la Serena (Badajoz).*********Ya está organizado el medio de transporte y personal auxiliar que le acompaña.*************Los gastos de taxi y acompañante corren a cargo del paciente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SARA'and edp.apellido1='VAZQUEZ'and apellido2='GILES'),'2017-07-19','SALIDA El 19/07/2017. Desde el centro se realizará una salida a La Cardenchosa (pedanía perteneciente a Azuaga).','2');
