insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='HURTADO'and apellido2='ARROYO'),'2017-07-19','FALLECIMIENTO El día 18/07/2017.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='HOLGUIN'and apellido2='MENESES'),'2017-07-19','(Pedro) Llamada a Cristina, de Aprosuba 12. +++En respuesta a su "disconformidad" en la actuación de la Comisión en relación al fallecimiento de D. Manuel: único "fallo" el no haber acusado recibo del primer correo. Resto de críticas, sinb justificación respecto a los medios de la Comisión para que no se produjesen las causas que las motivaron. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo al cuñado de D. Manuel (664-646662/924-760365):NO CONTESTA (dejo mensaje).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SARA'and edp.apellido1='VAZQUEZ'and apellido2='GILES'),'2017-07-20','(Pedro) Se remite Informe del ESM de Jerez de los Caballeros para adjuntar a la documentación d a presentar en el Cadex. Se remite por correo-e a Carmen Franco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2017-07-20','(Pedro)Conversación con Carmen Barquilla (Fiscal).927-620265. Preocupada por ventura, porque cree que el dinero que se le da al mes lo destina a la mujer que convivió con él (el escrito que nos mandó "...no se refería a que le diéramos más dinero, ya que se está haciendo como se indica en el Auto, sino en este sentido que comento ahora...". ACTUACIONES: +++Solicitar a Futuex un incremento de la frecuencia en las visitas (control sobre todo de alimentación y estado de la vivienda). +++Hablar con su abogado por si supiera algo al respecto. +++Obtener extractos bancarios desde que se le aumentó la asignación (solicitado). ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a Toni (Futuex): la pongo al corriente. Incrementarán la frecuencia de las visitas y nos mantendrán informados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2017-07-20','(Pedro) Llamada de Javier (657-833008). Ayer habló con su madre de la reunión que mantuvimos con ella: +++EXIGE dinero para irse de vacaciones, prometiendo que no volverá a comprar más móviles a partir de ahora, que gastará menos dinero en teléfono, etc. +++Se le pide que mantengamos una reunión mañana, 21 de julio, para hablar sobre su situación económica: "...pues no voy a ir, porque para que me digas que no me puedo ir de vacaciones no voy..."','2');
