insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2017-07-24','TRAS LA PETICIÓN DEL JUZGADO Nº 4 PARA QUE PRESENTEMOS LA CORRESPONDIENTE RENDICIÓN ANUAL ME PONGO EN CONTACTO CON EL JUZGADO Nº 4 QUE TAMBIÉN LLEVA EL PROCEDIMIENTO DE JURISDICIÓN VOLUNTARIA 177/2016 DEL INTERNAMIENTO INVOLUNTARIO PARA CONOCER SI HAY ALGUNA NOVEDAD EN EL MISMO. ME COMENTA LA OFICIAL DEL JUZGADO QUE EL PROCEDIMIENTO CONTINUA ABIERTO ESPERANDO QUE POR NUESTRA PARTE COMUNIQUEMOS UN DOMICILIO DEL TUTELADO. LE DIGO QUE CONTINUAMOS SIN SABER NADA DE EL , OPINA QUE AL SER UNA CUESTION CIVIL NO PUEDEN PONERLE EN BUSCA Y CAPTURA YA QUE ESE SUPUESTO ES SÓLO PARA CASOS PENALES. POR TANTO PROCEDO A INFORMAR AL JUZGADO QUE NO ES POSIBLE PRESENTAR LA RENDICIÓN ANUAL YA QUE NO TENEMOS NINGUNA INFORMACIÓN DE RAFAEL Y SOLICITAMOS QUE EL JUZGADO ACTIVE LOS MEDIOS OPORTUNOS PARA INTENTAR SU LOCALIZACIÓN YA QUE PARA NOSOTROS ES IMPOSIBLE .','2');
