insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2017-06-23','Buenas tardes. Disculpeme por la tardanza en contestar.Imagino que les habrá extrañado,debido a la urgencia con la que les solicité la reunión.A final de mes he tenido muchos temas familiares(complicados) y no he abierto el correo hasta hace dos días,lo siento.Ahora me encuentro en Madrid con mi hijo en terapia de logopedia. María Murillo dejó mi casa,creo que el 21 o22 de junio, según me contaron los vecinos.Ella no me comunicó nada ni me devolvió las llaves.A los pocos días, volvió a mi casa a recoger algo suyo,y como no llevaba la llave golpeó la cerradura hasta conseguir reventarla y poder entrar.Desde entonces no sé nada más. Le agradezco su interés. Un saludo','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2017-07-04','Correo-e de la propietaria de la vivienda ocupada por María. +++Buenas tardes. Disculpeme por la tardanza en contestar.Imagino que les habrá extrañado,debido a la urgencia con la que les solicité la reunión.A final de mes he tenido muchos temas familiares(complicados) y no he abierto el correo hasta hace dos días,lo siento.Ahora me encuentro en Madrid con mi hijo en terapia de logopedia. María Murillo dejó mi casa,creo que el 21 o22 de junio, según me contaron los vecinos.Ella no me comunicó nada ni me devolvió las llaves.A los pocos días, volvió a mi casa a recoger algo suyo,y como no llevaba la llave golpeó la cerradura hasta conseguir reventarla y poder entrar.Desde entonces no sé nada más. Le agradezco su interés. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2017-06-23','Correo-e de la propietaria de la vivienda ocupada por María. +++Ver Expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2017-07-24','(Pedro) LLamada de Carmen, T. Soc. del ESm de Cáceres: no ha vuelto a saber nada de María desde que tuvimos la reunión. Se ha enterado de que ya se marchó de la vivienda que tenía ocupada pero ahora no sabe dónde está. +++La próxima cita con el Psiquiatra, Dr. samino, es el 24 de agosto. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ (Pedro) Conversación con Dª Mª Soledad, madre de María: +++NUEVOS INCIDENTES: +++++ hace unos días la detuvo la Policía en el Corte Inglés. +++++ su perro atacaó a un señor, pero este no quiso poner dencuncia. +++++ ha vuelto a contactar con su padre, pero al parecer, en una de sus vistas al domicilio, "montó una buena que obligó a llamar al 112...Pero su padre le dijo que se fuera antes de que llegaran..." +++Desconoce su actual paradero: al parecer vive en casa de algún amigo. +++Dª Soledad cree que si no fuera por el perro, María querría ingresar voluntariamente. Sin embargo, su madre se ha ofrecido acuidar de él para que ingrese y ella no ha aceptado. +++Dª Soledad asegura que la única manera de intervenir con su hija es a través del ingreso (clínico o por denuncia) y no confía especialmente que la situación de su hija "tenga arreglo". +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++LLamo varias veces a la Fiscalía de Badajoz pero no me cogen el teléfono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-07-24','(Pedro) Información de Futuex: +++Próximos controles de gestación: 25 de julio (Matrona del C. Salud) +++La acompañarán a las visitas programadas hasta el parto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2017-07-24','(Pedro). Conversación con Gema (Admva de la Residencia "El Pendere": +++No están ni la Directora (Begoña) ni Cristina (E. Social). Las llamaré mañana. +++Gema comenta que D. Arturo está muy bien integrado en el centro, que se relaciona con todo el mundo y que ha dejado de decir que se quiere marchar a su casa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2017-07-24','(Pedro) Se recibe informe de la visita realizada por Futuex. La petición más importante para Dª Felisa es poder ir a ver a su hijo una vez al mes. +++Descartados tren y autobús, según informe, se considera que el medio de transporte más adecuado es el taxi, por la seguridad que ofrece a Dª Felisa ir sin escalas hasta el Marcelo Nesi. +++TAXISTA DE CONTACTO en Navas del Madroño: ANTONIO. Teléfono: 658-801614.PRECIO IDA Y VUELTA:100€. +++Paso a Alberto la forma de pago de estos viajes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2017-07-25','(Pedro). Llamada de Ana, Psicóloga del CAMP (20111). +++Sobre el mismo tema anterior.No cree que sea oportuno que se vaya a casa este fin de semana.SE plantean las mismas opciones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2017-07-25','(Pedro)Conversación con Futuex y con Valentina, T. Soc. del centro de Salud de Aldea Moret (52515). +++En caso de resistencia para el traslado, llamar al 112. +++Se envía a Valentina autorización judicila de ingreso por si se debiera activar el 112. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Amparo (36620) Directorea de "El Cuartillo". +++Misma solución en caso de resistencia. +++Se le envía por correo-e la documentación de ingreso. +++CORREO-E: desamparados.garcía@salud-juntaex.es','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2017-07-25','(Pedro) Conversación con Begoña, Directora de "EL Pendere". +++La integración de D. Arturo es inmejorable. +++Solicito informe sobre su situación personal, nivel de integración, relaciones personales, etc. LO enviarán.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SAUL'and edp.apellido1='RODRIGUEZ'and apellido2='RAMOS'),'2017-07-26','Acudimos ayer al Juzgado de 1º. Instancia e Instrucción nº 1, de Jerez de los Caballeros, en relación con la comparecencia relativa a la autorización judicial solicitada para aceptar la herencia de su madre (Procedimiento X15 Autoriz Jud Disposición Bs Menores/Discapac 368/2017). La Fiscal no se opone con lo que estamos a la espera de recibir la autorización judicial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2017-07-26','Enviamos contestación al Juzgado de 1ª. Instancia e Instrucción nº 3, de Cáceres, en relaciòn con la recuperación de su derecho de sufragio pasivo, proponiendo al Juzgado que lo examine el forense, adhiriéndonos a lo que dictamine.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIO'and edp.apellido1='GUISADO'and apellido2='GUISADO'),'2017-07-26','SALIDA El 26/07/2017. Se desplazará a Córdoba para pasar el día en el Acuapark. Irá acompañado de compañeros y monitores del centro. Saldrán sobre las 9 Hs. y llegarán al centro sobre las 22:30 Hs., aproximadamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN'and edp.apellido1='GUTIERREZ'and apellido2='RONCERO'),'2017-07-26','Hemos solicitado abogado de oficio para la venta del piso que tiene en herencia junto con sus hermanos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LEON'and edp.apellido1='LEAL'and apellido2='PEREZ OLAGUE'),'2017-07-26','Enviamos al Ayuntamiento de Valencia, solcitud de liquidación de la Plusvalía, por la venta del local en Mora de Rubielos, 14-6 de Valencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2017-07-26','Envío autorización a Francisco Javier Fernández Rodríguez, Director del CRR de Plasencia, para que acompañe a Francisco Cuevas, a la toma de declaración que tendrá lugar en Don Benito y a través de videoconferencia en Plasencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GABRIEL'and edp.apellido1='SOBRINO'and apellido2='TARDIO'),'2017-07-12','SALIDA Entre el 12/07/2017 y el 17/07/2017. Viaje a la Línea de la Concepción junto a otro grupo de compañeros, así como profesionales y voluntarios del centro que puedan prestarle el apoyo que precise.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GABRIEL'and edp.apellido1='SOBRINO'and apellido2='TARDIO'),'2017-07-18','REGRESO Y SALIDA Regresó ayer (17/07/2017) de las vacaciones en la Línea de la Concepción y se marcha a casa, el viernes, a pasar unos 15 o 20 días.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIA'and edp.apellido1='MARQUEZ'and apellido2='ANDRADE'),'2017-07-27','(Pedro) Llamada de Pilar, T. Soc. CSS Plasencia (24166): +++Victoria no quiere volver a ASINDI. +++Va a solicitar cambio de centro, para lo cual nos enviará dicha solcitud para que LA FIRMEMOS y se la renviemos nuevamente a Pilar para su tramitación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-07-26','(Pedro) Comparecencia en el Juzgado de 1ª Instancia nº 2 de Trujillo. +++PRESENTES: Jueza (Patricia), Fiscal (Carmen Barquilla), Francisco Sánchez (Letrado Junta), Mara Cendal (DG Infancia y Familia),Beatriz, D. Andrés (padre) y Pedro (CTAEx). +++CONCLUSIONES: *****durante los tres meses de gestación que quedan, se mantendrá en domicilio. *****se intentará mejorar las condiciones de habitabilidad de la vivienda solicitando el SAD. *****se intentará, a través del Programa de Familia, trabajar con Beatriz para que esta vaya adquiriendo conciencia de lo que significa tener un niño (ella tiene mucho miedo a que se lo quite la Junta), al menos hasta donde esto sea posible. ******se solicitará autorización judicial para uso de método anticonceptivo tras el parto (reversible según Juzgado). ******una de las protestas de Beatriz es que no puede manejar dinero (su padre no le deja) "y... tengo que comprarle ropita a mi bebé, pañales..."En vista de ello ycomo forma de que podamos conseguir algo de confianza por su parte, se le van a autorizar 20€/semana como gastos de bolsillo. *****paralelamente, se está gestionando el perfil para el acceso a centros así como la Dependencia, para que en el momento de dar a luz podamos tener el recurso preparado (ella no quiere ir a ningún centro). *****BEBÉ: desde la DG de Infancia y familia se están haciendo las gestiones para asumir la tutela del bebé, con la posibilidad de acogimiento familiar con derecho a visitas (VALORAR QUÉ PUEDE SER MÁS """"POSITIVO""" para Beatriz a la hora de serle retirado el bebé. *****TEMORES: que se pueda fugar del centro, dada la situación emocional a la que probablemente va a tener que hacer frente Beatriz. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Gestiones realizadas desde la CTAEx tras la comparecencia: +++CON el SSB: hablo con Esperanza, T. Social, sobre el caso: Merecedes no vuelve hasta el lunes (en cualquier caso Esperanza hablará con ella y también la llamaremos desde la Comisión). Correo-e SSB: ssbasetrujillo@gmail .com *****SAD: VA A SER DIFÍCIL por la lista de espera que hay. Le pido que hagan un esfurzo, al menos durante estos tres meses que quedan de embarazo (hablaré también con Mercedes a partir del lunes. *****PROGRAMA de FAMILIA: no cree que haya problema en que la Psicóloga hable con ella para tratar de conseguir el objetivo perseguido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-07-27','(Pedro)Gestiones realizadas en el día de hoy respecto a la comparecencia. +++FUTUEx: llamo a Toni para informarle de la situación: *****acompañarán a Beatriz al banco para sacar los 20€/semana (cuando virgiania esté de vacaciones acudirá otra Delegada). ***** se pondrán en contacto con Mercedes (SSB) para ver posibilidad de SAD y coordinar actuaciones con el programa de Familia. ***** hablarán con el padre de Beatriz para hacer un presupuesto y ver qué dinero, en su caso, podríamos autorizar para los gastos de su hija. +++SE gestiona la autorización de los 20€ semanales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2017-07-27','(Pedro)Visita de D. Manuel: +++NUEVO NÚMERO DE TELÉF: 634-288672 (HA CAMBIADO LA TARJETA CON FERNANDO (otro residente). +++Respecto de su hija, solo me sabe decir que trabaja en una Pizzería de la Barriada El Perú en Cáceres. +++Se le pide que nos haga llegar la Sentencia de Divorcio y la de las medidas a cumplir, para saber a qué juzgado dirigirnos a la hora del pago de las mismas. +++++++++++++++++++++++++ +++Hablo con Gisela sobre esto, para que se vuelva a quedar cada uno con su tarjeta, para evitar problemas en caso de uso inadecuado del las mismas. ++++++++++++++++++++++++++Conversación con D. José Luis (687-581061) (hermano de José Manuel): +++En estos momentos no puede venir a visitarle porque está convaleciente y es el único que puede conducir. +++Se le pide que lo llamen 2-3 veces a la semana ("...si él nos está llamando constantemente...") le indico que se trata de que para su hermano parece importante que sean ustedes los que faciliten ese contacto. +++Piso: "...no está habitable para que se pueda quedar en él si viene a Cáceres...Y si viene, va a ver a su exmujer y la va a liar como hizo la última vez..."). Su hermano tampoco plantea la posibilidad de que se quede en su piso. +++D. José Luis pregunta por las medidas que debe cumplir su hermano. +++DIRECCIÓN del PISO en copropiedad (6 hermanos): C/. Ecuador nº 36, 4º Dcha. (Cáceres) +++HIJA DE JOSÉ MANUEL (Nerea Romero Jiménez): D. José Luis no tiene relación alguna con ella, por lo que no nos puede decir nada de su situación laboral, si esto pudiese justificar una nueva solicitud de modificación de medidas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN FRANCISCO'and edp.apellido1='OSORIO'and apellido2='CALDERON'),'2017-07-24','SALIDA Carmen Gómez Guerrero informa: "...Julián se marchó a su pueblo el día 21 de julio para pasar unos días y volvía mañana día 25. Pero esta mañana ha llamado la trabajadora social de Cabeza del Buey para comntar que la situación de su madre es muy delicada, y que a lo largo de la semana van a hacer los trámtes necesarios para intentar que la ingresen en una residencia, y por tanto, si es posible que Julián se quedara unos días más. Tras hablar con Julián, hemos acordado que se quedará en Cabeza del Buey hasta finales de semana, pero que se pondrá en contacto con el centro para ir informando de cómo se encuentra, puesto que se ha valorado que el grado de estrés que le ocasionaría estar a la espera de información en el CRR sin poder colaborar en estas gestiones que tanto le preocupan podría ser más contraproducente que ampliar unos días su permiso. Para cualquier aportación no duden en contactar conmigo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN FRANCISCO'and edp.apellido1='OSORIO'and apellido2='CALDERON'),'2017-07-27','REGRESO El 25/07/2015. Informar que finalmente Julián volvió el día 25 por la noche porque se aceleró el ingreso de su madre en la residencia a esa misma mañana. Julián se encuentra significativamente más aliviado de tener ya a ambos padres en la residencia y satisfecho puesto que él ha luchado mucho a través de los servicios sociales para llegar a la situación actual.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2017-07-27','(Pedro)Conversación con José Mª, Psicólogo del CADEx de Cáceres (22002): +++Ayer fueron a valorar a Tomás a Toledo. +++PRIORIDADES: *****Ponderar más los aspectos físicos de la discapacidad que los psíquicos. *****Priorizar la permanencia en Cáceres para no desvincularlo de su grupo familiar y de su entorno. +++SE le proporciona teléfono de NACE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2017-07-27','Solicitamos al Juzgado nº 4 de Cáceres, nos envíen testimonio de la Sentencia de separación (procedimiento nº 457/2004) y Sentencia de divorcio (procedimiento nº 31/2017), dictadas por el Juzgado de Primera Instancia e Instrucción nº 4, de Cáceres y número de cuenta de la exmujer, para pagarle la pensión de alimentos de sus dos hijos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2017-07-27','(Pedro)Conversación con Soraya (24104), Directora del CSS de Plasencia. +++Se ha puesto la situación en conocimiento de la Fiscalía y de la Juez, y dado que José Mª tiene abierto otro procediemineto en la vía penal, se van a habilitar medidas cautelares para mantener el ingreso hasta que dicho procedimiento se resuelva.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORA'and edp.apellido1='LEAL'and apellido2='ROMAN'),'2017-07-27','Llama D. Pedro Cordero en representación de Dª Juana Leo (sobrina del marido de Dª Isidora). Teléfonos: 673-358753 y 678-769486. +++Interesándose por la herencia/piso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2017-07-28','(Pedro)Llamada de Bibi, T. Soc. de Aprosuba 7 (924-319712), Residencia (924-312056): +++Refiere faltas de Minerva sin justificar, rechazo del padre a que vaya de vacaciones a la playa, falta de higiene... +++La última vez que estuvo con la madre le dijo que se había dado un golpe en un ojo (Bibi cree que ese puede ser el motivo de las últimas faltas, que no se supiera lo ocurrido¿?) +++INTERVENCIÓN: citaré a D. Víctor en la Comisión para hablar con él sobre ello. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Corre-e de BIBI: Tras conversación telefónica paso a informarte de las faltas de la tutelada en los meses de Mayo, Junio y Julio de 2017. Mayo: 9,15 y 16. Junio: 16,19,23,26,27,28 y 29. Julio: 10,11,17,21,24,25,26,27 y 28. En el día de hoy aparece en el centro Minerva acompañada con su madre, observamos mala higiene de la tutelada y un ojo amoratado. Le pedimos explicaciones a la progenitora y nos comenta que son ojeras. Observamos en los últimos meses dejadez en su aspecto personal, informar que yo personalmente gestione el tema de compra de ropa de temporada (Mayo) y no se la hemos visto puesta. Nosotros desde el centro no podemos controlar los aspectos de su vida en el hogar así como asegurarnos de su bienestar emocional y físico. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con FUTUEx. +++Se les informa de todo ello y harán la próxima visita sin avisar, tratando de reforzar la obligación del padre de llevar a su hija al C.O. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++CITO a D. Víctor en el despacho: hoy no puede venir por estar trabajando. CITADO para el LUNES 31 DE JULIO a las 09:00h','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2016-11-11','REINTEGRACIÓN CAPACIDAD Se recibe Testimonio de la Sentencia nº. 245/16, de 24 de mayo, mediante la cual, Ventura, pretendía recuperar parcialmente la capacidad. Pasando de tutela a curatela.****La Sentencia es DESESTIMATORIA en este sentido, pero ESTIMATORIA en lo referente al sufragio activo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2017-07-28','(Pedro). Llamada de Patricia y Manoli, T. Soc. del Psiquiátrico Penitenciario (954-856048): +++Creen conveniente que llamemos a Juan Carlos de vez en cuando porque se siente muy solo y desanimado. +++Solicitarán permiso para ponerenos con él cuando llamemos, ya que la CTAEx no puede garantizar un horario determinado +++AFICIONES: fútbol (juega de portero los sábados) y el huerto. +++INTERVENCIÓN: *****llamar cada 10-15 día para hablar un rato con él. *****enviarle extra de 200€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2017-07-28','Hablo con los Juzgados, de Jerez de los Caballeros, donde le tomaron declaración el 24/7 y con el Juzgado de Badajoz nº 2, que fue quien impuso el alejamiento y trabajos en beneficio para la comunidad (Ejecutoria 459/16, 924284229). Lo que ha quebrantado es esto último, trabajos en beneficio de la comunidad. Aún no saben que efectos tendrá sobre José Florencio. Cuando lo sepan, nos lo comunican (envío fax a ambos Juzgados para comunicar domicilio a efecto de notificaciones a nosotros).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='FERNANDEZ'and apellido2='SANCHEZ'),'2017-04-03','REMOCIÓN La CTAEx ha sido removida del cargo mediante Sentencia 105/17, de 3 de abril, en la cual se nombra su curadora a su hermana Dña. Eladia Fernández Sánchez.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2017-07-28','(Pedro)Se recibe en la Comisión, por correo electrónico, los informes solicitados al Centro "El Péndere". ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Se llama a Daniel Merchán, T. Soc. SSB de Usagre (924-585011). +++De vacaciones hasta el martes 1 de agosto. Volver a llamar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BERNARDINO'and edp.apellido1='GALAN'and apellido2='PINILLA'),'2017-07-25','(Pedro). Visita (sin cita previa) de D. JOSÉ PINILLA GÓMEZ, hermano de D. Bernardino (por parte de madre). RESIDENCIA: C/. Paseo de Alabarderos nº 8, 1ºB (28024)Madrid. TELÉFONOS: 91-5090271 Y 660-541115 (Dª Florentina, su esposa). +++"Antes iba a ver a mi hermano, pero por motivos de salud ya no voy y lo llamo por teléfono." +++TEMA PRINCIPAL: VIVIENDA sita en la calle Reyes Huertas 30 (La Garrovilla). Propiedad de sus padres, ya fallecidos, D.-------------------------- y Dª Amparo Pinilla Rodríguez (fallecida el 18-9-2002 en Navalmoral de la Mata y enterrada en la Garrovilla). +++NO HAY ESCRITURAS y los único datos se encuentran en el CATASTRO a nombre de su padrastro. *****TAMPOCO HAY DECLARACIÓN DE HEREDEROS, NI ACEPTACIÓN DE HERENCIA. +++FAMILIA: *****Dª Brígida Galán Pinilla, hermana de D. Bernardino y su marido, D. Ramón Cifuentes García, residentes en C/ Miguel Hernández 30, 2º Izda (Mejorada del Campo). +++En la última visita realizada a la casa, ayer, vió que D. Ramón estaba haciendo obras en el tejado, "...y según me dijo una vecina, era para que se fuera a vivir allí un sobrino...Porque mi hermanastra dice que yo no tengo nada en aquella casa y que es solo suya..." +++CONSIDERA QUE tanto sus hermanos como él, tienenderecho sobre esa casa, cada uno en la proporción correspondiente al parentesco con los padres.Y desea inoformar de todo ello para que se tomen las medidas necesarias.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='ROLLAN'and apellido2='SUAREZ'),'2017-07-28','Se llama a Cristopher para informarle que el día 1 de agosto se incia el SAD por Dependencia. +++Él dice que no quiere el servicio, que ahora está en el campo trabajando con su tío y que no lo precisa... +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Hablo con Dependencia: se mantendrá la prestación como estaba prevista, con inicio el 1 de agosto aunque no se incie ese día (caso de ser así, pasar una Nota a Antolín (Jefe Sección) indoicando desde que día se está prestando el servicio. +++Minetrasctanto, intentar convencer a Cristopher de la conveniencia de aceptar el servicio. +++De ser así, poners een contacto conla empresa para el inicio del mismo. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Cristopher: NEGATIVA ROTUNDA A ACEPTAR EL SAD. Dar de baja el servicio. +++"Incendio": "...Lo provocó mi madre al golpear la vitrocerámica...y lo apagué con mis amigos...Estamos arreglando el piso: suelo, pintura, cambio de vitro..." Hablar con Futuex para visita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-07-31','Llama Mª Paz, psicóloga de Salud Mental - tlf. 22656, para informarse de cómo coordinar las medidas cautelares impuestas a Beatriz, envia correo electrónico. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Conversación con Merecedes, T. Soc. del SSB. Plantear el SAD, Programa de Familia (atención Psicológica) y m.a.c.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2017-07-31','(Pedro) Conversación con José Mª Tovar: +++Se le remite modelo de informe de salud para su cumplimentación por Médico de Familia y remisión a la CTAEx para solcitar revisión de Grado y PIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2017-07-31','(Pedro)Reunión con D. Víctor, padre de Minerva. +++Las faltas de asistencia dice que se debieron a encontrarse enferma la niña y el parte de urgencias que llevó le dijeron que no servía, que debía ser el del Médico de Familia. +++Respecto a la falta de higiene, dice que su hija se ducha todos los días y que sí se pone la ropa que se le compró en mayo (me enseña una foto ¿?). +++Respecto del aumento de peso de Minerva, al parecer en su casa desayuna un vaso de leche con galletas (5-6) y para cenar tampoco come mucho. Dice que le deberían poner a dieta en el centro. +++Tiene los pies hinchados (se ve en la foto): mañana la va a ver el Médico de Familia (Dra. Isabel Escaso, del C. salud San Luis). Nos hará llegar el Informe. Pedirlo también a la Médico. +++VACACIONES: el día 14 a las 8 de la mañana la llevará al centro para que se vaya con ellos: "...Mi hija dice que no quiere ir porque siempre van al mismo sitio..." Le hago ver lo afortunada que es de poder ir al menos siempre a un sitio -"...mira yo, que no puedo ir nunca de vaciones..." -dice el padre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='ROLLAN'and apellido2='SUAREZ'),'2017-07-31','(Pedro) Tras las dos conversaciones mantenidas el pasado viernes con Cristofer y dada su rotunda negativa a faciliatr la prestación de dicho servicio en modo alguno, acompañada de amenazas si le obligábamos a aceptar un servicio que dice no requerir, se procede en el dia de hoy a comunicar la Renuncia a la Unidad de Gestión de Recursos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='MARAVER'and apellido2='NORIEGA'),'2017-08-01','DESDE EL CENTRO NOS COMUNICAN QUE DOLORES NECESITA UN AUDÍFONO, NOS ENVÍAN 3 PRESUPUESTOS INDICANDO QUE LA OPCIÓN QUE MEJOR SE ADAPTA A ELLA ES LA PRIMERA, LLAMAMOS AL CENTRO PARA DAR EL VISTO BUENO. NO SE ENCUENTRA EL DIRECTOR , HABLO CON UNA CUIDADORA Y LE DIGO ACEPTAMOS EL PRESUPUESTO, UNA VEZ QUE LE PONGAN EL AUDÍFONO NOS ENVIAN LA FACTURA Y HAREMOS LA TRANSFERNCIA. (MJGH)','2');
