insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='GONZALEZ'and apellido2='ROJAS'),'2017-08-01','ICIAR: Llama Nuria Cordero, Trabajadora Social de Calzadilla de los Barros, se interesa por la situación de CArmen en la residencia de Vva. de la Serena pues la hermana de Carmen le ha pedido que vea si es posible trasladar a su hermana a Fuente de Cantos para que ella pueda visitarla, pues Fuente de Cantos está a pocos Kms de Calzadilla donde reside María.','2');
