insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2017-08-02','(Pedro)Conversación con Daniel Merchán Ugalde (924-506612), T. Soc. SSB de Bienvenida: +++Se responde a su pregunta de si se ha solicitado traslado de residencia por acercamineto familiar y se justifica la no conveninecia del mismo en estos momentos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='PECO'and apellido2='CARRANZA'),'2017-08-02','(Pedro) Conversación con Longina, T. Soc. de Madrigalejo: +++A raíz del Informe de la Policía Local se solicta a Alcaldía Informe del Arquitécto Técnico sobre el estado de la vivienda para que se valore si merece la pena hacer alguna reparación en ella (Longina cree que no) o bien debe ser derruida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2017-08-02','(Iciar/Pedro).Conversación con Beatriz, T. Soc. del C. Penitenciario de Badajoz: +++La visita la dejaremos para septiembre. +++Si quiere hablar con nosotros, nos enviará fax un día antes indicando la hora.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2017-08-02','(Pedro). Recxibimos en CTAEx la Resolución de autorizando el ingreso de D. Hermenegildo en la UDAC. +++Comunico al CAMP (Miriam) dicha resolción y el plazo para hacerla efectiva. +++Circunstancia: en estos momentos Hermenegildo tiene un comportamiento adecuado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2017-08-02','(Pedro). Converscaión con el Dr.Pizarro. +++Consulta para ver si sabemos algo en relación al alta de José Mª y el traslado para cumplir con la medida cautelar de separación de 200 m de su compañero. +++En cuanto sepamos algo se lo comunicaremos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2017-08-03','ICIAR: Envío a Beatriz por fax 924 289117, autorización para retirada semanal de 60€ de la cuenta peculio, y confirmar que las compras del exterior las realizará a través de FEAPS (Paula).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='FERNANDEZ'and apellido2='SERRANO'),'2017-08-03','(Pedro) Conversación con Pilar Carrero Gutiérrez (cuñada de Josefa), llama desde el despacho de Longina (T. Soc.): +++Dice que envío la documentación para su firma en relación a la baja de Josefa en SOMIMA. (revisar expediente). +++Dice haber enviado dos presupuestos para un plato de ducha, sin haber obtenido reaspuesta (comprobar). +++Pregunta si su cuñada puede tener derecho a la pensión de jubilación...sin haber cotizado, adado que va a cumplir los 65 años.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='VALADES'and apellido2='DIAZ'),'2017-08-03','Solicita nuevamente extra para ropa y calzado Se registra acuerdo en la Orden de Pago: +++Traerá comprobantes de compra: "Dadme una segunda oportunidad de demostrar que estoy utilizando el dinero correctamente…Es para aprovechar las rebajas…". Traerá los comprobantes antes de fin de agosto. Acepto este compromiso y firmo el mismo: Isabel Valadés Díaz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2017-08-02','(Pedro) Acude Jonathan a la CTAEx para pedir extra (50 € para ropa y calzado). +++Comenta que el lunes lo detuvieron por quebrantamineto de la Órden de Añlejamiento (O.A.) de su ex-pareja y que estuvo en los calabozos desde el lunes 31 de juio a las 10:40h hasta el martes a las 11:30h. En el Juzgado nº 4 de Méwrida. Traerá la documentación mañana. +++Él dice que es su "ex" la que le busca a él y que ahora la O. A. es mutua: "La Policía me ha dicho que si se me acerca ella los llame inmediatamnete."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2017-08-03','(Pedro) Jonathan no ha venido a traer la documentación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-08-03','(Pedro)Converssación con Mercedes. T. Soc. del SSB: +++Antes de comenzar el trabajo con el SAD, dado que las condicones de la vivienda no reunen las condiciones exigidas por el Servicio, se va a trabajar desde el Programa de Familia en la adecuación de dichas condiciones para luego dar comienzo a la labor del SAD. +++Paralelamente, se va a inicaqr la intervención de la Psicóloga del P. de Familia en el sentido de hacer ver a Dª Beatriz las exigencias que supone tener un bebé, con la finalidad de que ella tome mayor conciencia de la situación en la que se encuentra y sepa, hasta donde le sea posible, valorar dichas dificultades tras tomar al menos algo de conciencia sobre ellas. +++Se coordinará la atención desde el Programa de Familia con la intervención de la Psicóloga (Rocío) del ESM de Trujillo. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ +++CONSULTAS PROGRAMADAS: ***** 7 DE AGOSTO......ESM de Trujillo. Cons. de Psicología (Rocío Ríos: 54510) *****11 DE AGOSTO......en NEUROLOGÍA y GINECOLOGÍA (Alicia, de FUTUEx) *****25 DE AGOSTO......VACUNA TOSFERINA (Virginia, de FUTUEx) *****6 DE SEPTIEMBRE...CADEx (Virginia). *****7 DE SEPTIEMBRE...MATRONA (Pilar ya ha vuelto de vacaciones). ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Converscaión con DR Francisco Guerra, Médico de Familia del Consultorio de Huerta de Ánimas (927-322363): +++Solicitará consulta a Beatriz en el ESM de TRujillo. +++Se le envía por fax (927-323332) el Auto del Juzgado nº 2 de Trujillo con las medidas a adoptar. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2017-08-04','Se envía a Julia Durán la docuemtación remitida a Dependencia en el día de hoy. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Sagrario (ver correo-e del día 3 de agosto. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamada a Tomás: +++Se le informa de que en la primera semana de septiembre se le podrá traer a Cáceres (COCEMFE). La información dada al Hospital de Toledo es que el día 1 de septiembre se podrá hacer el traslado. Parece quedarse conformne, aunque tiene muchas ganas de estar con su fammilia y amigos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='CARRERA'and apellido2='PEREZ'),'2017-08-04','(PEDRO) SE envía Informe Médico y DNI de D. Roberto para Solicitud de Centros (Dependencia). Queda pendiente el envío del Informe Social del SSB de Vva. Serena, solcitado el 21 de julio y que no nos ha llegado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2017-08-04','ICIAR: Llamo a MAría Barrasa del Sociosanitario, t/c 24005, para que nos remita por fax el informe de alta de Ramón. Dice que el informe lo tiene la Dra.Isabel en el ordenador y que actualmente está de vacaciones, se incorpora el 16 de agosgto. Le deja nota para que nos lo envíe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='MARTINEZ'and apellido2='VAZQUEZ'),'2017-08-04','ICIAR. Llama de nuevo Belén para saber cómo va el tema del usufructo dela caa que Pedro, la pareja, le dejó en el testamento. Nos deja el tlf de Isabel PEcos, hermana de Pedro 662440957,para que nos pongamos en contacto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-08-04','(Pedro)Conversación con Rocío Ríos, Psicóloga del ESM de Trujillo (54510): +++La pongo al tanto de las circunstancias de Beatriz y de las gestiones para que sea atendidad desde el programa de Familia del Ayto de Trujillo (ya Mª Paz, de la Subdirección de Salud Mental, con la que ya la Comisión se había puesto en contacto) había hablado con ella del caso). +++Tratará de citarla la próxima semana, porque se va de vacaciones. +++++Me devuelve la llamada: ha hablado con Mercedes, T. Soc. del SSB y han quedado en que desde el preograma de Familia le acompañarán a la consulta con Rocío el PRÓXIMO LUNES, 7 de agosto y mantendrán la coordinación entre ambos servicios. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Convesración con Consuelo, Matrona (54401) del C. Salud de Trujillo. La Matrona de Beatriz, PIlar (54415), está de vacaciones: +++Quedamos en hablar a las 12:00h. La llamaré el lunes. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Durante esta mañana, he realizado sucesivos intentos de contactar con el S. de Ginecología-Tocología del H. san Pedro de Alcántara en los teléfonos proporcionados por Luli, T. Soc. del Hospital (927-256348) así como con el Servicio de T. Social, sin que ello haya sido posible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-08-07','(Pedro)Conversación con Consuelo (54401), Matrona de Beatriz mientras Pilar (54415) está de vacaciones. +++Se le inofrma de todoas los Servicios que están interviniendo en la atención de beatriz. +++También considera que la ligadura de trompas sería la mejor opción anticonceptiva para Beatriz, más si cabe si el parto fuese epor cesárea. +++Mañana inicia la Preparación al Parto: llamo a Toni (FUTUEx) y la acompañarán a la sesión. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Convesración con el Dr. José Antonio Lajas, Jefe del Servicio de Ginecología y Tocología del Hospital san pedro de Alcántara (927-256318///56575): +++OTROS TELÉFONOS: 927-256260, 927-256259, 927-256262. +++Se le envía el Auto del Juzgado en el que se indica que se suministre un método anticonceptivo permanente.Correo-e: joseantonio. alajas@salud-juntaex.es +++PEDIMOS ACLARACIÓN AL JUZGADO, también a petción del DR. Lajas, sobre el término "permanente": si quiere ser sin´nimo de irreversible o solo permanenete. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Teresa Sevillano, Psicóloga del Programa de Familia del Ayto. de Trujillo (927-323315): +++Solicita por escrito le comuniquemos el tipo de intervención a solcitar desde la CTAEx con Beatriz. Al parecer, puede existir algún problema en cuanto a las funciones que tiene asignadas el programa y que no coincidan,parcial o totalemte con lop solcitado por la Comisión. +++Me proporciona el teléfono de Lucas González, Coordinador del programa de familia (D.G.de Infancia y Familia en Mérida): 924-008835. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Lucas Glez: +++Se le explica la propuesta de intervención de la Comisión, a petición también del Juzgado de Trujillo. +++Considera que el Programa de Familia, al menos en parte, no tiene asignadas las funciones d para hacer ningúbn tipo de terapia (concienciar en lo que supone tener y cuidar a un hijo) ya que cosidera que ello requeriría la intervenciciión desde el Equipo de Salud Mental. +++En relación a la actuación en cuanto a la adecuación de la vivienda (habilidades organizativas, rutinas, etc) sí parece ser algo más dentro de las competencias del programa. +++Envío escrito con la propuesta de la CTAEx, coincidente con la del Juzfgado, y se le adjunta también el Auto del mismo. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a Nuria, de Dependencia (689-575719). Volver a llamar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2017-08-07','(Pedro) Llamada de Tomás (656747803). +++"...Quiero irme','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOFIA FLORENTINA'and edp.apellido1='COLLADO'and apellido2='ESTEBAN'),'2017-08-07','(Pedro)Conversación con D. José Tello. +++Se postpone para después del verano el tema de la finca, de acuerdo y a propuesta de D. José, mientras se valora alguna alternativa diferente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2017-08-07','(Pedro). Acude a la CTAEx con cita programada con Gisela. +++Ha estado algo "enfermo" por un problema de tensión: le dijo el médico que si no se corregía a lo mejor le tenían que poner un marcapasos. Ahora está bien. +++Interesarse por el piso que tiene con sus hermanos: todavía no ha llegado la resolución del Juzgado. +++Quiere un móvil nuevo y aumentar su dinero 10€/semana: sabe que ambas peticiones debe realizarlas a través del CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='CANELADA'and apellido2='GARCIA'),'2017-07-27','(Pedro)Conversación con Futuex y con Valentina, T. Soc. del centro de Salud de Aldea Moret (52515). +++En caso de resistencia para el traslado, llamar al 112. +++Se envía a Valentina autorización judicila de ingreso por si se debiera activar el 112. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Amparo (36620) Directorea de "El Cuartillo". +++Misma solución en caso de resistencia. +++Se le envía por correo-e la documentación de ingreso. +++CORREO-E: desamparados.garcía@salud-juntaex.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2017-08-08','(Pedro)Visita de María Dolores. +++Solicita resonancia magnética por los dolores que desde hace dos meses viene sufriendo. El médico de familia (Dr. Francisco Javier Blanco Aparicio, del C. salud Urbano Mérida III) no le envía al especilista.Ha estado también varias veces en Urgencias pero se da solo tratamiento sintomático. +++++++++++++++++++++++Converación con Beatriz, psicóloga del CRR de Mérida: +++EStán preocupadas por el estado de salud de Mª Dolores y plantean la posibilidad de consulta privada: +++El médico de Familia no consideranecesraia la derivación a endocrino o algún otro especuilaista; en urgencias el tratamineto es sintomatológico, y a pesar de las cuatro veces que ha acudido, tampoco plantean consulta con especilista. +++No hay problema en acudir a consulta privada, pero cualquier prueba que se deba hacer ha de contar con el consentimiento inofrmado firmado por la Comisión (así se le indica a Beatriz). +++Solicitarán cambio de Médico de Familia para ver la posibilidadde ser atendida por otro Médico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='VITA'and apellido2='GIL'),'2017-08-08','En relación con la citación a David para que acuda al Juzgado de 1ª. Instancia e Instrucción nº 1, de Villareal (Castellón), a declarar como denunciado, hoy hablo con el Juzgado y me dicen que su Señoría aún no ha resuelto, con motivo de declarar a través de videoconferencia en el Juzgado de Llerena, me anticipan que en principio no habría problema, con lo que David no tendría que desplazarse a Villareal. Les he dado el fax para que nos envíen la Resolución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2017-08-08','Enviamos hoy, al Juzgado Decano de Don Benito, solicitud de autorización judicial, para su ingreso involuntario en la Udac de Plasencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2017-08-08','(Pedro) Conversación con Eugenia, T. Soc. del SSB de Jerez de los Caballeros: +++El Ayto. está tratando de que se lleve a cabo la limpieza de la casa a través de una empresa de limpieza, pero no todos los hermanos quieren colabaorar económicamente en ello. +++También los hermanos han iniciado el procedimiento de incapacitación de Dª María, madre de Ramón. +++Desde que ha vuelto Ramón, su madre ha dejado de ir a comer a la Residencia, se lo lleva o lo envía a "robar" productos del campo, según refeieren sus hermanos. Además, parece ser que ahora es Ramón el que "controla" el trataminento de su madre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-08-08','(Pedro). Conversación con Nuria, Técnico de Dependencia (689-575719): +++Enviará la documentaciópn para su firma y remsión a dependencia para solcitar centro por emergencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO'and edp.apellido1='RODRIGUEZ'and apellido2='PARRILLA'),'2017-08-08','- SE ENVIA EL CAMBIO DE PIA POR DOMICILIO A DEPENDENCIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIANA PAULA'and edp.apellido1='CENTENO'and apellido2='RODRIGUEZ'),'2017-08-08','ICIAR: Después de la vista al domicilio de Juliana en Gómez Becerra 13; 4ºD; Cáceres, quedamos resuelto el tema de la avería con la vecina de abajo.La avería provenía de la fuga de uno de los grifos del baño, según nos dice el fontanero enviado por la aseguradora Mafre, contratada por la dueña Felicidad, con cortar el agua es suficiente. Así se procede. Debido a la cantidad y calidad de las pertenencias de Juliana se acuerda seguir pagando el alquiler de la casa pues realizar la mudanza y alquilar un guardamuebles sería más costoso que el propio alquier. A pesar de que Felicidad ya había cambiado la titularidad de la electricidad, la comunidad y el agua,y que se le había dicho que Juliana le dejaba de pagar el alquiler de la vivienda accede a seguir con el contrato verbal de alquiler. Se cambia el agua y la comunidad a nombre de JUliana, la electricidad, sin embargo, quedará a nombre de Felicidad, nos pasará por email las facturas','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='FERNANDEZ'and apellido2='PINILLA'),'2017-08-10','NOS INFORMAN DEL CENTRO SOCIOSANITARIO DE MERIDA QUE SE HA TRASLADADO A MIGUEL AL HOSPITAL DE MERIDA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='GONZALEZ'and apellido2='ROJAS'),'2017-08-09','- AMALIA: PETRI DTA. DE LA R. MAYORES ME CONFIRMA SU PERFECTA ADAPTACION AL CENTRO . LA HNA LA HA VISITADO EN ALGUNAS OCASIONS. NO SE VA A PEDIR TRASLADO A CALZADILLA O ALREDEDORES.','2');
