insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2017-08-10','-AMALIA: Nos comunican del CSS de Merida ( la psiquiatra ) que va a pasar de UME a URH.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SONIA'and edp.apellido1='VALCARCEL'and apellido2='VIDAL'),'2017-11-10','-AMALIA: Solicito información de servicios recibidos a Vitalia para valorar si continuar o reducir los mismos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2017-08-11','Llamo a Feclem (987218851), para preguntar por la asunción de la tutela por ellos, me dicen que se han excusado el 31/7 y han remitido el expediente a la Fundación Pública de Tutela de Castilla y León, que está obligada a asumir el cargo. Esta ha recibido la documentación el 2/8. Llamo a la Fundación (983412286/71), hablo con Paqui, me dice que la compañera que lleva el tema no está, pero que efectivamente, tienen que asumir el cargo. El 28/8 me llama.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOFIA FLORENTINA'and edp.apellido1='COLLADO'and apellido2='ESTEBAN'),'2017-08-11','En relación con la finca localizada en polígono 20, parcela 218, de Caleranos, Guadalupe, hablo con el Concejal de Caminos del Ayuntamiento de Guadalupe (Jacinto Porras, 600097554). Ha ido a ver la finca y la ha localizado. Me dice que no es muy grande, que hay sembrados olivos, que no están en buenas condiciones, que tiene mamones. Para hacer una limpieza de estos, conoce a empresas, habría que meter en la finca algún camión para recoger los mamones y todo lo que sobre, con dos o tres personas. He quedado en volver a llamarle el 14/8 para que nos de los teléfonos de las empresas que podrían hacer ese trabajo, a los efectos de pedirles un presupuesto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2017-08-11','-AMALIA: Hablo con Vanesa para conocer cúal es su situación actual y si mantiene su deseo de plaza en centro . Me confirma que sí , que sigue interesada porque quiere buscar algo dónde poder trabajar. Se maneja bien con la PNC y llega a fin de mes desde que su hno no reside con ella en la casa de Trujillo. - Mayte está haciendo gestiones para una plaza de V. T. en la provincia de Caceres .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2017-08-11','-AMALIA: Se recive Cdo. y tarjeta de discapacidad . 83% de caracter definitivo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JESUS'and edp.apellido1='DE LA OSA'and apellido2='DE LA OSA'),'2017-08-11','Recibimos correo de Pablo Sánchez, Director del CRR. La hermana de Francisco, Paula, quiere que le enviemos documentación relaciondada con la incapacidad, tutela, certificado de convivencia actual, donde conste su psicopatología, nivel de autonomía y funcionamiento. Toda esta documentación se la ha requerido a su vez un abogado, que está llevando el tema de la separación de otro hermano, para fijar un punto de encuentro y ver a una hija. El CRR ya le envió algo de documentación. ---------------------------- Le he dicho a Paula que su abogado presente el expediente ante el Juzgado correspondiente y que si le requieren para que aporte documentación relacionada con Francisco, nos haga llegar ese requerimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIO'and edp.apellido1='RANGEL'and apellido2='MONROY'),'2017-08-11','- AMALIA: Percibe PNC de 368.90. Se le pidió desde el Ctro Aprosuba 9 P. Orfandad. Ha venido aprobada por 194,80.Se opta por la P. Orf. y dejamos la PNC . Se tramitará PFHC desde el centro .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORO'and edp.apellido1='MORGADO'and apellido2='SANCHEZ'),'2017-08-14','El pasado viernes a ultima hora recibimos llamada de Victoria, trabajadora social del SSB de Alburquerque, para comunicar que Isidoro Morgado se había marchado de la residencia de Alburquerque, donde se encontraba desde hace una semana, a su domicilio. En su expediente no había ninguna comunicacion de traslado al respecto. Comenta que a lo largo de la tarde intentarían convencerlo para que regresara al centro ya que en su domicilio no hay luz ni agua yla puerta no tiene cerradura. Llamo hoy a primera hora de la mañana a Victoria para ver si hay alguna novedad y me comenta que el viernes por la noche consiguieron con la policía local y la concejal llevarlo de nuevo al centro. El fin de semana ha estado tranquilo aunque manifiesta que se encontraba mejor en la residencia de Azuaga. Le digo a Victoria que hable con la hermana de Isidoro puesto que ella tambien es dueña de la vivienda para poner una cerradura en la puerta y evitar que Isidoro pueda irse allí. Nos mantendrá informadas de cualquier novedad al respecto. Mª Jose','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN'and edp.apellido1='GUTIERREZ'and apellido2='RONCERO'),'2017-08-14','ICIAR.Llama Paula Morales la T.O. del CRR de Plasencia. Indica que Julián tuvo un percance con una máquina del café que se encuentra en un aparcamiento de Plasencia, van allí los usuarios porque debe ser más barato, el pasado viernes, se quemó los dedos,se puso en contacto con la empresa para comentar lo que le había ocurrido y si le podían indemnizar pues había tenido que recibir curas en los dedos debido a las ampollas que le había producido el café. Como según Paula ha debido de ponerse en contacto muchísimas veces, cree que a través de wasap. El responsable de la empresa le ha amenazado con mandarle a dos personas para darle una paliza si no deja de contactar con ellos. Paula mandará toda esta información al mail de la Comisión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AURORA'and edp.apellido1='PAREJO'and apellido2='MORENO'),'2017-08-14','ICIAR: Llama el hermano de Aurora, Antonio, para decir que han recibido una carta de la compañía telefónica con el adeudo de unos 600€ del la línea que se dio de alta a nombre de Aurora. Nos va a enviar por fax la factura. Ángel: Hablo con ISGF, Informes Comerciales, S.L. (910714529), que gesiona el cobro de la deuda de 675,74 euros. Me dice que han recibido del hermano de Aurora, Antonio, un fax con una denuncia que presentó Aurora en comisaría de Policía, denunciando el fraude en la contratación de esta línea telefónica por la que le reclaman los 675,74 euros. ISGF, ha paralizado la reclamación del cobro, trasladando a Vodafone la denuncia, por si pudiera tratarse de un posible fraude. Hablo con Vodafone (607123000), contestador automático, me dice que con el dni de Aurora no hay ningún producto contratado. Llamo a la Fiscalía de Villanueva de la Serena (924846039), el expediente lo lleva un tal Agustín. No está, se encuentra de vacaciones. Volveré a llamarlo el 5/9. Llamo a Aurora para que me envíe la denuncia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2017-08-14','ICIAR: Envio por correo electrónico al programa familia la solicitud sellada y firmada por consolación de la solicitud de prórroga dl alquiler de la vivienda de promoción pública, así como el ceretificado de pensiones como nos solicitaron.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2017-08-14','ICIAR: Llama Pilar, T.S. del Sociosanitario de PlasenciA. Comenta que Juan quiere salir el fin de semana del 26-27 de agosto para ir a Zorita a visitar a unos familiares. Lo comunica a la Comisión para ver si le facilitan el pase. Dice que alguna ocasión anterior ya había ido a ese pueblo en busca de familiares que no encontró.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO'and edp.apellido1='SANCHEZ'and apellido2='MIGUEL'),'2017-08-16','ARCHIVO Se nombra, mediante Sentencia nº. 281/17, de 25/05, a D. MIGUEL DEL SAZ SÁNCHEZ, tutor de D. Santiago. Mediante Diligencia de Ordenación, de 27/07/2017, se informa de la firmeza de la Sentencia de Incapacitación y Nombramiento. Se procede al archivo del expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORO'and edp.apellido1='MORGADO'and apellido2='SANCHEZ'),'2017-08-03','TRASLADO CENTRO El 03/08/2017. El Ctro. dixit: "Os informamos que hoy, día 2 de agosto de 2017, D. ISIDORO MORGADO SÁNCHEZ, con DNI 8.828.433-K, tutelado por la Comisión Tutelar, ha causado baja en este Centro, por traslado a la Residencia Municipal Virgen del Carmen, de Alburquerque.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2017-08-02','COMUNICACION CENTRO El 02/08/2017. "En las últimas semanas las conductas disruptivas dentro del CRR han ido en aumento. Llegando al punto de golpear cristales, paredes, amenazas e insultos a profesionales usuarios generando mucha tensión y siendo iposible reconducirlo. Creemos que el no contar con dinero para poder tener un alto consumo de bebidas energéticas, tabaco y realizar compras compulsivas, le está generando mucho nerviosismo y hace que su conducta se vuelva muy agresiva. Esta parte es capaz de reconocerla cuando está tranquilo por lo que hemos acordado con él una derivación al CEDEX por estos problemas de dependencia. Con respecto a las conductas agresivas, se le ha indicado que se aisará a la policia si vuelven a ocurrir y tendrá que pasar la noche o noches (si ocurriera en fin de semana) en un albergue de la ciudad hasta que sea atendido por uno de los técnicos (Director, Psicóloga o Terapeuta Ocupacional) al día siguiente o el lunes si fuera fin de semana.****************El objetivo de esta intervención es poner un límite a las conductas disruptivas y conseguir que el tiempo fuera le ayude a ir modificando su conducta. Además él considera que el estar tutelado le exime de cualquier consecuencia de su conducta y atribuye todo el peso de su conducta a la enfermedad. Por todo esto, consideramos que un buen modo de intervenir en estas conductas sería el anteriormente expuesto.','2');
