insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-08-21','ICIAR: Llaman del Juzgado nº 2 de Trujillo, Loli 927 32 00 85, para preguntar si es urgente la autorización para la ligadura de trompas de Beatriz pues la juez que lleva el caso está de vacaciones hasta el día 1, y si corre prisa lo pasarían a otro.. Lo consulto con Amalia, y le llamo de nuevo para decirle que al no saber si el parto se puede adelantar a octubre, fecha prevista, es mejor que lo hagan lo antes posible. Además nos preguntan si se toma diariamente la medicación y le informamos que una vez por semana va una delegada tutelar a hacerle una visita pero no hay todos los días alguien para saber si se lo toma o no.','2');
