insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2017-08-24','-AMALIA : DESDE CSS PLASNCIA SE COMUNICA QUE JUAN VA A SALIR DE ALTA UN FIN DE SEMANA PARA IR A ZORITA A VER A UNOS FAMILIARES. SE LE INFOMRA A PILAR LA TS QUE ALLI NO HAY FAMILIARES CON LOS QUE TENGA CONTACTO , AUN ASÍ LE DAN EL ALTA TERAPUETICA . NOS AVISAN DEL BANCO DE ZORITA QUE JUAN QUIERE RETIRAR DINERO , SE LE DENIEGA DESDE AQUI. HOY NOS LLAMAN DESDE EL CSS PLASE. JUAN ESTÁ EN EL CENTRO DE SALUD DE GUADALUPE Y NO QUIERE REGRESAR , PARA PEDIR UNA SOLUCIÓN. LES COMUNICO QUE LA SOLUCION TIENEN QUE DARLA ELLOS , EL PSIQUIATRA VA ACTIVAR EL 112 PARA REINGRESARLO.','2');
