insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GONZALEZ'and apellido2='GONZALEZ'),'2017-08-29','- AMALIA . SE LE IMPONE MEDIAD DE SEGURIDA DE LIBERTAD VIGILADA CON SOMENTIMEINO A TRATAMENO MEDICO EXTERNO PARA TRATAR LA ENFERM. MENTAL . + 90€ DE MULTA Ángel: Para cumplir con la condena impuesta en la Sentencia, tenemos que esperar a que el Juzgado dicte la ejecutoria. He comunicado por fax, que la remitan aquí.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2017-08-29','Nos citan el día 4/9/2017, a las 11:30 (festivo en Mérida), a la celebración del Juicio Oral en el Juzgado de lo Penal nº 1, de Badajoz (24/2017). Comunicamos al Juzgado que no podemos asistir y que en nuestro lugar acudirá Virginia Sanz Fernández, de Futuex, a la que le envío las actuaciones llevadas a cabo por nuestra parte con María, desde que somos susu totores. Acudirá también la Abogacía General, al pedir responsabilidad civil. Hablo con José Manuel Rodríguez y María Jesús López Bernal, Letrados de la Junta, les envío documentación (Sentencia de incapacitación, aceptación del cargo). Hablo también con la abogada de María, Niobe Sánchez Casimiro (651589191), me dice que ha hablado con María, para comunicarle la citacion. Hablo con un tal Antonio (924233377-692619936), que es con quien está viviendo ahora María. No quiere decirme el domicilio. Al parecer es un amigo/conocido del padre de María. Se muestra muy colaborador, facilitándome su número de teléfono móvil y ofreciéndose a acompañar a María al Juzgado el día 4). Hablo con María, se muestra tranquila, salió esa mañana a pasear con su perro. Conoce la citación y confirma que va a ir. Le advierto que debe ir, en caso contrario se dictaría orden de busca y captura. Hablo con la madre de Maria (658889091-927246523), para comunicarle el paradero de su hija, que no lo sabía. Está al corriente de la citación judicial para el día 4/9/17. El otro acusado, Jhonatan Xavier Arévalo Tomasino, está en prisión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2017-08-30','-AMALIA : RECIBO LLAMADA DE LA TS DE HNOS DE CRUZ BLANCA ( 927246852) PARA INFORMNARNOS QUE HAN ENVIADO UN ESCRITO A LA SECCION DE DISCAPACIDAD PARA QUE RECONSIDEREN EL CENTRO ASIGNADO PARA ALEJANDRO . ( NOS LO HAN FACILITADO DESDE DISCAPACIAD) ARGUMENTAN QUE POR EDAD ( EL RESTO DE RESIDENTES TIENEN UNA MEDIA DE 48 AÑOS Y ALEJANDRO 18 , POR PROBLEMATICA SANITARIA ... NO LO CONSIDERAN EL CENTRO ADECUADO. EL SEPAD NO CAMBIA SU POSTURA Y EL INGRESO SE HARÁ MAÑANA DESDE CAMINOMORISCO. AMBOS CENTROS ESTÁN EN CONTACTO PARA EL MISMO . PONGO A SU DISPOSICIÓN LA OPCIÓN DE PAGAR UN TAXI CON CUIDADOR QUE PAGARIA EL TUTELADO . LE ENVIO POR EMAIL TODA LA DOCUMENTACIÓN SOCIAL DE ALEJANDRO . QUEDAMOS PTE DE ESTABLECER EL PRESUPUESTO EC. PQ NO SE ENCUETRA LA COORDINADORA. PERCIBE PF+P. ORFANDAD .','2');
