insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2017-09-11','(Pedro) Conversación con Blanca, T. Soc: +++D. Ramón está en Crónicos, en el Pabellón "Siruela". +++No tiene prevista alta en estos momentos. +++Hablará con los médicos para saber en qué situación clínica se encuentra y por qué, según el padre y hermano (D. Juan) no les dejan verlo y solamente se lo permiten a su madre. Nos comunicará la inofrmación solicitada. +++Teléfonos de D. Juan Giles: 634-703501 y 924-953089. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con D. Juan (hermano de D. Ramón): +++Le han dado permiso de fin de semana. En estos momentos se encuentra en el domicilio familiar y esta tarde lo tienen que volver a llevar al CSS. +++Su principal duda es ¿por qué cuando van a verlo solo a su madre le dejan pasar?','2');
