insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2017-09-12','(Pedro). Conversación con Beatriz, T. Soc. del C. Penitenciario de Badajoz: +++El miértcoles 6 de septiembre de llevaron a Jesús al Psiq. Penitenciario de Sevilla. CAUSA: agresión (pelea) a otro interno mientras estaba allí ingresado. VOLVERÁ de nuevo al PENITENCIARIO de Badajoz tras el juicio.La Comisión NO había sido informada de ello. +++Preguntará en lo Servicios Médicos del Centro si tienen informes médicos (propios o de Sevilla) y me lo dirá por correo, indicando, en su caso, cómo solicitarlos. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Manoli, T. Soc. H. Psiquiátrico Penitenciario de Sevilla (954-856048). +++Jesús NO ESTÁ EN EL PSIQUIÁTRICO PENITENCIARIO, SINO EN SEVILLA-I. Tratará de averiguar su situación y Juzgado que lo lleva y nos lo dirá. +++Cuando fue trasladado a Badajoz se enviaron allí los correspondientes Informes Psiquiátricos del Penitenciario de Sevilla. +++Manoli considera que es un caso de Salud Mental (psicodefiencia) por los trastornos graves de conducta que padece. CELOSO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='VITA'and apellido2='GIL'),'2017-09-12','ICIAR: Llamo al Jdo nº 1 de Villarreal, t/c 964 73 82 78, para preguntar sobre la resolución al fax de petición de comparecencia por videoconferencia de David enviado el 13 de junio. Nos contestan que la persona que lleva las diligencias previas 72/2017 está de vacaciones. Nos pide que llamemos al día siguiente para ver si algún compañero de ella nos puede decir algo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN'and edp.apellido1='GUTIERREZ'and apellido2='RONCERO'),'2017-09-12','ICIAR: Nos deniegan el abogado de oficio','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-09-12','(Pedro) Conversación con Raquel Navarro, T. Soc. del ESM de TRujillo (54509): +++Se le ha adelantado la cita a mañana con Rocío, la Psicóloga. +++Plantea como alternativa para no separar a Dª Beatriz de su hija el recurso de ACISJF (Asociación Católica Internacional Juventud Femenina) en Cáceres. Sin embargo, no me puede dar muchos datos sobre dicha Asociación. Estudiar dicha posibilidad. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Convresación con Rocío, Psicóloga del ESM de Trujillo (54510). +++Ya atendió a Betariz antes de las vacaciones, y la vilverá a atender mañana. Hablará con Teresa, la Psicóloga del Programa de Familia, con la cual están coordinando el caso. +++Opina que con un apoyo adecuado y permanente, sobre todo al principio, quizá sería posible no separar a beatriz de su hija. Plantea la posibilidad del recurso anterior, pero tampoco lo conoce demasiado.Hablará con Teresa (Programa de Familia) para tener la consulta de mañana conjunta. +++Desded este Programa se está interviniendo sobre todo en el tema de las tareas domésticas y en lo que significa tener un hijo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-09-13','(Pedro) Conversación con MARA CENDAL, T. Soc. del S. de Infancia y Familia (927-004349. Correo-e: mara.cendal@salud-juntaex.es). +++Mantiene la opción de acogimiento familiar con derecho a visitas de la madre de los cero a tres años. +++No contempla la viabilidad de ACISJF. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Mercedes, T. Soc. del SSB de Trujillo. +++Comenta que se nos ha enviado un Informe del Programa de Familia señalando que, dada la falta de colaboración de Beatriz, ha sido impsoible realizar trabajo alguno con ella.Estamos a la espera de recibir dicho Informe. +++Respecto al SAD, tampoco se ha podido iniciar el servicio dadas las condiciones en las que se encuentra la vivienda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2017-09-13','-SE SOLICITA HABILITACION FUNICIONAL PARA TTO. PSICOLOGICO PEDIDO DESDE APROSBA 8 . SE ENVIARÁ LA SOLICITUD Y EL CENTRO ADJUNTARÁ INFORMES . ( AMALIA )','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SAMUEL'and edp.apellido1='BARRADO'and apellido2='SANCHEZ'),'2017-09-13','-SE LE CONCEDE PNC INVALIDEZ CON UNA CUANTIA DE ATRASOS PARA EL 2016 DE 2346€. PARA EL 2017 LA CUANTIA MENSUAL ES DE 193,72 , SE LE VE REDUCIDA PQ ESTÁ PERCIBIENDO RENTA BASICA (4260 € ANUAL )','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='VITA'and apellido2='GIL'),'2017-09-13','ICIAR: Llamamos de nuevo al Juzgado de Vilareal, hablamos con Iván t/c 964 73 82 78, al no ser él quien está con estas diligencias pues su compañera está de vacaciones, me insta a que le mandemos de nuevo el fax que ya enviamos el 13 de junio donde soliciábamos la videoconferencia y el abogado de oficio. Dice que va a mirar si puede decirme algo a lo largo de la mañana. Le vuelvo a llamar, confirma que le ha llegado el fax , pero no me dice nada más,no sabe si su compañera ha hecho algo. Textualmente dice que si ya lo enviamos en esa fecha su compañera, que se incorpora el 25,(el mismo día de la comparecencia), lo habrá gestionado, que no nos preocupemos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2017-09-13','TRASLADO CENTRO El 13/09/2017. Nuevo ctro.: Asociación Vera; Ctro. anterior: CSS de Plasencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AQUILINO'and edp.apellido1='CAMACHO'and apellido2='ROMERO'),'2017-09-13','ICIAR: hablo con matilde, enfermera de maxilofacial del infanta cristina, me confirma que podemos enviar por fax (924 21 98 41) el consentimiento informado de Juan para la operación. También hablo con Feli, T.S. del Hospital de TAlarrubias. Juan está en urgencias. ha hablado con el médico y no tiene ninguna hemorragia, solo está un poco decaído, le ha mandado hacer analítica. Seguramente le da el alta. Hablo con Carmen, la Directora de la Residencia, ella tiene el consentimiento informado que nos va a enviar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='VITA'and apellido2='GIL'),'2017-09-13','ICIAR: Llamo a Mercedes, T.S. 924 87 10 37, le comento lo que nos han dicho en el juzgado de Villareal, que no nos preocupemos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2017-09-13','ICIAR: Llama Eva de Plena Inclusión Montijo. Les ha llamado la madre de Joaquín para decir que le ha llegado citación de Joaquín del Jdo para el día 11/10. Llamo al Jdo nº2 de Montijo ( 924 45 91 93),lo confirman, y nos envían por fax la citación por delitos leves 82/17. Joaquín va en calidad de denunciante.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2017-09-13','(Pedro) llamada de Guadalupe Espárrago, Psiquiátra del ESM de Cáceres (54605). +++Nos comunica que Saturnino no se ha presentado en la consulta programada para hoy. Dada la desestabiliozación manifiesta de Saturnino va a activar el 112 para ingreso involuntario. Enviará el Informe de dicho ingreso. +++De acuerdo con esta Comisión en que Saturnino debe estar ingresado, tanto por su bien como por el de su familia, especialmente su madre, que ya ha manifestado en anteriores conversaciones con la Comisión su temor a que pueda terminar como uno de sus hermanos (que se suicidó).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIA'and edp.apellido1='MARQUEZ'and apellido2='ANDRADE'),'2017-09-13','CITACIÓN: Juzgado de 1ª Instancia e Instrucción Nº 4 de Cáceres: DÍA 21 DE SEPTIEMBRE DE 2017 A LAS 10:20h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='BUENO'and apellido2='FERNANDEZ'),'2017-09-14','(Pedro)Conversación con Gloria Nogales, de "La Granadilla" (20620 y 924-014300) sobre los incidentes referidos en el informe de 14 de agosto de 2017. +++La situación parece estar más tranquila en estos momentos. +++Se le ha retirado la asignación para evitar el consumo de vino (brick), aunque a pesar de ello en alguna ocasión se sabe que lo ha consumido.Parece haber aceptado esta medida razonablemente bien (¿?). +++Intentaron que pudiera ir a la cafetería del centro para tomarse un café, etc. sin que tuviera que pagar, descontándolo después, pero D. José Antonio no lo aceptó. +++Ante situaciones graves (agrsiones, etc) se le plantea el aviso al 112 y, llegado el caso, la presentación de denuncia formal ante la Policía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SAMUEL'and edp.apellido1='BARRADO'and apellido2='SANCHEZ'),'2017-09-14','-Samuel vive con sus abuelos maternos y su tía en un piso propiedad de estos, tanto la abuela como la tía, suelen estar presentes en las visitas que se les hace desde futuex y ayudan bastante a la hora de hacer comprender a Samuel la normativa que se le exige desde la CTAEX. Samuel es uno más de la familia y está integrado como tal en la casa de la abuela. No quiere que CTAEX le gestione su dinero . Su sentencia especifica curatela economica para más de 300€ . Se le va a subir la asignacion mensual a 450€ .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2017-09-14','El Juzgado de 1ª. Instancia e Instrucción nº 2, de Villanueva de la Serena, ha decretado la apertura de Juicio Oral, como consecuencia de las Diligencias Previas 162/2016, ante la Audiencia Provincial, por un delito de abusos sexuales, contra Ainoa Valadés Gómez. Tiene abogado (Gema Caballero Flores) y Procurador (Pilar Torres Martínez)','2');
