insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='ESTRELLA'and apellido2='CARRASCO'),'2017-09-15','SE SOLICITA INFORME SOCIAL A LOS SERVICIOS SOCIALES DE DAIMIEL CON EL OBJETO DE CONOCER LA SITUACIÓN ACTUAL Y PEDIR POSTERIORMENTE EL TRASLADO DE LA CURATELA A ESA COMUNIDAD. (MJGH)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='GARCIA'and apellido2='RAMIREZ'),'2017-09-15','ICIAR: llamo a la Asociación "Camino de Vida" en Montijo ( Julián Cruz - 657 813 847) donde se encuentra José Antonio, nos indican que no hay necesidad de pasarle un dinero mesusal a la madre Antonia, como ella nos había solicitado por teléfono, pues las necesidades de J.A. están cubiertas con la signación mensual, aunque esta podría ser aumentada. Pasará en octubre de 600 a 800€ (Alberto)mensuales, de ahí una parte 250-300€ se donan a la Asociación por el sustento, el resto para sus necesidfades. Llamo a Antonia ( 672473570), y le comunico que no se le va a dar ningún dinero a ella, y que no vamos a pagar más tickets que nos envie por correo postal, si ella quiere hacer algún regalo a su hijo que se lo haga pero que no nos pase la factura.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='MUÑOZ'and apellido2='CAMACHO GARCIA'),'2017-09-14','ICIAR: Desde el Ayto de Esparragosa nos envian el consentimiento informado para la operación de Juan en el Infanta. Una vez firmado por Consolación lo enviamos al Infanta Cristina, Maxilofacial- enfermera MAtilde fax 924 21 98 41 - ext 48448','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2017-09-15','REUNIÓN con NACE. Presentes: Dª Mª José y D. José Mª Tovar, la Directora-Gerente del SEPAD y el Jefe de Sección de CTAEx. +++Situación jurídica en l,a que queda D. Tomás y responsabilidad de Nace al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2017-09-15','- TRAS REUNION MANTENIDA CON CHEMA TOVAR EN LA DIRECCION GERENCIA PROCEDEMOS A LA BAJA EN NACE . IGUALMENTE SE PROCEDE A DAR DE BAJA A LOS PAGOS EN LA ASOCIACION .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='PESADO'and apellido2='ESTEBAN'),'2017-09-15','- NOS LLEGA DEL JUZGADO LA SOLICITUD D RESERVA DE PLAZA COMO MEDIDAS CAUTELARES. HAGO GESTIÓN CON TECNICOS PIA Y TS DE VALDEOBISPO PARA COMPROBAR EL RECURSO IDONEO . EL TECNICO PIA SE DECANTA TRAS VALORARLO CON EL RESTO DEL EQUIPO POR RAE. HABRIA Q SOLICITAR REVISION PIA ( TIENE GRADO III.2 ) Y PEDIR SOLICITUD DE PLAZA PERO LA CTAEX NO PUEDE FIRMAR ESTE DOCUMENTO . DE HECHO LA SOLICITUD VIENE A LA CONSEJERIA DE SANIDAD Y NO A CTAEX. SE LE DERIVA EL CASO A MANUELA GONZALEZ ( DISCAPACIDAD ) PARA QUE REALICE LAS GESTIONES PERTINENTES .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS MIGUEL'and edp.apellido1='MUÑOZ'and apellido2='SANCHO'),'2017-09-18','Realizo llamada a Luis MIguel para comprobar donde está residiendo actualmente ya que llevamos un tiempo sin saber de el y hay que presentar la rendición anual. A pesar de haber manifestado su intención de irse a vivir a Aliseda en el mes de junio me confirma que siguen viviendo con su hermano en Cáceres. Le comento que no estamos pagando su parte del alquiler y dice que su hermano no quiere nada. Tras preguntarle el motivo por el que no se marchó a Aliseda me dice que tiene intención de irse la semana que viene. Le pido que nos comunique cuando se marche para ver si necesita algo para acondicionar la casa de Aliseda. (MJGH)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL MARIA'and edp.apellido1='SANTOS'and apellido2='GOMEZ'),'2017-09-18','Alcudimos a Notaría de Mérida para la firma de la Compraventa de la finca La Loca, de Santa Marta de los Barros. El importe obtenido por la venta de esta finca, 12.376,88 euros, de los que Rafael obtiene 1.361,46 euros,deducidos los gastos notariales, que se abonaron allí mismo el día de la firma, se comprometen todos los vendedores (Madre, hermanos y Rafael), a ingresarlo en la cuenta de la sociedad Herederos De Hermanos Santos Neila, s.l., con el objeto de reducir deudas de la misma.','2');
