insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUVIGIS'and edp.apellido1='FUENTES'and apellido2='TORNERO'),'2017-09-18','ICIAR: Llama Juan Carlos director de la Residencia Los Pinos de Plasencia(ext 21911) indica que Eduvigis se ha caído y se ha dañado la cadera por lo que le tendrán que operar. Manda consentimiento informado por fax y por correo electrónico para que se lo enviemos de vuelta. pregunta tb por si fuera necesario acompañamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2017-09-18','LLamo al Juzgado Juzgado nº 4 de Cáceres, para preguntar por la solicitud que hicimos en julio, para que nos enviaran testimonio de la Sentencia de separación (procedimiento nº 457/2004) y Sentencia de divorcio (procedimiento nº 31/2017), dictadas por el Juzgado de Primera Instancia e Instrucción nº 4, de Cáceres y número de cuenta de la exmujer, para pagarle la pensión de alimentos de sus dos hijos. Me atiende Consuelo (927620407/8). Me dice que va a mirarlo y me llama.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICENTE'and edp.apellido1='CARRETERO'and apellido2='GARCIA'),'2017-09-18','BAJA Tras solicitar la confirmación de sentencia el 17/10/2016, el 29/03/2017 y el 05/06/2017, y no habiendo recibido noticia alguna del Jzdo. nº. 1, de Plasencia, se da por firme la Sentencia nº. 235/16, de 6 de septiembre, que nombra curador de D. Vicente a D. Serafín Álvaro Carretero García.*****************************************************Se archiva el expte. de Defensa Judicial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JORGE'and edp.apellido1='FERNANDEZ'and apellido2='CERECINOS'),'2017-09-18','-tf. de su hermna Rosario 690601104. Se puede intentar acercar a sus hnos ( Jorge y Matias ) unos dias en vacaciones de navidad o verano para que su hna que viene desde Santander pueda visitarlos. No es posible solicitar plaza por acercamiento familiar de Jorge porque no hay actualmente vacantes. Se volverá a intentar . ( Amalia )','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-09-19','(Pedro)Conversación con Paulina Mata, Educadora Social del Programa de Familia de Trujillo (927-323315). +++El Informe que dice haber enviado el pasado 5 de septiembre no nos ha llegado. Nos lo enviará hoy por correo electrónico. +++Consideran que Beatriz carece de capacidad para atender a un bebé ni habilidad alguna para desde el punto de vista de la maternidad, preccisnado ella cuidados las 24 h del día en un centro adecuado a su discapacidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2017-09-19','Hemos solicitado al Juzgado de Instrucción 7, de Sevilla, nos remitan toda la documentación relacionada con una Diligencia para el día 29 de septiembre. También hemos solicitado el Juzgado de lo Penal, 7, de Sevilla, nos remitan la Ejecutoria 394/2017, por la que condenan a Jesús al pago de 1.342,32 euros, solicitando nos indiquen un número de cuenta donde realizar el pago. La citación del 29/9 la lleva el Juzgado de Instrucción nº 8, de Sevilla. Es por un juicio por delitos leves, nº 64/2017, se realizará una videoconferencia, al estar él en el Centro Penitenciario de Badajoz. He pedido que nos envíen la diligencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORO'and edp.apellido1='MORGADO'and apellido2='SANCHEZ'),'2017-09-19','ICIAR: Isidoro se encuentra en la Residencia Sociosanitaria Virgen del Carmen, c/ Pozo de las Pias, Alburquerque','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JACINTA'and edp.apellido1='CABRERA'and apellido2='MORA'),'2017-09-19','ICIAR: Ha llegado autorización judicial para la venta de los inmuebles.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2017-09-19','Hablo con el Juzgado nº 4 de Cáceres (Consuelo 927620406). Le hemos pedido que nos envíe Sentencia de divorcio y número de cuenta de la exmujer, para pagar la pensión de alimentos de 200 euros por ambos hijos. Me dice que tiene que mirarlo en el archivo del Juzgado. Mientras tanto, me ha dado un número de cuenta del Juzgado para que paguemos en esa cuenta, hasta que sepamos la cuenta de la exmujer. Le pido también que me indique si hay mensualidades pendientes. Entendemos que las hay, ya que la condena de multa más indemnización por pensiones impagadas, es de julio de 2017. Con lo que ese mes, agosto y septiembre estarán sin pagar. Septiembre, si lo pagamos este mes no. Lo mira también.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2017-09-19','ICIAR: Llamo a Toni de Futuex. Me dice que mensualmente se comunican con Jesús Manuel, no sabían nada del tema del agua que, según J.M., su vecina Ana le coge agua de su contador. Van a ponerse en contacto con él para ir mañana a visitarle y tratar el tema de ese grifo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2017-09-19','- LLEGA LA RESOLUCION PIA DE ALEJANDRO PARA INGRESO EN CENRO HNOS CRUZ BLANCA CON FECHA 17/08/2017','2');
