insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUVIGIS'and edp.apellido1='FUENTES'and apellido2='TORNERO'),'2017-09-19','ICIAR: Llama Juan Carlos de la Residencia Los Pinos, nos informa que la operación ha salido muy bien. Eduvigis en cuatro días recibirá el alta. No necesita acompañamiento','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2017-09-19','(Pedro) Conversación con D. José Luis, hermano de D. José Manuel (687-581061). +++Situación de su hermano en el Centro. +++Lo llamaron de un Juzgado de Cáceres (¿?) y les dijo que estaba tutelado. Le dijeron que llamarían al Centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2017-09-20','(Pedro). Conversación con Ana Delfa (924-231645) CRR Badajoz. +++Informa de que ha sido denunciada por Ceferino por "maltrato psicológico" y quería que nosotros estuvieramos al tanto. +++Refiere que, dado el comportamiento de ceferino, ella le ha advertido en diferentes ocasiones de las consecuencias quepodría terminar teniendo y que ya en el pasado ha sufrido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2017-09-20','ICIAR: después de recibir la llamada de Juan José diciendo que ha encontrado un piso-pensión en Badajoz por 280€/quincena algo que él ya había tratado con María, la psicóloga del CRR de Badajoz (t/c 924 23 16 45)llamo a esta. Me dice que en han estado trabajando con él la posibilidad de que pudiera vivir 15 días independiente, siempre y cuando pueda gestionarlo con la asignación que recibe (200€/quincena)para que él pueda comprobar lo difícil que es vivir por su cuenta,antes de poder solicitar un piso tutelado en Cáceres,ella lo llama prueba-realidad,pero no de manera inmediata, y siempre y cuando pudiera hacerlo sin pedir más dinero de asignación. Ella se encarga de ponerse en contacto con él para indicarle que lo que nos dicho del piso-pensión no es viable.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2017-09-20','ICIAR: hablo con Beatriz, t.s. del centro penitenciario 924 28 91 00, me confirma que Jesús ha regresado hace un par de días al centro. Beatriz ya no tiene asignado el módulo de Jesús pero al estar su compañera de vacaciones mañana o pasado le irá a ver y le preguntará si ha traido alguna documentación de Sevilla. Nos lo comunicará. También me dice que Jesús ha recibido dinero del peculio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2017-09-20','(Pedro). Conversación con Mª Ángeles, de Aprosuba 8 de Montijo. 666-321676. +++Considera necesario replantearse la relación de Joaquín con su madre dado que la misma ha vuelto a derivar hacia una dirección no adecuada para él: posible manipulación, e incluso pudiera ser que fuese ella la responsable del incidente de la tienda (rotura de escaparate). +++Planteará fecha para una posible reunión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2017-09-20','(Pedro) Reunión con Julián (Gerente) y Agustina (directora en Cocemfe Cáceres, con Soraya y Pedro. +++SE inofmra de las responsabilidades que el centro asume a partir de ahora com Guardador de Hecho. +++SE discute sobre la mejor forma de que Tomás pueda mantener la relación con su grupo familiar de referencia en la mayor medida posible sain que ello pueda afectar a su reahbilitación y adptación al centro. +++Se enviará la documentación prevista al centro, así como todos los datos referidos a el abono de la plaza y gastos de bolsillo. Además, se enviará, para la Dirección, la Autorización general para la toma de decisiones que en cada momento sea preciso tomar, sin perjuicio de que cuando se comnsidere necesario por la relevanmcia del asunto se pueda solicitar una autorización expresa para dicho asunto. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Se llama a José Mª Tobar y se concierta nueva entrevista en la CTAEx para el lunes 25 de septiembre a las 12:00h.En la misma solicta que esté presente Soraya, como de hecho ya se tenía previsto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-09-21','(Pedro) Conversación con Mercedes (T. Soc. del SSB. 927-659391). +++Conflicto creciente entre D. Andrés y D.Antonio (pareja de Beatriz): Antonio se muestra muy controlador con Beatriz. +++Correo de Mercedes:Esta semana ha estado el padre de Beatriz en el despacho e informa de una situación muy tensa entre él y Antonio, el novio de Beatriz. Me ha pedido que no Beatriz no sepa que él ha informado de esto, pero el rechazo de Andrés hacia Antonio va en aumento y el modo en que habla de él es cada vez más despectivo. Habla de una discusión reciente en la que casi es agredido por Antonio, viéndose Andrés obligado a abandonar su domicilio para evitar un conflicto mayor; lo ha puesto en conocimiento de la Policía Local, quienes le han derivado a la Guardia Civil para su denuncia, no habiendo querido interponerla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='LAVADO'and apellido2='MACEDO'),'2017-09-21','ICIAR:Llama Juan Manuel, hermano de MºÁngeles, quiere saber cómo va el tema del acercamiento de su hermana desde el centro de Don Benito a Badajoz o Alburquerque. También nos comunica que el padre falleció enagosto y que quieren formalizar la herencia a beneficio de inventario. Le indico que vaya a la notaría y cuando lo tengan nos llamen para firmar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2017-09-21','Comunican del CSS de Plasencia la fuga JOsé Mª el 3 de septiembre. +++La Policía informó al CSS a las 20:00 que se encontraba en el H. Ntra. Señora de la Monataña, siendo trasladado de nuevo al CSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2017-09-21','ICIAR: Ante la petición de Mari Loli a Pedro de que desea vender uno de los tres nichos que tiene en propiedad. Llamo a los ayuntamientos de Aceuchal, Don Benito y Cáceres donde ella dice se encuentran. En Aceuchal sí tiene uno a su nombre en propiedad , nos mandarán certificado que les hemos solicitado por mail. En Don Benito no aparece nada a su nombre. En Cáceres tampoco aparece nada a su nombre, en la póliza de Santa Lucía sí aparece que tendría un nicho en cesión por 5 años.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='VITA'and apellido2='GIL'),'2017-09-21','ICÍAR:la citación del lunes 25/09/17 se ha quedado sin efecto. Hemos recibido fax del Jdo de Villarreal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2017-09-21','COMUNICACIO CENTRO PENITENCIARIO DE BADAJOZ "Por el presente le participo que el interno de este Centro JESUS VAZQUEZ DIAZ tiene nueva fecha de excarcelación al haberse recibido nueva causa penada, la ejecutoria 394/17, del J. Penal nº. 7 Sevilla, condenado a 3 meses y 10 días de prisión.************************************************* Su nueva fecha de excarcelación está prevista para el día 25/01/2018."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='FUENTES'and apellido2='ALCANTARA'),'2017-09-21','SALIDA Entre el 21/09/2017 y el 25/09/2017. "El presente -fax- es para comunicarles para su conocimiento y efectos, que el usuario de R.A.E. dependiente de PLENA INCLUSION AZUAGA, AGUSTIN FUENTES ALCANTARA, se marcha a su domicilio familiar desde hoy día 21 de septiembre hasta el lunes 25 de septiembre de 2017."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FRANCO'and apellido2='JIMENEZ'),'2017-09-22','(Pedro)Converscaión con Javier, Director CRR de Plasencia (677-407640): +++VACACIONES de D. Félix: dado que es una tutela muy reciente (11 de septiembre) y la CTAEx no está autorizada en sus cuentas, Javier PROPONE ADELANTARLE EL DINERO Y QUE UNA VEZ QUE TENGAMOS DICHA AUTORIZACIÓN LE REMBOLSEMOS ESA CANTIDAD. +++ Acordamos hacerlo así y Javier nos enviará el documento en el que se haga constar el gasto realizado. +++Javier asegura que D. Félix dispone de dinero para ello y que además, merece poder irse de vacaciones con sus compañeros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2017-09-22','ICIAR. Llama Eva de Plena Inclusión. Necesitan un certificado de vida laboral negativo. Una compañera del centro va a acompañar a Joaquin a la Seguridad Social a solicitarlo ya que no se puede online al ser negativo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2017-09-22','Recibo llamada del abogado que ha llevado las operaciones particionales de la herencia de los padres de Mª Luisa para comunicar que ya están todas las gestiones terminadas y que sus 3 hermanas se han hecho cargo de todos los gastos originados. Mediante esta herencia Mª Luisa ha heredado el usufructo de la vivienda donde reside en Don Benito, siendo la nuda propiedad de sus tres hermanas. (MJGH)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2017-09-22','(PEDRO)Llamada a Soraya, CSS Plasencia. +++INCIDENCIA: José Mª provocó incendio de su cama y sufrió quemaduras en dos dedos.ENVIARÁ INFORME DE LO SUCEDIDO. +++Hoy INGRESA NUEVAMENTE EN LA PRISIÓN de Cáceres a PETICIÓN PROPIA cyumpliendo medida el 10 de ocyubre. +++Tiene causas pendiendientes. +++Se ha comunicado al Juzgado todas estas incidencias. Se propone que planteen como alternativa al Juzgado la posibilidad de ingreso en C. psiquyiátrico penitenciario. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++El Informe recibido queda en el expediente de José Mª.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2017-09-22','(Pedro)Converascaión con Soraya (CSS Plasencia). +++Durante el verano tuvo permiso de salida a Zorita: rechazo de la familia, durmió un anoche en la pensión y se fue a Guadalupe. Al no tener dinero acudió a la Guardia Civil a la ve zque desede le CSS se ponía denuncia para que lo llevaran de nuevo. +++AHORA, consciente de esta realidad, acepta PISO TUTELADO (está el 1º).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2017-09-22','Hablo con Elena de nuevo. Me dice que han decidido que no es viable que la Junta de Castilla y León asuma el cargo. Han enviado contestación al Juzgado de 1ª. Instancia e Instrucción nº 3, de Ávila. Me pasa con Conchi Valario, Jefe de Área, que me indica el motivo de no asumir el cargo. Según ella, nosotros decidimos trasladar a Margarita a Ávila, por existir allí el centro más adecuado a su perfil. Ese motivo no puede ser una causa para que ellos asuman el cargo, ya que el ejercicio tutelar puede desempeñarse desde la distancia, diciéndome incluso que su sede central la tienen en Valladolid, estando nosotros hasta más cerca de Ávila... El caso ahora depende del Juzgado nº 3 de Ávila, que es el que debe resolver si definitivamente la Junta de Castilla y León debe asumir el cargo o no. Hablo con el Juzgado (920359022), pero quien lo lleva (Aurora), está de vacaciones. Vuelve la semana que viene.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='MUÑOZ'and apellido2='CAMACHO GARCIA'),'2017-09-22','ICIAR: Llama Paqui, sobrina política de Juan tlf 933773421, para interesarse por el estado médico de Juan, si la operación que se le va a realizar es grave, y si necesita que alguien esté con él. Comenta que ya ha hablado con Ana Luque pero que no le ha dicho la gravedad o no de la operación. Ella estaría dispuesta a cubrir gastos en el caso de que fuera necesario. Juan solo tiene un sobrino directo que es el marido de Paqui.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2017-09-20','-tf de su hermano 606883444 , piden cita para venir a las oficinas el proximo dia 28','2');
