insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2017-09-22','ICIAR: Llama Gema, t.s. de Puebla de Sancho Pérez t/c 924 57 52 09, a la cual le hemos requerido el informe social de Ildefonso para la rendición de cuentas,desconoce su situación, y su familia tampoco sabe nada. se le informa que si desconoce la situación lo exprese así en el informe.Ildefonso tiene una ordende alejamiento de su madre pero esta no sabe hasta cuando está vigente dicha orden.','1');
