insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORA'and edp.apellido1='LEAL'and apellido2='ROMAN'),'2017-09-26','Correeo-e de Pilar Cerrillo. +++según conversación telefónica te envío los datos que tenemos del vecino de doña Isidora Leal, comunicarte que el tiene en su poder las llaves del piso y las cartillas del banco de la señora. Además, todas las pertenencias de su esposo Juan Leo cuando falleció también las recogieron ellos, su cartera con dinero,... Su nombre es Benito Donoso Calzado, su teléfono es 608 62 13 08 y (927)23 40 09.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LEON'and edp.apellido1='LEAL'and apellido2='PEREZ OLAGUE'),'2017-09-27','Acudimos ayer a la notaría de virgen de guadalupe, en Cáceres, para la firma de la compraventa de la casa en calle General Margallo, 13. La hemos vendido por 100.000 euros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2017-10-01','SALIDA Entre el 01/10/2017 y el 08/10/2017. Vacaciones en Cantabria. Solicitan autorización. Se les responde que pueden amparar las vacaciones en la Aut. Gral. que se les remitió en su momento.','2');
