insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2017-09-27','(Pedro). Reunión de Alberto y Pedro con Dª Dora, madre de Javier. +++Situación personal de Javier. +++Situación económica. +++Próxima consulta en el ESM el 02 de octubre con el Dr. Periañez. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a Asunción Cabrera, pero no me cogen el teléfono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2017-09-27','(Pedro). Reunión de la Subcomisión Sociosanitaria Regional de Casos. +++Hasta tener plaza en centro de iscapacidad se mantendrá en URH del CSS de mérida. +++Tras Informne del Cadex, se solicitará plaza en C. Dispacpacidad (RAE+C.O.. +++++Hablar previamernte con dicho centro sobre las características que se dan en este caso. +++++Reunir a la familia en la CTAEx y explicarles la conveniencia de la medida tomada. +++++Se informa en esta Subcomsión de la scompetenciasde la CTAEx en caso de que hubiese de limitar de alguna forma la relación de Ramón con la familia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2017-09-27','(Pedro)Convereasación con D. Juan y con Soraya (Directora CSSPlasencia) +++Ayer fur reconocidoi por el Forense. +++Quiere irse a su casa, pero reconoce que estaría mejor atendido en un Piso Tutelado: "...Pero no me apetece tener que aguantar a 5 o 6 personas ...".Acepta que una vez salgfa del CSS con la Plaza del Piso, se marchará allí al m enos una temporada. +++Volver a llamarlo en 10-15 días.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2017-09-27','(Pedro)Conversación con Dª Niobe, abogada de María. +++La pena de prisión de 1 año y 9 meses quizá sea suspendida y sustituida por alguna medida de seguridad(NO PODEMOS SEGUIR HABLANDO PORQUE ESTÁ CONDUCIENDO. LLAMARÉ MAÑANA ENTRE LAS 13 Y LAS 14h). +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a Dª Marisol, madre de María, pero no coge el teléfono (comunica).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2017-09-28','(Pedro). Llama D. Pablo, nieto de Dª Manuela (676-783101)muy alterado porque la CTAEx "...lo ha hecho muy mal, porque por la mañana todos estamos trabajando y no podemos ir al punto de encuentro..." +++Hablo con Dª Belén (mujer de Pablo):"En el Juzgado dicen que es la Comisión la que tiene que decirle al Juzgado cuando podemos ver a la abuela y que ellos lo respaldan..." +++COMPROMISO: HABLAR CON EL JUZGADO PARA VER QUÉ ES LO QUE PRETENDE QUE HAGA LA COMISIÓN...".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2017-09-28','(Pedro). Llamo a NIOBE y dejo mensaje en el constestador, identificando la llamada como de la CTAEx. +++Llamaré a la madre de María una vez haya hablado con la abogada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2017-09-28','(Pedro) Conversación con ASunción Cabrera (24025). +++SE está planteando la psoibilidad de "volver" a su piso. Se comenta la última información que se nos dió por parte de la hermana en relación a las condiciones de habitabilidad del piso. +++Desde CTAEx se insite en la importancia del apoyo familiar si finalmente se lleva a cabo el retorno al piso, especialmente en cuanto al control del tratamiento y asistencia a las consultas programadas en el ESM. +++Asun hablará con la hermana para conocer dicha disponibilidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2017-09-28','(Pedro) Conversación con Asunción Cabrera (24025). +++Hace algún tiempo que no la ve. SE le informa que sigue acudiendo al Comedor Social y que de vez en cuando acude a la CTAEx para autorizarle sacar dinero.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2017-09-28','(Pedro)Conversación con Asunción Cabrera (24025). +++Ha atendido a Javier hoy en su consulta. +++SE le informa de la entrevista mantenida ayer con su madre, Dora: situación personal y económica. +++Comenta que va a volver al PRL y que ella hablará con los compañeros del centro para que traten de adaptar la actividad que se le plantee a sus inquietudes: trabajo en la perrera, desdepeñar un papel de voluntario en la Protectora. +++Dice tener interés en hacer un curso de Auxiliar de Veterinaria en Almendralejo, en el centro de Formación Tierra de Barros. Dificultades: su situación económica (es un centro, además, privado), y su capacidadpara afrotar un curso de más de 900h).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='MIRANDA'and apellido2='ROSADO'),'2017-09-28','(Pedro)Conversación con Asunción Cabrera (24025). +++Ha hablado con las dos posibles candidatas a compartir piso con Catalina pero finalmente no cree que ninguna de ellas sea adecuada para convivir con ella. +++Está de acuerdo con la CTAEx en que en estos momentos Catalina se encuentra bien viviendo sola y que introducir otra variable en su vida podría desetabilizar la situación actual. Además, no hay que olvidar la volubilidad de las decisiones que toma Catalina en general y, en concreto, en este tema.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='MACIAS'and apellido2='MARTINEZ'),'2017-09-29','ICIAR: Llama MºJosé, t/c 927 43 30 03 - directora de Nuñomoral, dice que Fco. quiere ir a pasar unos días de Navidad con su hermana con la que hace poco ha retomado la relación. Ella no lo ve pero quier comentarlo con la Comisión','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2017-09-29','(Pedro)Llamada de Javier. +++Quedamos en maneterner una reunión el próximo día 4 de octubre a las 10:00h en la Comisión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2017-09-29','(Pedro)Conversación con NIOBE, abogada de María en el procedimiento penal en curso. +++Situación actual:la pena propuesta de 21 meses de prisión está pendiente de suspensión. "Hasta que el juez decida sobre la misma no se puede hacer nada...". La sustituación de la misma, llegada el caso, podría ser estar "X"tiempo sin delinquir o cualquier otra. +++Propuesta de CTAEx:dados los antecedentes de María, con periodos en los que se desconoce su paradero, la falta de control de tratamineto, el no acudir a los controles de salud mental, etc.se le palntea a NIOBE la psoibilidad de que, en las actuales circunstancias, se pueda intentar que la medida a considerar sea el ingreso en un Centro que pueda garantizar su tratamiento duranmte un espacio de tiempo prolongado, ya que el tratamiento ambulatorio se ha demostrado ineficaz en este caso. +++++Niobe refeiere que ya ha hecho una propuesta parecida al Juez en ese sentido. +++++También se le informa de que los Centros quizá más adecuados para ello sean los CSS, pero teniendo en cuenta que estos no cuentan con las suficientes medidas para garantizar una medida de seguridad de manera eficaz. +++LLAMAR A NIOBE EL PROXIMO MARTES 3 DE OCTUBRE A LAS 13:30h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='CALZAS'and apellido2='SANCHEZ'),'2017-10-02','ICIAR: LLama Domingo, el marido de María Luisa, nos hace saber que el piso vuelve a tener cucarachas. Me pongo en contacto con la empresa que ya realizó otra actuación similar en 2014, nos mandan presupuesto. Hablo con T. S. del Ayto de Plasencia, no tiene constancia porque no se han pasado por allí por el tema de las cucarachas, pero no le extraña porque la casa está dejada a pesar de contar con ayuda a domicilio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2017-10-02','ICIAR: llamo a Eugenia de nuevo, t/c directo 924 73 01 01. Va a hablar con los hermanos de Ramón por el tema de dónde van a residir mientras se efectuúa la desinfección de la casa, pues según el responsable de la empresa durante algunos días deberían estar fuera del inmueble.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2017-10-02','(Pedro)Convesración con Ana, Adva. del ESM de Merida (924-487229): +++Esperanza, la T. Soc. está ocupada. +++Carmen tiene consulta con el Dr. Periañez el próximo 30 de octubre de 2017 a las 11:40h. +++Volveré a llamar a Esperanza.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='MUÑOZ'and apellido2='CAMACHO GARCIA'),'2017-10-02','ICIAR: Llamo a Ana Luque, T.S. de Esparragosa t/c 615 749 165, para comentar e tema de la subida de la asignación de Juan. Dice que Juan pide incesantemente la subida de su asignación semanal, que literalmente se fuma pues según Juan eltabaco le da la vida. Le indico nos envie por correo electrónico justificación del aumento de la cantidad semanal que se le proporciona a Juan, aproximadamente pasar de 20€ a 30€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CESAREO'and edp.apellido1='PANIAGUA'and apellido2='CALLE'),'2017-10-02','En relación con la demanda civil de modificación de medidas, con motivo de la pensión de alimentos a sus hijos (120,04 euros), envío documentación a la abogada María Rocío Felipe Tome, 927412497-600221608-616916639, delrocio@icac.es).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2017-10-02','(Pedro)Conversación con Marta Gandullo, Jueza del Juzgado de Valencia de Alcántara (927-580297 y 927-668175). +++"La Comisión no tiene nada que hacer en este sentido -visitas de los nietos a su abuela-. Se trata de un problema entre ellos y, a lo sumo, lo que tenéis que hacer como CTAEx es decirles que, si no están conformes con la situación, lo pongan en conocimineto de este Juzgado POR ESCRITO y yo haré un requerimiento a aquella de las partes que incumplan el régimen de visitas establecido..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2017-10-02','ICIAR: Llama MAite del Penitenciario de Cc porque José Mª necesita dinero pues el que llevaba se le ha acabado. Se pasa orden para que se le ingrese 100€ en la cuenta peculio, y así poder cobrarlo el jueves.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='MORCILLO'and apellido2='PAJUELO'),'2017-10-02','ICIAR: Llaman de las cruces de don BEnito t/c 20102, pq les ha llegado una citación para el jdo de Mérida mañana 3/10. nosotros no tenemos constancia. Nos mandan la citación. Además nos llaman de la Audiencia Provincial de Mérida, Mario 924 31 02 56, para comunicarnos la citación de mañana,donde pilar será testigo muy importante, tb nos mandan la citación. hacen un exhorto para que declare por videoconferencia en el jdo nº 1 de Don Benito, y así no desplazarse hasta Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2017-10-02','(Pedro)Lllamada de Carmen, Directora CSS de Mérida (24003): +++El psiquiatra le ha dado permiso para una semana, dado que su comportamiento en el Centro es bueno. +++Al parecer ha ido la familia y les ha dicho que la Comisión les había dado permiso para sacar a Ramón... +++Carmen ha hablado con los compañeros para que actuaran en función de las dierctrices de la Subcomisión Regional. +++Informo a carmen que en ningún caso la Comisión autoriza salidas, sino que son los centros los que, llegado el caso, las solicvitan si las consideran adecuadas para la evolución del tutelado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2017-10-03','(Pedro)Conversación con Eugenia, T. Soc. SSB de Jerez de los Caballeros (924-730101): +++Ayer habló con Ángela, hermana de Ramón: Dª María, su madre, se puede marchar con su hija Amalia a Zafra durante los días de la limpieza (garantizamos así que no intente entrar durante ese periodo en la casa); Juan Francisco (hermano) se puede quedar con Ángela durante esos día y su otro hermano, Agustín, está trabajando durante un mes fuera de la localidad. +++Teléfono de Juan Francisco. 615-784228. +++Ramón NO SE PUEDE QUEDAR CON NADIE:su hermana Ángela dice que no quiere que conviva con sus hijos y que ella no se va a hacer cargo de él. +++Eugenia comenta que tampoco la alternativa de un hostal es posible, no ya solo porque cuando se ha intentado Ramón se ha negado, sino porque además ningún hostal lo quiere tener de huésped. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Juan Francisco (615-784228), hermano de Ramón,Angela, Amalia y Agustín: +++NO PONE PROBLEMA PARA QUEDARSE CON ÁNGELA DURANTE LOS DÍAS DE LA LIMPIEZA. +++Dice que su hermano Agustín ha vuelto de Alicante:"...lo vi ayer, pero no sé si es que estará de vacaciones...". En cualquire caso, Juan Francisco dice que no habrá problema en que se quede en casa de Ángela: "Hablaré esta tarde con ella". +++Sobre RAMÓN: "Mi hermana no quiere que vaya a su casa por que es un guarro: escupe en el suelo, mancha todo...y ella no quiere tenerlo por eso..." +++He pedido hablar con Ramón, pero Juan Francisco me ha dicho que se había ido al campo: "Entra y sale cuando le da la gana..." +++RETIRADA DE MUEBLES INSERVIBLES: Juan Ramón dice que él estará pendiente de lo que se puede tirar o no. +++SE LE ADVIERTE DE QUE NADIE PUEDE ENTRAR EN LA CASA MIENTRAS DURE LA LIMPIEZA DE LA MISMA. LOS ANIMALES TAMBIÉN HAY QUE LLEVÁRSELOS DE ALLÍ. +++Pregunta si su madre se va a quedar en la residencia. Como Ángela no ha hablado con él todavía, le digo que lo hable con su hermana (ella nos dijo que se quedaría también en su casa esos días) e insisto en que NADIE DEBE ENTRAR EN LA CASA DURANTE SU LIMPIEZA. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Mariola (ESM de jerez). +++PROPUESTA: tratar de convencer a Ramón de que ingrese voluntariamente en el CSS durante los días de limpieza. Lo hablará con fabiola para ver la posibilidad de ello (hay que contar también con la disponibilidad de plazas).','2');
