insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-10-03','(Pedro) LLamada de Mara (927-004349).D.G. Infancia y Familia. +++Se pone al día del Informe enviado por esta Comisión al Juzgado, incidiendo especialmemte en la mejor forma de prevenir futuros embarazos. +++Se plantea si la Comisión ha de firmar algún documentos, en nombre de Beatriz, si finalmente se lleva a cabo la "retirada" del bebé por parte de la D. General. Lo va a plantear a su asesoría jurídica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='CALZAS'and apellido2='SANCHEZ'),'2017-10-03','ICIAR: llamo a la empresa de control de plagas, t/c 927 40 47 95 - Juan Manuel, para que se pongan en contacto con Mª Luisa para pasar por el domicilio a hacer el trabajo (Alberto). Nos mandará factura x fax con nº cuenta para transferencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='MORCILLO'and apellido2='PAJUELO'),'2017-10-03','Acudimos hoy a Don Benito, en relación al Procedimiento Abreviado 29/2007, a la videoconferencia del juicio que se celebraría hoy en Mérida. No se ha celebrado porque las partes han llegado a un acuerdo. Nos envían la resolución cuando la tengan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2017-10-03','(Pedro)Llamo a Niobe, como quedamos la semana pasada. Salta el contestador. Dejo mensaje.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2017-10-03','(Pedro) Llamada de Consolación (Gerente Sepad): +++Ventura la está llamando repetidamente estos días. +++Consolación sugiere mantener una reunión con él en la gerencia. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a Ventura (12:46): NO COGE el teléfono, a pesar de que mantengo la llamada hasta que se corta. VOLVER A LLAMAR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2017-10-04','(Pedro) Llamada de Mariola (ESM Jerez). +++fabiola acepta la propuesta para ingreso voluntario de ramón en el CSS, siempre que haya plazas. Tendría que ir en taxi (lo acompañaría Silvia, de Futuex)porque no se activaría el 112. +++DIFICULTADES: +++++Que acepte voluntariamente ir: mañana Silvia se pondrá en contacto con Fabiola (Psiquiatra del ESM) para hablar ambas con él y tratar de convencerlo para que acepte ingresar durante los días de la limpieza (ya lo he comentado con Toni, de Futuex). +++++Que el día del ingreso haya plazas. +++++Disponibilidad de fechas de la empresa de limpieza: para que coincida con el ingreso. +++Mañana entra Fabiola de guardia, lo que facilitaría la actuación, pero no da tiempo para hablar con la empresa y ver en qué fechas se podría realizar. Vuelve a estar de guardia el viernes 13 de octubre (Puente del Pilar), por lo que no se podría iniciar la limpieza, seguramente, hasta la semana siguiente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2017-10-04','(Pedro)Conversación con Aurora, del Juzgado de 1ª Instancia e Instrucción nº 3, de Ávila (920-359022). +++Pendiente de la valoración e informe que se emita desde Fiscalía y posterior toma de decisión del Juez. +++Se insiste en la urgencia de la situación y se piede que se agilice todo lo que se pueda en la medida de lo posible. En cuanto se tome la decisión nos lo comunicarán.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2017-10-04','(Pedro)Llamo a Ventura (10:05): NO COGE el teléfono, a pesar de que mantengo la llamada hasta que se corta. +++VUELVO A LLAMAR.Conversación con Ventura. +++Quiere que le quitemos la tutela: pasa de las amenazas contra mí a calmarse y hablar en términos más correctos. +++Quedamos en que le llamaré para tener una reunión con Consolación la semana que viene, una vez que esta me diga el día que puede ser. Dice que el lunes no puede y el viernes es el puente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='MUÑOZ'and apellido2='CAMACHO GARCIA'),'2017-10-04','ICIAR. llaman de la Residencia, t/c 924 633 548, para informar que Juan ha ido esta mañana en ambulancia al anestesista del Infanta para las pruebas de la operación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='CASTAÑO'and apellido2='TORNAVACA'),'2017-10-04','ICIAR: LLama el sargento de la Comandancia de Aliseda, Luis María 927 277 012. Necesita información sobre la situación actual de Agustín. Agustín fue condenado por maltrato a su exmujer con orden de alejamiento. El tiempo ya ha transcurrido y desean saber si Agustín va a salir del centro donde reside pues le ha llegado a oidos de la mujer que va a volver al pueblo. Indica que la Guardia Civil protege a las víctimas de maltrato aunque ya haya pasado el periodo de alejamiento. Envia correo electrónico con detalles','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2017-10-04','(Pedro)Llama Dª Mª Ángeles, preguntando sobre el traslado de su hermana a Plasencia. +++Volverá a llamar la semana que viene.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2017-10-04','(Pedro)Conversación con Juan Carlos, solcitada por las T. Sociales del Psiq. Penit. de Sevilla. +++Juan Carlos se siente solo, pide que vayamos a verlo. Hablamos de fútbol y del huerto en el que trabaja. +++Esta tarde va a ir al cine con algunos de sus compañeros. +++Propongo llamarlo en otra fecha pero Manoli prefiere pedírnoslo antes para que pueda estar con ellas en el momento de efectuar la llamada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2017-10-04','(Alberto y Pedro). Reunión mantenida con Javier. Llega con media hora de retraso y pide disculpas por ello nada más entrar. +++CORREO-e de Javier: fraile4714@gmail.com +++El día 2 de octubre fue a la consulta del Dr. Periañez, su Psiquiátra. Le cambió la medicación y le quitó algún medicamento: +++++Ahora toma:seroquel, topomax, habilifix inyectable (mensual) y ribotril; le han retirado el deprax y el depakine (sustituido por el habilifix).En momentos de tensión, debe tomar 1 ribotil y 2 seroken. +++SITUACIÓN ECONÓMICA: se va a dar de baja en Orange y no se va a pagar ningún recibo más +++++El gasto máximo de teléfono (incluido IVA) que puede afrontar es de 60€. Dice que mirará otras compañías más baratas que le permitan acceso a internet desde casa. +++++Se le advierte de las posibles consecuencias que a nivel jurídico puede tener que enfrentar si sigue firmando contratos por su cuenta y se compromete a no hacer nada sin antes consultarlo con la Comisión. Sabe que no tiene capacidad legal para hecerlo de otra forma. +++++POSIBILIDAD DE AHORRO: disminuyendo el consumo telefónico y el de tabaco. +++OCUPACIÓN: Asunción va a hablar con el PRL para ver la posibilidadde que pueda asistir como voluntario a la perrera. +++AUTOESTIMA. Se trata de que sea consciente de lo importante que es que valore todo aquello que se le de bien o le salga bien en un momento determinado y que no se desanime por las posibles "torpezas" que en algún momento pueda cometer. Como él mismo dice "...todo es cuestión de práctica..." +++Comenta que con Asun habló de la posibilidad de cambiar de piso y de localidad, quizá Almendralejo. Dice que va a mirar alquileres allí, pero se le repite varias veces que la Comisión, de momento, no dice que sí ni no a dicha posibilidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2017-10-04','(Pedro)Llamo a Niobe. Salta el contestador. Dejo mensaje.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SARA'and edp.apellido1='VAZQUEZ'and apellido2='GILES'),'2017-10-04','ICIAR: Llamo al jdo de jerez nº 1 para informarles que con fecha de 25 de septiembre ya hemos contestado por escrito postal conacuse de recibo a su solicitud de comparecencia para la rendición de cuentas. Dice que debido a un problema informático han tenido que mandar dos escritos pues en el primero, que es el segundo que nos ha llegado a nosotros, no ponía la fecha de la comparecencia. Insisto en mandárselo de nuevo por fax ya que nos ha ocurrido anteriormente que parece ser que no les llegan pero después de comprobar la dirección nos dice que no es necesario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2017-10-04','v','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2017-10-04','En relación con la Ejecutoria 395/2017-5, nos comunican desde el Juzgado de lo Penal, nº 1, de Plasencia, que la medida de internamiento de un año la va a cumplir en el Centro Penitenciario de Cáceres, al ser el centro adecuado, según le indicaron desde la Subdirección General de Coordinación de Sanidad Penitenciaria. Empieza a cumplirla el 11/10/2017.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2017-10-04','(Pedro) Llamo a Lucía (Secretaria Gerencia). +++Reunión con D. Ventura: 11 de octubre de 2017 a las 09:30h. +++Lo comunico a D. Ventura y acepta la fecha.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='CASTAÑO'and apellido2='TORNAVACA'),'2017-10-05','Sentencia 268/2013 de 31 de octubre (Proc. Abreviado: maltrato y amenazas): +++ABSOLUCIÓN (AT. 20.1º DEL C. PENAL) +++LIBERTAD VIGILADA MÁX. DE 3+1+1AÑOS:5 AÑOS. +++Orden de ALEJAMIENTO (NO INFERIOR A 200m) DE SU EX-MUJER DURANTE 5 AÑOS HASTA EL 31-10-2018. +++INDEMNIZACIÓN: 5000€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='MUÑOZ'and apellido2='CAMACHO GARCIA'),'2017-10-05','ICIAR: Llaman de nuevo desde los Pisos Tutelados para decir que alguien de la Comisión debería haber estado ayer con Juan en el anestesista, algo que desconocíamos pues no se nos había comunicado. De todas formas le hicieron las pruebas. Nos mandan por correo un informe del hospital que dicen debe ser firmado y entregado en mano para que le pongan en lista de espera.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='CASTAÑO'and apellido2='TORNAVACA'),'2017-10-05','ICIAR: Llamo a Pablo del CRR de Cáceres, 927 18 11 09, para preguntar por situación de Agustín. Según indica no se preve que Agustín vaya a salir del centro ni que vaya a ir a Aliseda. Dice que últimamente sí que ha preguntado por cuándo termina la orden de alejamiento pero sin expresar deseo de ir a su pueblo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2017-10-05','(Pedro)Llamada de Jesús. +++Alterado, como siempre, y descontento con la gestión que hacemos de su curatela. +++Quiere cambiarse de piso porque dice "...que la vecina de arriba le roba el agua y que el dueño del piso no hace nada porque tiene algún lío con ella...". Futuex está sobre ello. +++SE le indica que busque un piso y que cuando lo encuentre nos envíe el contrato para revisarlo y ver si puede o no pagarlo. +++Pide también comprarse un amplificador para su guitarra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='PESADO'and apellido2='ESTEBAN'),'2017-10-05','MEDIDAS CAUTELARES INGRESO EN CENTRO Escalona remite, vía @, nuevo requerimiento, mediante DIOR, del Jzdo. nº. 2, de Plasencia, interesando la confirmación de plaza en centro.**Está en manos de Manuela Glez. (Discapacidad). Por tanto, se le envía, así mismo, a ella, el nuevo requerimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IVAN'and edp.apellido1='MESA'and apellido2='CANDIL'),'2017-10-05','ICIAR: Llama Caty de Aprosuba 3,nos comenta que la asignación que se le dio en verano para la visita a su hermana no lo perdió como dijo en un principio sino que se lo dio a su hermana para pagar la guardería de los niños, admitido por el mismo. Además nos hace saber que el cuñado de Iván se ha presentado en el centro pidiendo información sobre lo que cobra de pensión Iván , y del dinero de que dispone, que según él es muy poco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='BAS'and apellido2='GONZALEZ'),'2017-10-05','(Pedro)Llamada de María, T. Soc. SSB de Vva. del Fresno (924-427000): +++Requiere información sobre la tutela porque se va a celebrar el juicio de remoción proximamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DANIEL'and edp.apellido1='MONTAÑO'and apellido2='RANGEL'),'2017-10-05','ICIAR: Llama Caty de Aprosuba 3. Nos comenta que Daniel hace dos semanas en Almossasa de Badajoz se le vio cogido de la mano con un chico con síndrome de down. Preguntado por quién era dijo que era el hijo de unos señores propietarios de un bar. Iván dice que no le daban ninguna gratificación por salir a pasear con el hijo, solo algunas veces le daban de cenar en el bar. Desde Aprosuba le piden a los padres una autorización firmada que pueda llevar Iván por si ocurriera algo. Aunque lo hacen no están muy de acuerdo con dicha autorización, se muestran recelosos.s Daniel deja de salir a pasear con el chico después del comportamiento extraño de los padres. Tb envian autorización para dos actividades de Iván','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2017-05-30','DIOR Se recibe DIOR, del Jzdo. nº. 1, de Mérida solicitando a la CTAEx aportación de cuentas anuales de D. Miguel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2017-06-08','CONTESTACIÓN PUNTO ANTERIOR Se remite oficio al Jzdo. nº. 1, de Mérida, indicando que la CTAEx no ostenta cargo alguno en referencia a D. Miguel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2017-08-22','CITACIÓN PARA RENDIR CUENTAS Se recibe DIOR en la que se cita a la CTAEx para el 28/09/2017, a las 9.15 Hs., para rendir cuentas sobre la gestión de la tutela de D. Miguel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2017-09-04','COMUNICACION TELEFÓNICA Se mantiene comunicación telefónica con el Jzdo. nº. 1, de Jerez de los Caballeros. Se nos informa que el procedimiento fue remitido a los Jzdos. de Zaragoza y que, éstos, acusaron recibo del mismo. En ese punto no había sido nombrado nadie tutor o curador de D. Miguel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2017-09-05','OFICIO AL JUZGADO Se remite nuevo oficio recordando el anterior de 08/06/2017. Se informa, además, que la CTAEx no va a acudir a la citación por no ostentar cargo alguno con respecto a D. Ángel. Se hace saber, así mismo, la información recibida del Jzdo. nº. 1, de Jerez de los Caballeros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='BAS'and apellido2='GONZALEZ'),'2017-10-05','BAJA No obsante el punto anterior, se procede a dar la baja hasta el posible nombramiento. Todo ello porque la misma se debió haber realizado con f/ 02/04/2013. Se incapacitó a D. Candido, y se nombró tutor a su hermana (Dña. Josefa Bas Glez.), mediante Sentencia 42/13, de 2 de abril, proc. Inc. 953/12.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='PESADO'and apellido2='ESTEBAN'),'2017-10-05','Se recibe 2º requerimiento del Juzgado de 1ª Inst.e Instr. nº 2 de Plasencia. +++SE le entrega también a Manuela.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2017-10-06','Belén:Llama Maribel T.S del CSS Mérida, para indicarnos que Ramón ha pasado a ULE pabellón Siruela,le han sacado 300€ de la cuenta para gastos y nos indica que se ha presentado la familia comentando que "eso era mucho dinero para tenerlo allí" en esos momentos se encontraba sola la encargada y se vio presionada y les dio sobre 200€ a la familia. Por otra parte, Ramón tiene concedida una PNC por importe de 313,57€, ella va a solicitar la PNC completa de 368€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2017-10-05','ICIAR: llama Félix Sanz de Aegón seguros - investigador ( 677 471 822) para informarse si Mª Eugenia había estado involucrada en algún incendio previo al ocurrido recientemente en la vivienda donde ella se encontraba en Arroyo de la Luz. Dice que según los vecinos y la guardia civil así ha sido, además de que en alguna ocasión se le ha visto incendiando contenedores y cortinas. Le respondo que no tenemos constancia de algo así.','2');
