insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2017-10-09','En relación con la Ejecutoria 395/2017-5, nos comunica la abogada Ana I. Plasencia González, 927422919, que ha interpuesto un Recurso contra la resolución por la que se le impone a José María cumplir una medida de internamiento en régimen cerrado, en centro médico adecuado a su patología, determinando que la cumpliera en el Centro Penitenciario de Cáceres, por no considerarse como tal el mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIANA'and edp.apellido1='HERNANDEZ'and apellido2='GARCIA'),'2017-10-09','(Pedro) Conversación con Marisa, T. Soc. C.R. Cervantes (22237). +++Ya ha realizado el pago del nicho (1008,27€). +++Han sobrado 91.73€. +++Enviará certificación del pago por correo-e y original. +++El dinero sobrante lo utilizará para comprar un camisón a Dª Victoriana, que lo necesita (enviará jsutificante).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2017-10-09','(Pedro)Llamo a Niobe. Salta el contestador. Dejo mensaje y en solicito se ponga en contacto con la Comisión bien a través dfe mi correo corporativo, bien a través del de la Comisión: se indica la dirección de ambos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2017-10-09','(Pedro) Llamada de Teresa (618819511), hermana de José Mª. Preocupada por: +++Lleva 2 ó 3 días sin tomar Senogán 25: le dicen en la farmacia que ya no lo dispensan. +++Padece migrañas desde que lo dejó de tomar. +++No sabe si se ducha o no porque tiene 3 bombonas de butano vacías y no compra ni avisa al propietario. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Lourdes, Enfermera del ESM de Plasencia. Se le cometa todo ello y habla con la Dra. Parrado: +++Senogán 25: no existe alerta medicamentosa respecto a este preparado (probablemente sea problema de desabastecimineto). PUEDE PEDIR SENOGÁN DE 100 y fragmentar la pastilla en 4 partes: precisa receta de su médico para ello. +++CITAS: NO ACUDIÓ a la última de mayo. Cuando esté Ana le darán una nueva cita que le comunicarán a él y pido que también a nosotros. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a José María: le digo que vaya a su médico de familia para que le haga la receta y le explique que la dosis es de 1/4 de pastilla. Insito en que vaya lo antes posible para que retome el tratamiento ya. +++Estará atento para cuando pase el respartidor del butano pedirle una bombona. +++No jsutifica en modo alguno su falta a la revisión de mayo. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a Toni, de Futuex: +++Confirman que esta semana Teresa irá a verlo. Se le informa de todo lo anterior para que lo tengan en cuenta de cara a esa visita. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Vuelvo a llamar a Teresa (hermana) y dejo mensaje en contestador.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2017-10-09','INCIDENCIA El 09/10/2017. Dña. Loly Olivera Pachón, Trabajadora Social del HIC, informa que María se encuentra ingresada desde el día 07/10/2017, de manera voluntaria, en la UHB.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='MUÑOZ'and apellido2='CAMACHO GARCIA'),'2017-10-10','(Pedro)Llamada de Dª Paqui Rodríguez (esposa del D. José Mª, sobrino de D. Juan). CONTACTOS: +++Paqui........:933-773421 y 653581756 +++José María...:653-581755 +++CORREO-e.....:josek76@hotmail.com COLABORACIÓN: +++Podemos contar con ellos para lo que sea necesario, incluido si su tío necesita dinero por algún motivo.','2');
