insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-10-10','(Pedro) Llamada de Mercedes, T. Soc. SSB Turjillo. +++Se le pone al día del Informe remitido al Juzgado. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Pilar, Matrona de Beatriz. +++Acudió el 3 de octubre a consulta, aseada y con mejor aspecto. +++El embarazo evoluciona dentro de la normalidad. +++Sigue negándose a tomar la medicación de neurología pero se toma el ác. fólico correctamente. +++Acude acompañada de su pareja a preparación al parto y está muy ilusionada con su bebé, a quien le va a poner de nombre Mª del Rocío. +++PRÓXIMAS CONSULTAS: +++++20 OCTUBRE: ANESTESIA para EPIDURAL. 11:50h. +++++26 octubre: MONITORES (10:30) Y TOCOLOGÍA (10:45). Según la cita que le den en Tocología así la citará la Matrona (ha quedado con Virginia en que le avisará cuando salgan).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2017-10-10','(Pedro)Llamada de Carmen, T. Soc. (42853) del ESM de Valdepasillas: +++María ha solcitado el ingrespo volintario en la UHB del Infanta. +++El Dr. Samino va a hablar con su Psiquitra, el Dr. Antonio Leal, para intentar que mantenganel ingreso el mayor tiempo posible. +++Nos comunicarán lo hablado en relación a dicho ingreso. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro)Conversación con Niobe. +++Todavía no se ha tomado una decisión sobre la psoibilidad de que la pena de 21 meses se suspenda, pero todo apunta a que será así. +++La cuestión es por qué se sustituye: por parte de Niobe se ha propuesto el ingreso en centro sanitario para dar la oportunidad a María de recibir un tratamineto adecuado. +++Niobe va a solicitar informes de los ingresos en Psiaquiatría para apoyar dicha medida. +++Desde la Comisión se le reuega que haga todo lo posible para que María tenga la oportunidad de ser atendida en un Centro sanitario adecuado durante un periodo prolongado de tiempo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='DEBON'and apellido2='CHENIQUE'),'2017-09-12','SALIDA El 12/09/2017. El 04/09/2017 plantea la residente la posibilidad de realizar un viaje a Don Benito con el objeto de visitar a Juan Martín Isidoro. Refiere que es su pareja sentimental. Durante la entrevista la residente cuenta que se han conocido mediante las redes sociales. Consta en el registro de visitas que ha venido en numerosas ocasiones a visitarla, incluso en este Departamento ha entregado fotocopia de su DNI en una de las visitas.******************No obstante, desde este Departamento y con el objeto de prevenir alguna incidencia que pudiera surgir, dada la grave discapacidad de la residente, se contactó con los servicios sociales de Don Benito, coordinadora Mª. Paz Andrade, se solicitó por escrito información sobre el señor Juan Martín Isidoro, tal y como ella misma me pidió. Hasta la fecha actual y a pesar de insistir no han estimado oportuno contestar.*************Refiere la residente que el 04/08/2017 han operado a su pareja de un proceso oncológico, con posterioridad a esta fecha él ha vuelto al CAMF a visitarla.*******************************************En la actualidad es Isabel Debón quien quiere viajar a Don Benito a visitarle con ida y vuelta en el día. Para ello contaría con la asistencia personal de una acompañante (Sara Toribio, cuidadora en el CAMF) a propuesta de la propia residente y desplazamientos en taxi adaptado de la localidad de Alcuéscar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='DAVILA'and apellido2='HIDALGO'),'2017-10-11','CONTACTO JUAN FRANCISCO SÁNCHEZ (678 13 49 81). Ha sido la persona que ha llevado, de facto, la curatela hasta ahora. Mantiene un poder a s/ favor. Retiró, según comenta él, al curatelado del alcoholismo. Logró que el INSS (FELIPE GARCÍA, JEFE DE SECCIÓN DE PENSIONES. TLF.: 924 216 190) retuviera la pensión del curatelado para evitar que su mujer (anterior curadora) se la quitara. Habló con la casera del curatelado para evitar que lo desahuciaran, debe, por tanto varias cuotas de alquiler.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2017-10-11','Reunión con D. Ventura, la Gerencia del Sepad y la CTAEx.Sus peticiones: +++Que le quiten la "Curatela"...Se le explica varias veces lo que implica tanto la curatela como la tutela. Lo que él quiere es manejar su dinero como le apetezca. +++Ahora sí quiere la Ayuda a Domicilio: hablo con Susana, Futuex, para ver la posibilidad de contratar el servicio con alguna empresa o el Ayto. +++MÓVIL: dicen que le han cortado la línea: Comprobaremos si algún recibo está pendiente de pago o qué es lo que ha ocurrido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-10-11','(Pedro). Conversación con el Dr. José Antonio Lajas, Jefe del Servicio de Ginecología y Tocología del Hospital San Pedro de Alcántara (927-256318///56575): +++OTROS TELÉFONOS: 927-256260, 927-256259, 927-256262. +++Correo-e: joséantonio.alajas@salud-juntaex.es +++SE confirma la recepción del último correo-e de la Comisión, al que se adjuntaba la aclaración del Juzagdo sobre la reversibilidad del método anticonceptivo. +++Hablará con el perosnal de su Servicio para que todos estén al tanto de esta situación, dado que no se puede precisar el momento del parto con absoluta certeza.Tampoco se ha planteado hasta el momento que el mismo pueda ser programado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2017-10-11','Acudo hoy al Juicio sobre delitos leves 82/2017. No se presenta Joaquín. El resto de implicados en las distintas agresiones, entre las que se encuentra su madre, deciden no seguir adelante con el Juicio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='MUÑOZ'and apellido2='CAMACHO GARCIA'),'2017-10-11','ICIAR: llama Ana Luque para informar que Juan ya ha salido de la operación y pasa a planta, todo bien, tiene sonda anasogástrica. Le darán el alta el viernes 13. Se le facilitan los teléfonos de los sobrinos, indica que ella ya los tiene.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIONISIA'and edp.apellido1='BENITEZ'and apellido2='SANCHO'),'2017-10-11','FALLECIMIENTO Se recibe del Ctro., Ntra. Sra. de la Piedad (Almendralejo), Certificado Defunción. El óbito tuvo lugar el 09/10/2017, a las 10 horas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='MIRANDA'and apellido2='ROSADO'),'2017-10-11','(Pedro)Conversación con el Dr. Daniel Pizarro, Psiquiatra CSS de Plasencia. +++La CTAEx descarta la propuesta de que Catalina pudiera volver a compartir piso con Sonia (anterior compañera), dada la inestabilidad de aquella a la hora de mantener una convivencia adecuada en el tiempo. En estosw mometos, catalina se encuentra en una situación de estabilidad que elñ compartir piso podría poner en entredicho. +++Daniel comprende la posición de la CTAEx y agradece que le hayamos respeondido con prontitud. +++también refiere que de momento la madre de Sonia va a seguir siendo la tutora y que será para enero cuando se tenga el juicio para una posible remoción.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2017-10-10','-AMALIA: SE LE ENVIA A SU HNO. ANTONIO UNA AUTOIRZACION PARA DAR BAJA A UNA MOTO EN LA D.G. TRAFICO A NOMBRE DE ELLA . - SE PASA A LA PARTE EC. TODAS LAS DEUDAS Y DOCUMENTACIÓN QUE TRAJO SU HNO. -SIGUE EN EL CSS DE PLASENCIA . - TF. HNA. CANDI 650609633 -TF HNA. ANA 630346052 LOS TRES HNOS . ESTUVIERON EN LA CTAEX EXPONIENDO EL CASO.','2');
