insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='SOLIS'and apellido2='BERMEJO'),'2017-09-10','SALIDA Entre el 10/09/2017 y el 17/09/2017. Viaje a Cádiz, Conil de la Frontera, organizado por COCEMFE, subvencionado por el IMSERSO. La residente no ha viajado, ni viajará, en otros viajes subvencionados por el IMSERSO durante el periodo comprendido entre el 01/06/2017 y el 31/05/2018, tal y como establece el programa de vacaciones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2017-10-11','(Pedro)Conversación con Loli, T. Soc. HIC (48075): +++Se pone al día respecto a la situación de María y la necesidad, entiene la Comisión, de ingreso prolongado en Centro sanitario para garantizar trataminento y evoplución. +++Ya ha dado muestras de la agresividad y violencia que en ocasiones esgrime contra quine no le da lo que pide. +++Me pasa con el Dr. Antonio Leal, Psiquiatra de la UHB: +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Converscaión con el Dr. Antonio Leal. +++Se planmtea la necsidad de ingreso prolongado, y si bien dice que María pide quedarse todavía en la Unidad, no descarta que lleghado el caso deban promover el ingreso involuntario si ella quiere marcharse (está tutelada) cuando se encuentre mejor. +++Reconoce que es un caso muy difícil y que en la UME no la van a aaceptar de ninguna manera por su comportamineto antisocial (motivo de exclusión), aslvo Orden Judicial al respecto: se le coemnta (ya estab al tanto) de las causa penales que tiene pendientes y estáde acuerdo que si la pena impuesta fuese internamineto en Centro sanitariao (Psiquiátrico penitenciario o CSS) sería posible facilitar dicho seguimineto. +++La Comisión plantea dicho eingreso como una oportinidad para María de, con la supervisión adecuada, garantizar su tratamineto y valorar su evolución, algo que hasta ahora no se ha "probado". ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo nuevamente a su madre pero comunica...Volvereé a intentar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='INOCENCIO'and edp.apellido1='MARTINEZ'and apellido2='NOVAS'),'2017-10-11','-AMALIA : ENVIAMOS PIA MANTENIMIENO PLAZA EN CAMP PLASENCIA','2');
