insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2017-10-13','(Pedro)Llama Paqui, T.Soc.del Servicio de Gestión de Penas de Badajoz: +++Dice habernos enviado una notificación a la Comisión para que comunicasemos a Jonathan que DEBÍA COMPARECER HOY, 13 de Octubre, en las dependencias del Servicio.Al parecer dicha notificación la recepcionó Pedro Becerra (comprobar). +++Pido que la envíe por fax para tener constancia.La envía. +++En dicha comparecencia, se le debía notificar la realización de 50 jornadas de trabajos para la Comunidad. +++TRATAR de LOCALIZARLO y decirle que llame a Paqui, para nueva cita, al 924-256158. paqui comenta que ttodavía tiene un plazo de un mes para ser citado nuevamente antes de comunicar la incomparecencia al Juzgado. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a Jonathan al teléfono 666-940487: +++Salta el contestador: dejo grabado que se pase por la Comisión o bien que nos llame.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2017-10-13','(Pedro)Se recibe correo-e de Curro en el que se solicita la opinión de la CTAEx para asumir la tutela de D. Miguel, actualmente en manos de la C. A. Aragón. +++Llamo al CSS de Mérida y hablo con Maribel:el 2 de noviembre de 2016 ingresó en UME y el 30 de julio de 2017 pasó al pabellón de Siruela para crónicos. +++Pido a Maribel que nos envíe el Auto del Juzgado de 1ª instancia e Instrucción nº 2 de Mérida, de 31 de julio de 2017, en el que en su parte dispositiva se indica: "DISPONGO: AUTORIZAR el cambio de tutela excusando del cargo tutelar a la Comisión Tutelar de Aragón y nombrando como tutor de Miguel Gamero Gómez a la Comisión Tutelar de la junta de Extremadura". +++Llamo a Curro para informarle de ello, pero no consigo contactar con él.','2');
