insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2017-10-16','(Pedro). No consta en el expediente si se finalmente se han llevado a cabo o no las consultas solcitadas al ESM. +++Comprobar si se han realizado las visitas a ESM y ver posibilidad de derivación dentro de la red. +++Solicitar revisión del Grado de Dependencia. +++EXPEDIENTE de DEPENDENCIA:CBr-07558-11','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2017-10-16','(Pedro)Llamada del Dr. Javier Jerez, Psiquiatra de la UHB del H. Nuestra Señora de la Montaña. +++A fecha de HOY se le ha dado el ALTA n la UHB y se ha derivado a la UME de Plasencia. +++Enviará por fax Informe de Alta y derivación. +++Igual que CTAEx, considera que Saturnino no mtiene conciencia alguna de enferemdad y que debe estar un tiempo prolongado en un entorno controlado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMELO'and edp.apellido1='VERA'and apellido2='NAVAS'),'2017-10-16','(Pedro)Llamo a D. Carmelo.llamó ayer, domingo, por la tarde. +++No le ocurría nada. Dice que él no llamó, por lo que cree que sería un error al marcar otro número. Está bien. +++Quiere irse con su hermano unos días para Navidad y pregunta si le podríamos dar algo más de dinero. Le digo que lo tendremos en cuenta, pero que nos llame un poco más adelante. NO SABE CUÁNTO DINERO PEDIR. +++Le preguntpo por la dirección de su hermano pero no me la sabe decir, auque lo intenta (La Rioja, parece ser...) Le digo que nos llame para darnos el teléfono de su hermano (lo tiene en la agenda del móvil).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='MUÑOZ'and apellido2='CAMACHO GARCIA'),'2017-10-16','ICIAR: Llama Juanjo, T.S. Hospital Infanta, T/c 924 21 80 75 - Ext 48991, comunica que la sobrina de Juan le ha tramitado el ingreso de forma privada en la residencia de Talarrubias pues Juan después de la operación no podía volver a los pisos tutelados de Esparragosa pues neesita cuidados. Quiere hablar con la Comisión para que se tramite plaza en reidencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-10-16','(Pedro)Converesación con José Antonio Lajas, sobre la comparecencia del día 26: +++Consideran que ellos poco pueden aportar, salvo el instaurar el m.a.c que el juzgado indique (reversible o no), con la única limitación de posibles efectos secundarios. +++Ya ha puesto al corriente a todo el servicio para que estén preparados ante el momento del parto: dejarán que Beatriz tenga a su hija inmediatamente después del parto y transcurrida la primera hora, más o menos, se la llevarán a neonatos. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Convesración con Rocío, Psicóloga del ESM de Trujillo: +++Beatriz no acudió a la consulta que tenía el día 13 de octubre. Virginia (Futuex) la estuvo llamando pero no le cogió el teléfono."Creo que, a medida que se va acercando el parto, es más reacia a acudir a esta consultas..." +++Se le inoforma de la comparecencia en el Juzgado del día 26 de octbre a las 10:30: necesita que se le requiera formamalmente:DIRECCIÓN: ESM de Trujillo. A/A Mª del Rocío Río Alonso. CAR. Plaza del Molinillo s/n.(10.200) Trujillo. FAX:927-322156. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Toni (Futuex): se les comunica la comparecencia del día 26 de octubre a las 10:30h para que pueda asistir Virginia. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Carmen Gallego, Jefa de Sección de Dependencia de Cáceres (927-004339): +++El PIA sale hoy para Mérida. +++En caso de DIU, este no se podría instaurar hasta tres meses después del parto y, durante','2');
