insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2017-10-16','(Pedro)Conversación con Toni (Futuex): +++Solicito nueva visita domiciliaria a Mª Luisa para valoración de la situación: confirmar que la hija ya no vive con ella y que le han retirado a su nieta. saber con quien convive actualmente. +++Solicitaremos ingreso involuntario en Residencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2017-10-16','(Pedro) Conversación con Toni (FUtuex): +++Han estado en dos Hostales de jerez con Ramón y en ninguno los dos han puesto objecciones para que se quede unos días. Enviará dos presupuestos con pensión completa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='MUÑOZ'and apellido2='CAMACHO GARCIA'),'2017-10-16','-AMALIA: A JUAN LE DIERON EL ALTA EL VIERNES TRAS SU INTERVENCION DE CANCER EN LA BOCA . ESTUVO MUY POCO TIEMPO EN EL HOSPITAL Y VA BASTANTE MAL , PRECISA CUIDADOS SOCIOSANITARIOS. COMO NO PODIA SER ATENDIDO ASI EN LOS PISOS TUTELADOS , LA TS HABLA CON SU SOBRINA E INGRESA EN LA R.M. DE TALARRUBIAS EN PLAZA PRIVADA QUE ABONARÁ SU SOBRINA . PTE. DE QUE LE DEN PLAZA T3 QUE SE ESTÁ TRAMITANDO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='VALLE'and apellido2='SIMON'),'2017-10-16','(Pedro)Llamada de Ana Benavente, T. Soc. ESM de Plasencia: +++Citan a José María el lunes 30 de octubre 0 las 9:00 con Psiquiatra y a las 9:30 con T. Soc. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Se comunica a josé Mª: todo son pegas para acudir.Quiere cambiarse al ESM de Mérida: le comento que me parace lógico, pero que esta última consulta creo que es mejor que vaya a Plasewncia, donde le cocnocen y luego que hagan informe para trasñlado de expediemnte a mwe´rida. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++llamo a Toni (Futuex): Intentarán acompañrlo nuevamente al médico de cabecera y luego al ESM de Plasencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS CARLOS'and edp.apellido1='FRADE'and apellido2='PARRA'),'2017-10-16','comunicarte que hace unos minutos Luis Carlos F. P., tutelado vuestro, acaba de ser trasaldado via 112 de forma involuntaria al HIC. Anoche llegó a Badajoz, tras estar tres días en una excursión en Galicia (junto con otro usuario de piso), parece ser que estaba sentado en un banco de fuera y no reconocía a profesionales que bajaron a buscarlo... se activo el 112 pero cuando llegaron había desaparecido, a las 3 de la mañana lo volvieron a ver por la calle y los monitores de nuevo bajaron a buscarlo, algo más accesible entró en el centro y se le facilitó el que pudiera descansar y tomar algo. Se llamo de nuevo al 112 presentándose en el centro, quisieron ponerle haloperidol negándose el propio usuario a ello... esta mañana se mostraba desorganizado a nivel de pensamientos, con un discurso totalmente incoherente y con gestos amenazantes... mantenía negativa ante la toma de medicación(algo que en sus 2.5 años con nosotros no había pasado) le hemos ofrecido acudir o bien al CEDEX o bien al ESM mostrándose agitado e inaccesible a nivel de procesamiento de la información. Vamos a ver que tal va evoluciona, realmente es una pena porque su proceso había sido muy positivo, e incluso estábamos trabajando para su incorporación al piso. si necesitas cualquier clarificación estoy en el CRR.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS CARLOS'and edp.apellido1='FRADE'and apellido2='PARRA'),'2017-10-16','Correo-e de Ana Delfa: +++comunicarte que hace unos minutos Luis Carlos F. P., tutelado vuestro, acaba de ser trasaldado via 112 de forma involuntaria al HIC. Anoche llegó a Badajoz, tras estar tres días en una excursión en Galicia (junto con otro usuario de piso), parece ser que estaba sentado en un banco de fuera y no reconocía a profesionales que bajaron a buscarlo... se activo el 112 pero cuando llegaron había desaparecido, a las 3 de la mañana lo volvieron a ver por la calle y los monitores de nuevo bajaron a buscarlo, algo más accesible entró en el centro y se le facilitó el que pudiera descansar y tomar algo. Se llamo de nuevo al 112 presentándose en el centro, quisieron ponerle haloperidol negándose el propio usuario a ello... esta mañana se mostraba desorganizado a nivel de pensamientos, con un discurso totalmente incoherente y con gestos amenazantes... mantenía negativa ante la toma de medicación(algo que en sus 2.5 años con nosotros no había pasado) le hemos ofrecido acudir o bien al CEDEX o bien al ESM mostrándose agitado e inaccesible a nivel de procesamiento de la información. Vamos a ver que tal va evoluciona, realmente es una pena porque su proceso había sido muy positivo, e incluso estábamos trabajando para su incorporación al piso. si necesitas cualquier clarificación estoy en el CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LIBERTAD'and edp.apellido1='GARCIA'and apellido2='MARQUEZ'),'2017-10-17','(Pedro)Llamada de Mª Jesús (42428), T. Soc. del C. salud de San Roque, Badajoz: +++Llamaba para saber si Libertad estaba tutelada por la CTAEx: la aceptación del cargo es de 15 de septiembre de 2017. +++Está en coordinación con Pilar, T. Soc. del SSB: nos enviarán los informes solicitados y les pido que hagan constar en ellos las propuestas que consideren oportunas. +++Refiere que tiene un Grado I y que renunciaron a un recurso (¿?)antes de estar tutelada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS CARLOS'and edp.apellido1='FRADE'and apellido2='PARRA'),'2017-10-17','(Pedro)Conversación con Ana Delfa: +++El compañero con el que se fue a Galicia comenta que fue solamente en el viaje de vuelta cuando empezó a ponerse algo nervioso. Durante todo el viaje se lo pasó estupendamente. +++Han descartado consumo de sustancias. +++Seguiremos en contacto para ver la evolcuión de Luis Carlos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2017-10-17','Hablo con el Juzgado nº 3 de Ávila, me indican que el Fiscal ya se ha pronunciado, enviando su contestación a su Señoría, para que emita la Resolución que corresponda. No nos adelantan el sentido del pronunciamiento del Fiscal. Una vez su Señoría resuelva, nos lo comunicarán por fax.','2');
