insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-10-17','(Pedro) Conversación con Pilar (54415), Matrona de Beatriz. +++Se le informa de la comparecencia del día 26 de octubre a las 10:30 en el Juzgado de 1ª Instancia e Instrucción nº 2 de Trujillo. +++Me llamará está semana si pudsiera ir. +++Me informa que el pasado día 13, sobre las 15:00h, se enteró de que Beatriz había estado en el CAR por un dolor abdominal, sinedo dada de alta sin ingreso. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++','2');
