insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2017-10-17','(Pedro) Llama la Madre de José Mª, Dª Julia 927-512108). +++Quiere que su hijo vaya a casa y él también quiere salir. +++Se le explica que ahora es necesario que se adapte al nuevo centro. Se queda convencida de las razones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GOMEZ'and apellido2='CHAVEZ'),'2017-10-17','(Pedro) llamada de Silvia (Futuex).625-548631. +++Francisco quiere hablar conmigo: "ME QUIERO IR DE ESTE PUEBLO, PORQUE NO HAY NINGÚN SERVICIO...ME QUIERO IR A ZAFRA..." +++Aparentemente no hay ningún motivo: hablaré con José, T. Social +++Le explico los inconvenenientes de ello: desarraigo, acceso a otros SSb, Sad, méwdico, etc. +++Insiste en que se quiere cambiar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2017-10-17','(Pedro) Conversación con Teófilo, T. Soc. del CRPS de Cáceres (927-232106). +++Se le explica que, dada la Sentencia 36/2014 en la que el padre de Jesús, una vez transcurridos los 18 meses y ya con pensiones reconoccidas para su hijo, queda aparatado de todfa respeonsabilidad respecto de él, la Comisión considera que no debe "mediar" en una situación que ya el Juzgado ha dado por zanjada y ante la cual no existe por nuestra parte ninguna capacidad legal para forzar al padre a acceder a los requerimientos de su hijo. +++El propio Teófilo reconoce que, cuando él intentó hablar con el padre, éste no mostró el más mínimo interés por ayudar a su hijo. +++Desde la Comisión se le plantea que sea el propio Jesús el que se ponga en contacto con su padre e incluso que le dé nuestros teléfonos por si él quisiese ponerse en contacto con nosotros. +++También plantea la posibilidad de solicitar una remoción de la tutela, o al menos que se la dejasen en una curatela.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='DAVILA'and apellido2='HIDALGO'),'2017-10-17','- tf rafael 663603150. Estoy haciendo las gestiones para desbloquear la pensión .Enviar a FUTUEX para hacer visita y pto. de gastos ( alquiler , comida del Ayto ... )','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='DOMINGUEZ'and apellido2='IZQUIERDO'),'2017-10-18','(Pedro) Converscaión con Ana, T. Soc. del IMASS de Badajoz (924-478914). +++Al parecer el hijo de Dªarmen quiere hacer alguna reforma en casa y acudió a la T. Soc. porque no podía sacar el dinero de la cuenta de su madre, con quien convive (eran uns 600€). +++Se le explica a Ana que si quiere hacer alguna reforma, tiene que ser autorizada por la Comisión si el dinero es el de su madre y, para ello, nos tiene que enviar al menos dos presupuestos y justificar por un lado la necesidad de dicha reforma y por otro el que él no pueda hacer frente a la misma. +++Según Ana, se sabe que trabaja pero sin contrato y sin conocer los ingresos que puede tener.','2');
