insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2017-10-18','(Pedro) Conversación con Juan. +++Se quiere marchar del CSS. +++Irse a vivir a Guadalupe. +++Trabajar allí para tener más dinero: "...Con 70 €/mes no tengo ni para tabaco..." +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Mariví, T. Soc: +++Si tuviese 600-700€/mes de ingreso se podría probar un piso de alquiler, seguimiento en ESM y SSB: pero carece de conciencia de enfermedad y las posibilidades de éxito, como se ha demostrado en otras ocasiones, son muy escasas. +++Compromiso: averiguar el estado de "su" casa en Guadalupe.','2');
