insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2017-10-19','En relación con el procedimiento 1215/2017, seguido en el Juzgado de Instrucción nº 2, de Badajoz, se decreta el sobreseimiento provisional de la causa. Admite recurso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2017-10-19','ICIAR: He hablado con Ángela la hermana de Ramón le comento que esta tarde van a pasar por la empresa de plagas por la casa para que avise a su familia, me dice que mandará a su hijo. Ante la imposibilidad de contactar con Juan Francisco en el tlf. que nos ha facilitado Eugenia, la T.S., será ella quien le comunique que el lunes comienzan los trabajos, y el domingo noche ya tendrán que dormir en su casa, tanto él como el otro hermano, y la madre llevarla a Zafra con su hermana. Además le indicamos que deben de comprar los dos candados ante la falta de cerradura. He hablado con la empresa de plagas, Juan Fco. 685 95 77 25, y me dice que el lunes irá a las 9 de la mañana, tardará unas dos horas, quiere que haya alguien en la casa para entrar. Nos ponemos encontacto con Tony de Futuex que nos dice irá Silvia el lunes, se le facilita el tlf de la empresa. le hemos enviado firmadopor Consolación el contrato. HEmos hablado asi mismo con la empresa de limpieza,Mª Luisa 687 46 24 27, se le ha devuelto el presupuesto firmado por Consolación, ellos irán el martes a hacer la limpieza. Estarán allí los hermanos para decirles qué tirar y qué no.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-10-19','(Pedro) Se habla con Curro: +++Se le envía el informe de CTAEx remitido al Juzgado. +++Quedamos en recogerle el día 26 para ir juntos a Trujillo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='ARNEDO'and apellido2='LOPEZ'),'2017-10-20','Acudo a la comparecencia en el Juzgado de 1ª. Instancia e Instrucción nº 4, de Mérida, en relación con el procedimiento X15 Autoriz. Jud. Disposición Bs Menores/Discapac 194/2017, para vender tres fincas en Los Guájeres. La fiscal no se opone.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='VALLE'and apellido2='SIMON'),'2017-10-18','CORREO-e DE FUTUEx: +++José Mª Valle: tiene nueva cita en su centro de salud para el jueves 19 de octubre a última hora, no quería para martes ni para miércoles ni a primer ahora porque se levanta muy tarde. Demanda más cantidad de dinero al mes, ahora recibe 250 euros (se gasta 126 euros como mínimo en tabaco) el resto en comida , compra que realiza cada dos días más o menos. Nulas habilidades para la vida en el hogar: falta de limpieza, acumulación de basura, no maneja lavadora (estando allí nos pidió que le pusiéramos nosotros la ropa para lavar) y lo más preocupante, no maneja ni sabe colocar ni calentador ni bombona de gas butano. Pide que en alguna de las visitas compremos con él la bombona y la instalemos. no acepta la planificación para el próximo lunes 23 de pasar el fin de semana con su familia, pide salir el mismo lunes temprano y acompañado por nosotros. DADAS LAS CIRCUNSTANCIAS ESPECIALES, PODEMOS ASUMIR POR ESTA VEZ ACOMPAÑARLE EN EL DESPLAZAMIENTO A SALUD MENTAL A PLASENCIA, PARA POSTERIORMENTE CAMBIAR EL EXPEDIENTE A MÉRIDA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IGNACIO'and edp.apellido1='MORUNO'and apellido2='GALLO'),'2017-10-18','INGRESO El 18/10/2017. Trasladado a Urgencias del Hospital de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN'and edp.apellido1='GUTIERREZ'and apellido2='RONCERO'),'2017-10-23','ICIAR: Llamo a Teresa, hermana de Julián, le indico que para poder con el támite de la autorizació judicial para al venta del piso se necesita que en el Registro de la Propiedad aparezcan los herederos como titulares de la vivienda. En principio lo iban a hacer en el mismo momento de la venta, le indico que para poder presentarlo en el juzgado necesitamos que lo hagan antes. Se pondrá de acuerdo con su hermana Puerto para ir a la notaría y realizar el trámite.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='PINTADO'and apellido2='ESTRELLA'),'2017-10-23','ICIAR: Llama Marivi Clemente T.S. del Sociosanitario - ext. 24142- de Plasencia indica que ha estado esta mañana el hermano de Miguel Ángel para preguntar por los enseres de M.A. y el dinero de su cuenta. Le comento que las pertenecias sí se las puede entregar al hermano. El dinero de bolsillo me indica que lo han ingresado en su cuenta. Y sobre la PNC el Registro Civil lo notifica a la Seguridad Social.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BLAS'and edp.apellido1='GUERRERO'and apellido2='ASEGURADO'),'2017-10-23','COMUNICACIÓN DE INGRESO PARA INTERVENCIÓN DE PRÓSTATA "Desde el Centro Residencia PJCRIbarra en Villafranca de los Barros se informa, que el residente tutelado por la Comisión Tutelar de Adultos de Extremadura, D. Blas Guerrero Asegurado, ingresará el jueves 26/10/2017, a las 10:30, en el Hospital de Mérida, para intervención quirúrgica de próstata que tendrá lugar el viernes 27/10/2017.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BLAS'and edp.apellido1='GUERRERO'and apellido2='ASEGURADO'),'2017-10-23','SALDIA "Desde el Centro Residencia Presidente J.C.R. Ibarra se informa que el residente Tutelado Blas Guerrero Asegurado, acudirá máñana día 20/10/2017 a visitar la localidad de Salvatierra de los Barros, acompañado del personal del centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='PINTADO'and apellido2='ESTRELLA'),'2013-10-21','EXITUS El 21/10/2017, a las 17:30 Hs. La compañía funeraria a la que estaba suscrito se ha hecho cargo de las gestiones del sepelio, pidiendo opinión al único hermano del paciente, residente en Navalmoral de la Mata, se trasladó el cadáver a dicha localidad, para el entierro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2017-10-23','ICIAR.Llama Loli, T.S. del Infanta, para comunicar que a maría le dan de alta hoy, y que nos ha enviado fax. Antonio, el amigo del padre de María, la va a recoger para llevarla a su casa. La madre de María es conocedora tanto del alta como del traslado de su hija a la casa de Antonio. Tb nos informa de que según la madre Antonio ha grabado las conversaciones que ha tenido con la comisión y se las ha pasado por audio a ella, sin la autorización de la Comisión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2017-10-24','(Pedro)Conversación con María, T. Soc. C. Salud Zafra (45970). +++SE le pide que, cuando acuda Ildefonso por el centro, le digan que se ponga en contacto con nosotros. +++Acualmente está conviviendo con dos amigos, pero no acudió a la CTAEx en como quedamos en la reunión de junio para superviasr el contrato de alquiler y regular las cuentas. +++Actualmente saaldo negativo de casi 500€. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Convereación con Gemma, T. Soc. de Puebla de','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='ESTRELLA'and apellido2='CARRASCO'),'2017-10-24','NOS CONTESTAN LOS SERVICIOS SOCIALES DE DAIMIEL DICIENDO QUE NO TIENEN INFORMACIÓN ALGUNA SOBRE JOSE ANTONIO NI SE HA INTERVENIDO CON EL. LLAMO AL SSB DE VILLANUEVA DEL FRESNO PARA SABER SI HA VUELTO AL PUEBLO. ME DICE LA TRABAJADORA SOCIAL QUE ALLÍ NO HA REGRESADO. INTENTARÁ AVERIGUAR SU PARADERO A TRAVÉS DE LA FAMILIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='FERNANDEZ'and apellido2='PINILLA'),'2017-10-24','(Pedro)Llamada de D. Federico Bonilla (680-973608), cuñado de D. Miguel.Vive en Andorra. +++Ha estado hablando con los comapñeros del CSS de Mérida. +++D. Miguel padece un cancer de pulmón ("terminal" según D. Federico) y "...creo que no merece la pena que se le opere, porque él ya ha vivido todo lo que tenía que vivir y ha dado mucho mal en su vida...". Se le indica que eso no lo tiene que decidsir ni él ni nadie y que serán los médicos correspoendientes los que digan a la Comisión lo que procede en este caso y en base a ello se autorizará o no la intervención. +++Pregunta por que le procedimineto a seguir una vez se produz ca el fallecimiento... ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Blanca, T. Soc. CSS de Mérida (24012): +++Los médicos no se ponen de acuerdo: en Baddajoz creen que la operación sí es posible y aquí en Mérida parace que no lo tienen tan claro. +++Se está a la espera de los informes médicos para tomar una decisión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2017-10-24','(Pedro) Llamada de Eugenia: +++La empresa de limpieza dice que el Ayuntamiento tiene que poner contenedores para tirrar toda la basura. +++Se le indica que en el presupuesto está contemplada esa cláusula. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversacaciones con Mª Luisa (687-462427) de la empresa de limpieza y con Francisco (685-957725): +++Nuevca desinfección esta tarde. +++Retomar limpieza a partir de que el de plagas indique que se puede hacer.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2017-10-24','(Pedro) Llamada de Dolores. +++Quiere pedir cita. Le digo que no pueede ser hasta dentro de dos semanas. +++QUIERE SER ENTERRADA EN ACEUCHAL, donde tiene un nicho en PROPIEDAD. +++Le han dicho que tiene artrosis en las caderas. Quiere un colchón más grueso.Se le dice que lo hable con Gisela y que lo consulte con el médico para ver qué tipo de colchón sería más aconsejable. +++Dice que Antonio le ha propuesto pinerla en la cuenta. Se le dice que no, que cada uno en la suya. +++SE PUEDE DECIR QUE HEMOS TENIDO LA REUNIÓN POR TELÉFONO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2017-10-24','-CARMEN FERRER NOS TRAE DOCUMENTACION SOBRE INCIDENCIAS DE PACO EN EL CRR ( AMENAZAS DE MUERTE Y AMENAZA DE ABUSO SEXUAL ) . LO DERIVAN A LA UHB Y DE ALLÍ A UME DE CSS PLASENCIA DONDE SE ENCUENTRA. DISCREPANCIA ENTRE PSIQUIATRAS NO SE PONEN DE ACUERDO EN EL RECURSO MÁS IDONEO PARA ÉL.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2017-10-25','(Pedro)Converscaión con Asunción Cabrera (24025). +++Preparando salida de Manuel del CSS, con intención de alta en Pisos Supervisados ante de dar el paso de volver a su piso de Badajoz. +++Sale los fines de semana a Badajoz, está con sus hermanas pero vuelve en el día. +++Tiene mucho repseto a la recacción que puedan tener los vecinos con su regreso. +++Ha hablado con la hermana, Mª José, y estaría dispuesta a que cuando vuelva al piso ejercer cierta supervisión en su evolución (medicación, ESM etc.). +++Cuando llegue el momento podría salir cada 15 días un par de días, tratando de que Futuex le hiciese alguna visita. +++ACTUACIÓN: +++++++hablar desde CTAEx con Mª José, la hermana, para ver la s necesidades que tiene el piso para ser habitable por una persona. Que haga un presupuesto para valorar el mismo y luego decidir.MANUEL NECESITA VER QUE SE ESTÁN DANDO PASOS HACIA SU AUTONOMÍA. +++++ASUN: estará pendiente de la lista de pisos supervisados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2017-10-25','Visita de Víctor Martín: +++Por motivos de trabajo no puede acudir a la reunión de hoy a las 11. "Me han avisado con muy poco tiempo...y no sé tampoco cuando vamos a terminar". +++Le indico que esa reunión se tiene que celebrar y que le avisarán con más tiempo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='JIMENEZ'and apellido2='RUIZ'),'2017-10-25','-AMALIA: NOS LLAMA POR TF EL TECNICO PIA QUE SOLICITÓ EL AÑO PASADO POR DEPENDENCIA PLAZA EN DISCAPACIDAD POR EMERGENCIA S. AUN NO TENEMOS LA AUTORIZACION JUDICIAL PARA EL INGRESO ( SE ENVIÓ EN NOV 16 ) NO SE HIZO INVENTARIO ( SE LO PASO A M. JOSE ) PREGUNTO EN DISCAPACIDAD Y NO LO TIENEN TRAMITADO. AL RATO ME CONFIRMAN QUE TENDRIA PLAZA RAL EN VERA. PTE. DE LA RESOLUCION JUDICIAL PARA EL INGRESO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='MUÑOZ'and apellido2='CAMACHO GARCIA'),'2017-10-25','-AMALIA : NOS LLAMA PAQUI SOBRINA DE JUAN DESDE BARCELONA ( 933773421) , SU TIO INGRESÓ AYER POR URGENCIA EN EL HOSPITAL DE TALARRUBIAS. NO LE DAN INFORMACIÓN CLINICA POR TF Y QUIERE SABER COMO ESTÁ. PAGARÁ LA PLAZA EN RESIDENCIA PERO NO POR MUCHO TIEMPO PQ LE CUESTA 1500€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='MUÑOZ'and apellido2='CAMACHO GARCIA'),'2017-10-25','-AMALIA: HABLO CON LA TS ( ANA LUQUE ) PARA SOLICITAR INFORMACIÓN . YA HA REMITIDO PARA QUE FIRMEMOS LA SOLICITUD DE T3 . ESTARIA EL PRIMERO PARA EL CENTRO DONDE ESTÁ AHORA. ESPERARIAMOS UN MES POR SI SE QUEDA ALGUNA LIBRE Y SI NO LA PLAZA DONDE SEA. HA MANDADO FACTURA DEL ACOMPÑAMIENTO EN BJOZ. SE PODRIAN PONER UNAS HRAS EN ESTE NUEVO INGRESO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2017-10-24','ICIAR: Llama Beatriz para confirmar si desde la Comisión se ha propuesto a Pilar, pisos tutelados, que Beatriz deje el piso de alquiler y vuelva con ellos. Nos dice que si ha estado últimamente solicitando más dinero, a parte delos 60€ de su asignación semanal, ha sido para dárselo a su familia pues ellos no disponen de ingresos. Ella asegura que a partir de ahora no va a volver a hacerlo y que con su asignación le vale para sus gastos, que de hecho está ahorrando 10 € cada semana. Dice que si tiene algún gasto que no pueda asumir con la asignación se lo comentará a Pilar para que ella lo pida. Está arrepentida de lo que ha hecho y no volverá a suceder. Quiere quedarse en el piso de alquiler donde se encuentra muy agusto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-10-24','(Pedro)Conversación con Ana Rosa, T. Soc. de Plena Inclusión Extremadura (924-315911) +++Sugieren que llame a la Casa de La Mujer de Cáceres porque Plena Inclusión tiene algún programa en consjunto con ellos y quizá el caso de Isabel lo puedan atender allí. +++Muestro mis dudas al respecto por cuáles son los objetivos de dicho recurso, que no "cuadran" con las necesidades y perfil de la situación de Beatriz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-10-25','(Pedro)Conversción con la Casa de la Mujer de Cáceres, con su Directora, Blanca Delgado (927-010868). +++EL CASO DE BEATRIZ NO ES SUSCEPTIBLE DE SER ATENDIDO EN ESTE RECURSO. +++Sí me comenta, a colación de una pregunta mía al respecto de dicho recurso, que en una ocasión hicieron derivación de una mujer embarazada al Centro Materno Infantil "Ave María" en Santa Marta de Tormes, al cual tengo penbdiente llamar. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro)Centro Materno Infantil "AVE MARÍA", en Santa Marta de Tormes.Hablo con su Directora. +++Contacto: Rosario, Directora. 923-200388 +++Correo-e: rosariocentroavemaria@gmail.com +++Atención residencial 24h. Capacidad: 14 plazas, actualmente ocupadas 12, vacantes 2 pero una de ellas está prácticamente ocupada. +++SOLICITUD: A través de remisión de Informe sobre la situación de la mujer afectada. +++ACTUACIÖN: interiorizar la maternidad, en caso de menores , fomentar los estudios de la mujer y también la inserción laboral. +++DISCAPACIDAD: no se pone objecciones inicialmente ante la situación descrita respectoi a Beatriz. +++PAGO DE LA PLAZA: supondría en este caso entregar la PNC completa, únicos ingresos de Beatriz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='MUÑOZ'and apellido2='CAMACHO GARCIA'),'2017-10-25','- Hay una baja de T3 que vamos a intentar que sea para Juan . Hablo con TS del Hospital van a enviar consentimiento informado . Pte. de acompañamiento si desde la RM. encuentran a alguien.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIANA PAULA'and edp.apellido1='CENTENO'and apellido2='RODRIGUEZ'),'2017-10-25','ICIAR: Recibimos la llamada de Soledad Jiménez,ahijada de Juliana Paula t/c 660802605, ha vuelto de Escocia. Nos dice que reside en Alicante. Ella ha llamado a la residencia donde está Juliana, ha hablado con Pilar la directora y también con Juliana. Dice que su madrina quiere ir a su piso pq dice que le han robado sus cosas, ella vendrá a Cáceres el próximo mes de noviembre y le gustaría visitar la casa con su madrina. Además indica que quiere que su madrina le compre un coche que necesita pues el trabajo que ha conseguido está en Denia y ella vive en Alicante, el anterior coche ya se lo compró tb Juliana. Comenta que su madrina, a la que llama tía, le ha dicho que sí pero que no sabe cuánto dinero tiene en su cuenta. Dice que ella no se hizo tutora de su tía porque estaba fuera de España pero que piensa que igual podría hacerlo ahora. Asegura que ella es la única heredera de su madrina. Como su tía está tutelada por la Comisión le comento que para hacer cualquier movimiento se necesita autorización judicial.','2');
