insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2017-10-26','ICIAR: Llama Antonio, hermano de Concepción,para informarse si Concepción va a disponer de dinero durante los días que va a estar en Trujillo en casa de la madre ( de jueves a domingo. A Concepción se le ha autorizado para que saque dinero de la sucursal de su banco en Trujillo mañana viernes. Así se le comunica. Además Pilar del Sociosanitario de Plasencia ha quedado en llamar también a la hermana de Concepción para decírselo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2017-10-26','- SE ENVIA AL CENTRO LA LUZ LA SOLICITUD DE DEPENDENCIA FIRMADA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2017-10-26','ICIAR: Llamo a Ana Royo (924-563092) de Plena Inclusión Zafra, me relata el tema de Antonia. Aunque la hermana asegura que Antonia tiene el testamento del padre en su poder ella dice que no lo tiene. Ana va a intentar pedírselo de nuevo. La hermana de Antonia estaba pagando los gastos de la casa que tienen en herencia los tres hermanos, pero ha decidido dejar de pagar porque los gastos son de los tres, a raiz de lo cual se ha producido un embargo de cuentas. Habría que mirar el tema de la casa y los gastos, además de que indica que la casa necesitaría alguna reforma para que no se deteriorara más. En principio no querrían venderla.El hermano no quiere saber nada de dinero ni de casas, y las hermanas no se llevan bien entre ellas. Existen también dos cuentas, una en Caja Rural con Antonia y su madre, y otra en Caja Badajoz de Antonia con el padre. Según Ana se debería gestionar la herencia, primero va a comprobar el tema del testamento. También comenta el tema de la dentadura. Antonia ha accedido a ponerse una dentadura convencional, el presupuesto estaría entre 3000-4000€. Habría que mirar el tema porque a día de hoy está sin dientes.','2');
