insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-10-26','COMPARECENCIA EN EL JUZGADO DE 1ª INSTANCIA Nº 2 DE TRUJILLO. +++ASISTENTES: Patricia (Jueza), Carmen Barquilla (Fiscal), Merecedes (T. Soc. SSB), Virgnia (Delegada Tutelar de Futuex), Curro (Gabinete Jurídico) y Pedro (CTAEx) +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++UNIDAD DE TRABAJO SOCIAL DEL H. SAN PEDRO DE ALCÁNTARA: 56341 y 56348.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-10-27','(Pedro)Rocío (ESM): no ha acudido a la consulta de hoy. +++Virginia no la ha podido localizar. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Correo-e de Merecedes, del SSB de Trujillo. +++Esta mañana me llamó Mara, de Menores, para ver en qué había quedado la reunión de ayer, pero creo que también ha contactado contigo. Y, lo más importante, esta mañana Beatriz tenía dos citas: una con la ATS de la localidad a la que tenía que llevar una muestra de orina ya que continúa con la infección de orina y, a las 11:30 tenía cita con al Psicóloga. Pues bien, no ha ido ni a una ni a otra. Virginia contactó con ella ayer pero cuando ha venido no la ha localizado en casa; la ha estado buscando en los sitios habituales y tampoco la ha localizado. No ha sido capaz de contactar con ella ni por teléfono ni por whatsapp, así que la he acompañado a casa de Antonio para buscarla allí. Cuando hemos llegado nos ha dicho la cuñada de Antonio que se acababan de ir (previamente Virginia había ido al Centro de Salud para hablar con Rocío, la Psicóloga, y para comprobar si estaban por allí). Tras ir a casa de Antonio, hemos subido al Juzgado para comentarle a la Jueza y que tomara nota para posibles comunicaciones a la Fiscal (no sé si nos habremos anticipado o extralimitado, pero la intención era buena). No obstante, la Jueza hoy no estaba en Trujillo. Finalmente hemos localizado a Beatriz y a Antonio esperando el autobús que va a Huertas de Ánimas. No ha sabido dar explicación de por qué no ha ido a las consultas. Ha manifestado que no le gusta estar con la Psicóloga. Antonio dice que se siente acorralada con tantas consultas. Lo que está claro es que ella no ve necesario tantos controles médicos a pesar de que parece ser que ayer tenía la tensión muy alta y estuvieron a punto de dejarla ingresada por este motivo, según me informa Virginia. Creo que te he hecho un buen resumen. Si lo crees conveniente, llámame. Un saludo. Mercedes Prieto Sánchez. Trabajadora Social del Ayuntamiento de Trujillo +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ CONVERSACIÓN CON MARA (D.G. DE INFANCIA Y FAMILIA).927-004349. +++Papel de la CTAEx...........firmar la renuncia. +++TUTELA del Menor: desde que se le comunica el nacimiento a Menores. +++Informar a la madre.........Menores, aunque la Comisión puede y considero que debe estar presente. Requerir apoyo psicológico/psiquiátrico previsto con antelacxión ante la posible reacción de Beatriz. +++Orientaciones para la madre (en este caso también para Ctaex): derecho del hijo adulto a conocer a su madre, etc. (Ley 1026/2015, de 28 de julio). +++EL PADRE: desde Menores se está gestionando esta situación en previsión de cuál puede ser la respuesta de éste. +++ACOGIMIENTO PROPUESTO: URGENTE (no más de 6 meses). +++++DERECHO de la madre a VISITAR a su hijo: tiene derecho legal, pero se tiene que valorar la conveninecia por parte de los Técnicos. +++LA MADRE, tras la renuncia, tiene un PERIODO de REFLEXIÓN de 6 SEMANAS, tras el cual se puede ratificar o no en dicha renuncia tras nueva firma.','2');
