insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-10-30','- HABLO CON TONI COORDINADORA FUTUEX PARA QUE ME PERMITA HABLAR POR TF CON VIRGINIA PERSONALMENTE. ME CUENTA QUE BEATRIZ ESTÁ ASUSTADA , SOSPECHA QUE LE VAN A RETIRAR A SU NIÑA Y NO ESTÁ DISPUESTA A ELLO. ANTONIO , PAREJA DE BEATRIZ , RESIDE EN TRUJILLO PERO PASA MUCHO TIEMPO EN SU CASA ( HUERTA DE ANIMAS ) DESCONOCE SI LE HAN HECHO PRUEBAS PARA DESCARTAR POSIBLES DISPCAPACIDAD DEL BEBÉ . TIENE COSAS COMPRADAS AUNQUE POCAS . LA IDEA ES QUE CUANDO SE PONGA DE PARTO LLAME AL 112 Y LA TRASLADARÁN AL HOSPITAL. LE HA DADO SU TF PARA QUE LA AVISEN A CUALQUIER HORA. TRATO DE CONTACTAR CON UNIDAD DE TS DEL HOSPITAL SAN FCO. PERO NO ES POSIBLE.','2');
