insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='SANCHEZ'and apellido2='PANIAGUA TRENADO'),'2017-11-02','En relación con la herencia de su abuela, volvemos a solicitar asistencia jurídica gratuita, la anterior designación quedó sin efecto porque el letrado designado pertenecía a un Partido Judicial incompetente territorialmente, al que corresponde, debido a que la abuela falleció en Talarrubias, siendo los Juzgados competentes los de Herrera del Duque y no los de Don Benito.','2');
