insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='PARIENTE'and apellido2='LUCAS'),'2017-11-06','Iciar: Llama Juana la T.S. de Villa del CAmpo, t/c 927448177, para saber cómo van las gestiones con los solares de Juana. Se le indica que estamos tramitando la herencia para posteriormente pedir autorización judicial de aceptacióny una vez hehco pedir autorización judicial para venta del solar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='RASTROLLO'and apellido2='BARRAGAN'),'2017-11-06','(Pedro) Conversación con Blanca (T. Soc. CSS Mérida. 24012): +++Saldo a fecha 25 de septiembre de 2017: 4340,21€. +++PROPUESTA CSS: quieren darle permiso de salida a Llerena UN DIA entre semana. Solicitan visita de Delegada de Futuex durante esa salida. +++PROPUESTA CTAEX: +++++Nos avisarán con 2 ó 3 días de antelación para tratar de ajustar esta visita con FUTUEX. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llega propuesta del CSS Mérida para dar permiso para los día 15 y 16 de noviembre (pasar una noche en Llerena, C/ Ollerías 32.). +++Lo hablo con Toni (Futuex) y es posible visitar a D. Agustín una de esas mañanas. Les indicaré el momento y la dirección cunado Blanca confirme a qué hora va a llegar, o bien dejar la visita para el 16 por la mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DANIEL'and edp.apellido1='MONTAÑO'and apellido2='RANGEL'),'2017-11-06','En relación con el Juicio Verbal 684/17, seguido en el Juzgado de 1ª. Instancia nº 2, de Badajoz, han señalado citación para el día 15/1/2018. Me pongo en contacto con la abogada que le ha designado el Colegio de Abogados, María Luz Carrasco Vallés (693325817-3392@icaba.com)a los efectos de enviarle documentación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2017-11-06','Icíar: Llamo a Vanesa al Centro Ocupacional de Miajadas, Directora MArili t/c 687820329, después de hablar con los pisos tutelados de Almoharín, t/ 927 38 62 24, para informarle que mañana martes 7/11 tiene que acudir al Jdo nº 2 de Trujillo donde se celebrará el juicio que había sido suspendido por delito leves- pelea con perros. Desde el Centro Ocupacional de Miajadas se encargan en llevarla al Jdo de TRujillo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-11-06','(Pedro)Comunicación del nacimiento de Rocío, hija de Beatriz, esta mañana a la 01:00h de la madrugada (6-11-2017): +++ESTADO:ha nacido con bajo peso y ha tenido que ser intubada. En el momento de la llamada a Mamen, T. Soc. del H. San Pedro de Alcántara, se encontraba en la UCI de Neonatos, ya sin respiración asistida. +++COMUNICACIÓN (POR TELÉFONO): Al Juzgado (Patricia, Jueza), a la Fiscalía (Carmen Barquilla, Fiscal), a Gabinete Jurídico (Curro), a Futuex (Virgina, Delegada Tutelar), Rocío (Psicóloga ESM Trujillo), Merecedes (T. Soc. del SSB Trujillo), Pilar (Matrona) +++Conversaciones con Pilar Ribada, Ser. Jurídico de Menores y a Mara, T. Socila del mismo Servicio. +++ACTUACIÓN: previsto por Menores acudir esta mañana a comunicarle a Beatriz la retirada del bebé. SOLCITO QUE NOS AVISEN A LA CTAEx para estar allí en ese momento. Así lo harán. +++Conversación con Curro: +++++al no estar casados Betariz y Antonio, es necesaria la DEclaración de la madre atestiguando que el padre es tal para que si lo quiere reconocer lo puedas inscribir en el Registro Civil. +++++Si Beatriz quiere RECURRIR la reirada del bebé, la CTAEX ha de soicitar un abogado de oficio para que se encargue del tema, ya que en este caso se produce un CONFLICTO DE INTERESES al ser la Junta de Extremadura quien tutela y quien retira. Considero que, tanto legal como éticamente, hemos de informar a Beatriz de dicha posibilidad por si la quiere ejercer. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con MERCEDES(T.Soc. SSB e Trujillo) +++SE le informa del estado de Beatriz. +++Nos informa de que ha "aparecido" David (32 años), hermano de Beatriz, a través de una Educadora (¿?) del centro en el que estuvo él (también ha tenido una vida complicada). Se interesaba por saber si tenía que "ayudar" a su hermana conalgún trámite. Mercedes comenta que, al parecer, él también acaba de ser padre y que su mujer no debe estar muy bien. Le ha informado de que su hermana ya está atendida en todo lo necesrio por la CTAEx. +++Por otra parte, David tampoco mantiene ningún contacto con su madre, a la que considera desaparecida. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamadas a los siguinetes servicios: +++Neonatología (Dra. Mª Jesús García):56316 +++Obstetricia ( Enferemera Mercedes) :927-256389 Ambas informan de que tanto madre como hija se encuentran bien en estos momentos y que durante el parto hubo de ayudar finalmente a Beatriz utilizando espátula para alumbrar al bebé.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='CAYERO'and apellido2='AGUILAR'),'2017-11-06','(Pedro)Conersación con Mª José (CTAEX). +++Maribel directora de Aprosuba 9, informaq que José tiene que acudir al H. De la Princesa, en Madrid, el 22 de MARZO de 2018 para un ESTUDIO NEUROLÓGICO. No es posible el traslado en ambulancia (salvo que la pagara él). Verá la posibilidad de trasdlado en taxi. +++REQUIERE ACOMPAÑAMIENTO para traslado y estancia en Hospital: NO SE SABE LA DURACIÓN DEL INGRESO. Además, requiere que el acompañante sea conocido de José, por lo que tendrá que ser alguien del propio Centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2017-11-06','(Pedro) Conversación con Soraya. +++Han trasladado a D. Francisco al CRR de Cáceres dedsde el pasado 20 de octubre. Carmen Ferrer trae la comunicación por escrito.','2');
