insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2017-11-07','- SOLUCION PARA GARANTIZAR LAS COMIDAS , SE VA A COMPRAR UN MICROONDAS PARA QUE CALIENTE LOS PRODUCTOS PRECOCINADOS Y SE MANTIENE EL GASTO LIMITADO A 180€ EN LA TIENDA . SE DEJA EL RESTAURANTE DONDE HA COMIDO DURANTE UNOS DIAS . ANTE OTRAS ALTERNATIVAS PARA IR A COMER A R. MAYORES... ÉL NO QUIERE .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='RETAMAL'and apellido2='GONZALEZ'),'2017-11-07','Iciar: Llama Cándido porque necesita unos zapatos. Hablo con la zapatería Salamanca de Almendralejo, efectivamente se ha pasado por allí. Le apartan los zapatos hasta que C. saque el dinero y pase a recogerlos. También le informo de que a partir de diciembre la primera semana de cada mes retirará 150€,antes eran 100€ y de manera puntual 50€, y las siguientes 65€ como siempre. Se le recuerda que a partir de diciembre los reintegros extras deben limitarse.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2017-11-07','-ALTA EN UME DE CSS PLASENCIA . PASA AL CRR DE CÁCERES EN LUGAR DEL DE PLASENCIA , ALLÍ EL PSICOLOGO ES UN HOMBRE, TRAS LAS AMENAZAS A LA PSICOLOGA DEL CRR DE PLASENCIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2017-11-08','Iciar: Llamo a Toni de Futuex para explicarle lo que gestionamos con el teléfono del exnovio de Felisa pues hemos recibido nota de Virginia, la delegada de apoyo, diciendo que se ha dado de baja la linea de móvil de Felisa aparengtemente suplantando su identidad. Le indico que la linea de la cual pagamos la deuda, y que hablamos con el programa familia, no estaba a nombre de Felisa sino de su exnovio. Esta linea a la que ellas se refieren debe de ser otra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN JOSE'and edp.apellido1='EXPOSITO'and apellido2='VERDION'),'2017-11-08','Iciar: Llama de Santa Lucía para indicar que le viene devuelto el recibo del seguro de decesos desde el mes de septiembre. Comprobamos que Caja Sur ha pasado a ser Caja Almendralejo y ha cambiado el nº de cuenta. Se le facilita el nuevo nº para que pasen de nuevo los recibos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2017-11-08','Acudo el 7/11 al Juicio por Delitos leves 18/2017, seguido en el Juzgado de 1ª. Instancia e Instrucción nº 2, de Trujillo. La parte denunciante no va a continuar con el mismo, con lo que se dictará Sentencia absolutoria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2017-11-08','Iciar: Llama Toni y nos facilita el móvil que ha sido dado de baja 658 886 236. Llamo a Orange 1414 y me confirman que efectvamente ha sido dado de baja el día 2/11, la documentación con el dni escaneado y la "firma" de Felisa fue enciado el día 25/10 para proceder a la baja. Desde el servicio de bajas nos confirman que la baja la han solicitado porque tiene una sentencia de incapacitación!!???, y que de ninguna manera se be de reactivar!!??? No saben decirme quién ha solicitado esa baja. Intentan reactivarla en 48h. pero no lo aseguran. Nª incidencia 1-25951845 (Ana- Supervisora Dpto Bajas- León)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-11-08','Traslado e ingreso de Beatriz en Plena Inclusión de Llerena sobre las 14:30h. acompañada por Virginia (637-266068. Futuex).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-11-09','(Pedro) Conversación con Cristina, Directora de Plena Inclusión de Llerena ((924-870293///correo-e: plenainclusiónllerena.gerencia@gmail.com) +++Beatriz ha pasado bien la noche. Ayer apernas comió y durante toda la tarde estuvo acompañada, primero, al llegar, por Mª Ángeles, la Psicóloga y después por una Educadora. +++Estuvo hablando por teléfono con Antonio (pareja), con alguna vecina y con su madre (desconocíamos que mantuvbiera contacto alguno con ella). +++Está en una habitación doble, pero ella sola de momento. +++No deja de llorar y de decir que se quiere ir a casa con su hija. +++SE informa a Cristina sobre la necesidad de instaurar métcodo anticonceptivo en Planificación Familia: en el Hospital San pedro de Alcántara no se lo han puesto porque carecían de él. Se informa de la epilepsia de Beatriz para que se tenga en cuienta, si bien el jefe del Servicio de Ginecología considera que no hay problema por ello. +++En caso de "conflicto" con la pareja de Beatriz o con la familia de éste se indica llamen a la CTAEx y al 112. Ya ayer el Centro se pueso en conatcto con Guardia Civil para que supieran del caso y se reaccionara dcon rapidez si se deiera dicha necesidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2017-11-09','Se recibe por fax Providencia del Juzgado de 1ª Instancia e Instrucción Nº 3 de Ávila en la que se comunica a la CTAEx que se va a prestar audiencia por segunda vez a la Entidad Pública Fundación Acción Social y Tutela de Castilla la Mancha sobre si aceptaría el cargo de tutor de Dª Margarita, al no haber sido aceptado por FECLEM y, en el caso de no aceptarlo, que explique los motivos por los cuales no se acepta. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro) Llamada de Elena, T. Social de las Cumbres. +++Plantea la forma de pago de la plza residencial de Margarita a partir del 19 de octubre, fecha en la que finalizó el contrato. Enviará propuesta de pago por correo-e.','2');
