insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LIBERTAD'and edp.apellido1='GARCIA'and apellido2='MARQUEZ'),'2017-11-13','Iciar: Llama Pilar Mateos, T.S. 924 478 777, Libertad y su madre han ido al banco y no han podido sacar 20€, eran los últimos que quedaban en la cuenta. Ya está Consolación en la cuenta y por lotanto necesita autorización para retirar el dinero, Pilar se lo traslada a Libertad. Pilar ha enviado el jueves 9/11 el informe y los documentos solicitados por la Comisión pero confirmamos que aún no los hemos recibido. Nos facilita el teléfono de la madre, Eva Márquez 663 525. 644','2');
