insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2017-11-14','Iciar: Javier acude a la Comisión, aunque la cita era para las 12:30h.se presenta a las 10:10. Reunión con Alberto. Ha dado de alta Movistar fusión series: Fijo+Fibra 50 Mg+Series+Móvil ilimitado 4g. 3 primeros meses 45€ / resto 60€/mes. Se compromete a que la factura no supere los 60€/mes en ningún caso. (Nuevo nº tlf. 689 095 949). Quiere tb tratar el tema del PRL por si pudiera recibir un incentivo por acudir, pero se queda (Alberto) en llamarle para confirmárselo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2017-11-14','- FELISA PERCIBE PNC. POR SU HIJO ES TITULAR DE PFHC -18 AÑOS Y P. ORFANDAD. LA PFHC ESTÁ DOMICILIADA EN UNA CUENTA PROPIA DEL HIJO GESTIONADO POR EL CENTRO DE MENORES DONDE RESIDE ( AMALIA )','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2017-11-14','(Pedro) Conversación con Soraya (Directora CSS Plasencia, 24104). +++Juan se está mostrando más inestable, al saber que está de alta y no poder salir del CSS. +++Alternativas: pensión, alquiler...Problema: falta de recursos económicos y que existe el riesgo cierto, más si cabe al no tener conciencia de enfermedad, de que quiera volver a Guadalupe donde dice tener su casa. +++PROPUESTA DESDE CTAEx: hay pacientes externos en el CSS que pasan el día en el centro y duermen en su casa. Planteo la posibilidad de valorar que pueda compartir esa sistuación con alguno de ellos (pagando cierta cantidad) y adquiriendo el compromiso de acudir durante el día al CSS. LO planteará a Daniel (Psiquíatra) para ver la viabilidad de la propuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-11-14','(Pedro) Conversación con David Ruiz, hermano de Beatriz. Teléfono 690-941581. Vive en Madrid. +++Beatriz no había hablado de su hermano en ningún momento con la CTAEx. +++No puede acudir a la CTAEx porque tiene una tienda y solo tenía este martes para poder acudir. Respeta el no ir a ver a su hermana hasta que nosotros lo consideremos oportuno. +++El acudir por aquí no podrá ser ya hasta después de Navidad, con las vacaciones del próximo año. +++Preguntado sobre la frecuencia de los contactos con su hermana comenta que hace mucho que no se ven y que hablan de vez en cuando por teléfono (no menciona desde cuando). ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro)Conversación con Carmen Barquilla (Fiscal: 927-620279). +++Se informa sobre la situación actual de Beatriz: traslado a Plena Inclusión de Llerena (C/.Convento de los Dominicos nº 5. Teléf: 924-870293), método anticonceptivo, recurso de la abuela "paterna". +++SE confirma que el Alta de la niña se producirá en la mañana de hoy a última hora (llamo a Neonatos del H. San Pedro de Alcántara) +++SE informa también de la conversación mantenida con David Ruiz, hermano de Beatriz que vive en Madrid.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO'and edp.apellido1='BLANCO'and apellido2='LUQUE'),'2017-11-14','Iciar: Envío a al D.G: de Transporte el certificado recibido de la seguridad social de la pensión por hijo a cargo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2017-11-14','(Pedro)Conversación con Elena (T. Social de Las Cumbres). +++Todavía no ha obtenido respuesta a la ocnsulta que hizo por correo-e sobre que hacer con los cobros de octubre y noviembre de Margarita. +++Posibilidad de rebajar "algo" el coste de la plaza en las actuales circusntancias: "Lo he planteado a la Junta y me han dicho que no es posible...". +++INCIDENCIAS: recuerda la inestabilidad que afecta a Margarita cuando por ejemplo se van a ir de vacaciones, o ante cualquier cambio en su rutina. "La Psiquiatra dice que los que amenazan con suicidarse son los que menos deben preocupar. Los preocupantes son los que no dicen nada...y Maragarita nunca lo dice."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='SANCHEZ'and apellido2='OBREGON'),'2017-11-15','Iciar: Llama el nieto, Juan Carlos Encinas para saber cómo recibir la herencia de Dolores. Se le informa de que la labor de la Comisión ha terminado, y que debería gestionarse de la misma manera que se hace ordinariamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2017-11-15','Iciar. Llamo a Orange, 1414, para comprobar si la linea móvil permanece de baja o han podido hacer algo para reactivarla. Me indican que la incidencia permanece abierta y que hoy se pondrán en contacto para informarnos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2017-11-15','(Pedro)Conversación con D. Gregorio, Alcalde de Valdecaballeros (628-556073). +++Requerimiento de derribo que se quedó en enviar, junto con presupuesto de derribo si lo hacía el Ayto (conversación de 12 de julio de 2016) no se ha enviado desde el Ayto. +++Tampoco hemos recibido los presupuestos solicitados a la hija de Carmen (volver a llamar) +++Hablará con el Arquitecto Municipal para ver cómo se puede hacer ello: requerimiento y coste de derribo municipal. +++PLANTEAMIENTO: si se hace cargo el Ayto, ver posibilidad de que la venta del solar puediera cubrir el coste del derribo: ya se le indica al Alcalde que ello no supone que se vaya a "malvender" ni a especular, pero sí que se trata de conseguir el mejor precio para nuestra tutelada, llegado el caso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2017-11-15','(pedro) Reunión con Mariloli a las 10:00h. +++Quiere ir con Antonio Merchán y un amigo la casa que tiene en Talavera la Real (quieren la llave). No nos han dicho nada desde el CRR. Llamaremos a Gisela. +++Compra de colchón por los problemas de espalda y cadera que padece. +++Quiere 10 "eurillos" más de paga semanal. ++++++++++++++++++++++++++Conversación con Gisela (T. Soc. del CRR) +++Vivienda de Talavera: tienen la idea de permitir que vayan un día (ida/vuelta) pero sin ver la casa: priumero debemos saber en qué condiciones se encuentra y además convendría que alguien del CRR les acompañara. +++Colchón:pedirán prepuesto y nos lo enviarán para su compra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2020-06-03','Ana: Registrada de ENTRADA la Comunicación de cambio de datos bancarios para el abono de la pensión a fecha de hoy.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-11-15','(Pedro) Conversación con Plena Inclusión de Llerena (924-870293). +++CRISTINA (DIRECTORA).Correo-e: He visto que habéis llamado, pero no he podido atender la llamada y ahora al devolvérosla no me lo coge nadie. Yo pensaba poneros correo hoy por aclarar varias cuestiones, paso a exponerle. Hoy pasado por la Asociación Silvia para conocer a Beatriz. No hemos querido decirle que es delegada tutelar ni que trabaja con la Comisión para que no se niegue a hablar con ella. Es más, le he dicho que es educadora social y en cuanto ha oido hablar de social ha dicho que no quería hablar con ninguna que sea social. Por tanto, en relación a la visita que planteaba al centro, preferiblemente no queremos que se produzca de momento. Por otro lado, desde menores se han puesto en contacto con Mercedes Rubio, nuestra trabajadora social y coordinadora del servicio de residencia. Le explican que quieren que pasada la primera semana del bebé en el domicilio de acogimiento se comiencen a producir las visitas por parte de Beatriz y también de Antonio (ellos proponen los dos juntos). Entiendo que en este caso, sois vosotros los que tenéis que dar el visto bueno y la autorización, por lo que necesito que nos vayáis informando al respecto. Igualmente, si los encuentros con el bebé se van a producir en breve, la psicóloga del centro ocupacional considera que debería ir informandola sobre este tema y trabajando con ella el tema de las visitas para que le resulte más llevadero y asuma progresivamente su situación. Nos gustaría que nos indicarais que os parece la propuesta y si autorizáis las sesiones de trabajo de la psicóloga en este sentido. +++Mª ÁNGELES (PSICÓLOGA): +++++Considera que la evolución de Beatriz está siendo bastante positiva y tiene la esperanza de que pueda llegar a adaptarse bastante bien en el Centro (sin forjarnos falsas expectaivas). Está participando en los tallerers de encuadernación, mostrándose colaboradora y con iniciativa. +++++Plantea que como los puntos están cerrando bien, pronto se marchará a su casa. La Psicóloga trata de hacerle ver que esto no va a ocurrir de inmediato, hablando de un periodo de meses para que Beatriz pueda tener alguna referencia temporal (está muy desorientada) pero tratando a su vez de no generar falsas expectativas en ella, con la esperanza de que en ese tiempo se haya podido alcanzar un buen nivel de adaptación. +++++Las Cuidadoras están también muy pendientes de ella y ella se muestra agusto también: le pintan las uñas, le ponen abalorios, etc. que hacen que Beatriz se sienta muy bien con ellas. +++++CONSULTAS: se han pedido ya para Neurología ("...el otro día decía que había visto un fanmtasma en la habitación...") y en Planificación Familiar. Y esta mañana ha acudido con una Cuidadora al banco para sacar dinero. +++++VISITAS FAMILIA: también considera que no es el momento de que nadie vea a Beatriz, porque podría ser perjudicial para su periodo de adapatación.DE VEZ EN CUANDO DICE QUE LA VA A TUTELAR SU TÍA (cuando hablemos con ella hay que decirle que no genere expectativas que no está en su mano cumplir). +++++VISITAS A ROCÍO: Mª Ángeles opina que en caso de querer que se produzcan, ello va a requerir un trabajo previo con Beatriz durante el tiempo que ello sea necesario. Se le indica que cuentan con la colaboración de la Comisión para todo lo que esté relacionado con Beatriz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2017-11-16','(Pedro) Conversdación con Mª Carmen, hija de Carmen. +++Enviará nuevamente los presupuestos (2) actualizados en el día de hoy. +++Cuando los envió, dichas cantidades eran de 8064 y 9719€. Comenta que en la actualidad hay una nueva ley sobre retirada de escombros que seguramente incrementará los mismos, por lo que se le pide que solicte su actualización. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con D. gregorio, Alcalde de Valdecaballeros. +++SE le pide que envié lo antes posible el informe del Arquitecto Municipal sobre el estado de ruina de la casa (hasta el martes no va al Ayto.) y que incluya en él una valoración del solar que quedaría tras su derribo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-11-02','PESIÓN PNC Se recibe resolución por la cual se informa que la nueva PNC de Beatriz asciende a 368.90€. Cobrará atrasos (3 meses) por una cuantía de 165,99€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIO'and edp.apellido1='RANGEL'and apellido2='MONROY'),'2017-11-02','PENSIÓN PNC Se recibe resolución modificando la cuantía de la PNC. Pasa de 368,90€ a 338€. Cobró indebidamente,y debe devolver a la Consejería de Sanidad y PP. SS. el importe de 278,10€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='MORENO'and apellido2='MOVILLA'),'2017-11-02','SALIDA El 02/11/2017. "Acudirá a Cáceres el jueves día 2, para participar en una actividad sobre naturalez organizada por Adenex. Está fuera de 9:00 a 19:00H del mismo día".','2');
