insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-11-08','CAMBIO DOMICILIO Beatriz se traslada a P. I. Llerena. Su dirección anterior era: C/ LANCHA VIEJA, 8 (HUERTAS DE ANIMAS), 10290, Trujillo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO'and edp.apellido1='GONZALEZ'and apellido2='ALVAREZ'),'2017-11-16','(Pedro) Conversación con María (927-223745), T. Soc. Novaforma. +++En relación a la comparecencia de la madre de älvaro ante la Fiscalía. +++SE SOLICITA INFORME por correo-e, que remitirán tanto por el mismo medio como por correo ordinario. +++Correos-e NOVAFORMA: +++++novaforma.novaforma@gmail.com +++++contabilidad.novaforma@gmail.com','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2017-11-16','Iciar: Después de la llamada de ayer de Jesús solicitando el amplificador, se llama a la escuela de música de Cáceres para preguntar por la asistencia de J.M. a las clases de guitarra. Nos comenta la secretaria que ha hablado con el profesor y que está contento con el comportamiento de J.M. y que acude con regularidad a las clases. Se le dice a J.M. que se comprará amplificador con la extra de Navidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2017-11-16','(Pedro) Conversación con Asunción Cabrera (24025). +++Sobre la conversación última mantenida en octubre. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Mª José (629 78 55 81), hermana de Manuel. +++ACTUACIÓN: +++++Se encargarán de hacer un PRESUPUESTO de las necesidades que para hacer habitable el piso consideren oportunas y nos lo enviarán a la CTAEx.En estos momentos no hay calentador, ni cocina, ni cama, etc. Planteo que un dormitorio y un comedor básicos, de momento (si va a comer a casa de su hermana) podría ser suficiente. El suelo de la cocina tiene varios terrazos rotos, con riesgo de tropiezo. +++++PETICIÓN IMPORTANTE: "NO QUEREMOS QUE NUESTRO HERMANO SEPA QUE ESTAMOS HACIENDO ESTO -pasos para amueblar mínimamente el piso- YA QUE SI SE ENTERA, VA A CONSOLIDARSE EN ÉL LA IDEA DE QUE HEMOS SIDO NOSOTROS LOS QUE LE HEMOS IMPEDIDO SALIR ANTES DEL CSS, como también nos culpa de haberlo metido en él..." +++++NO se consideran con capacidad para realizar un mínimo control del tratamiento, consultas ESM, etc. cuando su hermano esté en el piso, por las razones que se exponen en los apartados siguientes. +++RELACIONES FAMILIARES (IMPORTANTE): +++++"En las últimas ocasiones que mi hermano ha salido a Badajoz a estado con nosotras. Pero yo sé que, si tuviera dinero para irse a un bar a comerse un bocadillo, preferiría que fuera así para estar solo. El siempre busca su espacio" +++++"Mi hermano tiene problemas desde hace tiempo con mi marido, por lo que cuando sale yo voy a verlo a casa de mi hermana. El otro día no pude ir a verlo por la mañana y lo llame para tomar un café, pero no quiso..." +++++"Cuando esté en su piso, mucho me temo que no va a querer salir de su casa. Nunca nos ha dejado acceder a él, busca aislarse y nunca nos ha respetado." +++++Mi hermano solo funciona con la AUTORIDAD. Necesita que alguine con esa autoridad lo supervise porque él sí es consciente de quién tiene y quién no esa autoridad. Y para él nosotros nunca la hemos tenido."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2017-11-16','Iciar: En vista de que no tenemos conetestación de Orange, hablo con Toni para que den de alta una linea nueva de prepago para Felisa (hablado con Alberto). Nos manda por correo el presupuesto paRA dar de alta la linea. Irá Virginia con Felisa a la tienda el próximo lunes 20/11','2');
