insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-11-17','(Pedro) Conversación con Mª Ángeles. +++Más sonriente, aunque sigue con las mismas demandas. +++Citada en Neurología el lunes 20 a las 11:00. +++Prioridades: sus animales. Sobre el bebé no parece tener conciencia sobre lo que significa. +++Talleres. Relaciones todavía no muy normalizadas. +++ESTÁ CONTENTA. +++cADA VEZ USA MENOS EL TELÉFONO. +++La tía no ha vuelto a llamar.','2');
