insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2017-11-20','Iciar: HAblo con pablo, director del CRR de CC, para que nos envie informe de necesidad de realizar tratamiento odontológico a Antonia para pedir la autorización judicial. P. indica que actualmente Antonia está bastante inestable y en estas condiciones no sería óptimo hacer el tratamiento ahora, aún así nos envía el informe para solicitar la autorización judicial pues igual para cuando llegue se puede realizar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2017-11-20','-AMALIA: HABLO CON LOLY ( TS H.I.C ) EL TRASLADO A LA R.M. OLIVIENZA EN PLAZA PRIVADA SE HIZO DE MANERA VOLUNTARIA . DESDE EL CENTRO LE COMENTAN QUE ESTÁ MUY ADAPTADO Y DE DINERO DE BOLSILLO NECESITARÁ 2€/DIA. SU SOBRINA LE HA COMPRADO ROPA NUEVA . HAY QUE ABONAR 1300€/ MES POR LA PLAZA ( HA CONTADO CON LAS 14 PAGAS ) . HA SOLCITADO PLAZA PUBLICA POR DECRETO NO VALORADO POR DEPENDENCIA','2');
