insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2017-11-21','-AMALIA: LLAMA LOLY ( TS H.I.C.) PARA COMUNICAR QUE SE ENCUENTRA INGRESADA DESDE EL DIA 9/11 EN UHB. PATOLOGICAMENTE MEDIANAMENTE ESTABLE , INGRESA VOLUNTARIAMETNE POR CONSUMO DE DROGAS. HA SIDO DERIVADA A CEDEX Y VOLUNTARIAMENTE QUIERE INGRESAR EN CC.TERAPEUTICA. ACTUALMENTE NO HAY PLAZAS. NO POSILBLE DERIVACION A CSS NI A RECURSOS DE SALUD MENTAL POR CONSUMO . LA MADRE NO QUIERE LLEVARSELA A SU CASA .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CAMPA'and apellido2='SILGUERO'),'2017-11-21','-LLAMAN DESDE DEPENDENCIA , HA SIDO VALORADA Y QUIEREN QUE ACEPTEMOS PIA. SE PROPONE PLAZA EN CENTRO RESIDENCIAL . YA HACE UN AÑO QUE SE PIDIÓ AUTORIZACION PARA INGRESO INVOLUNTARIO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='VITA'and apellido2='GIL'),'2017-11-21','En relación con el procedimiento Diligencias Previas nº 72/2017, en que tiene la condición de denunciado por un delito/falta de acoso, se le cita a videoconferencia en la sede de los Juzgados de Llerena, el día 4/12/17, a las 10.15 h, para la declaración. Hasta ese día no le designan abogado del turno de oficio. Se lo comunico a Plena Incursión Llerena.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2017-11-21','Iciar: Llama Fco de la empresa de fumigaciones para concertar una cita para pasar por la casa de RAmón a terminar el tratamiento de plagas. Hablará con Juan, hermano de Ramón, por si pudiera estar allí pues quiere acudir al domicilio acompañado. En el caso de que no pudiera Juan, he hablado con TOny de Futuex para que vaya Silvia. Comenta Francisco que si todavía aparecen cucarachas en casa de Ramón es debido a que falta por realizar este tratamiento último, y si fuera necesario actuaría de nuevo pasadas unas semanas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2017-11-21','El Juzgado de 1º. Instancia e Instrucción nº 1 de Mérida, concede Autorización Jud nº 213/2017, para vender la parte que tiene, junto con su madre (usufructo) y hermanos de la vivienda sita en C/. Espadán nº 10-1º, de Cáceres. Se lo comunico por correo electrónico a su hermano Miguel Ángel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TERESA'and edp.apellido1='NEVADO'and apellido2='MARTIN'),'2017-11-21','Iciar: Recibimos la designación de abogado de oficio','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2017-11-21','(Pedro)Conversación con Inés. Enfermera de la Residencia de Jaraicejo (699-036400). +++INGRESO EN H. SAN PEDRO DE ALCÁNTARA: 22-11-2017. +++INTERVENCIÓN: 23-11-2017 +++MOTIVO: estirpar pólipo endometrial por laparoscopia e histerometría. +++HERMANA: si Isabel quería que fuese a verla el día de la operación le tenía que pagar el viaje. Isabel le dijo que no quería que fuese a verla, porque no quería estar con su familia. +++ESM de Plasencia: acude regularmente, los controles dan resultados positivos y se le está rebajando la medicación. +++FIRMÓ ELLA EL CONSENTIMIENTO INFORMADO para autorizar la intervención: explico que ella no tiene capacidad juridica para ello. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con José A., Jefe del Servicio de Ginecología del Hospital (56318).También hablo con mamen, T. Soc. del Hospital. +++Se le informa de la incidencia anterior. Nos enviará el nuevo consentimineto para su firma en la Comisión y posterior remisión. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Convesración con Toni (Futuex) +++Mañana Alicia acompañará a Isabel en el ingrteso y estará también el día de la intervención. +++Averiguará si va a necesitar acompañamiento y el tiempo aproximado de estancioa en el Hospital. +++HERMANA: plantea cuidarla siempre y cuando se le pague dicho "trabajo".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2017-11-22','En relación con el expediente de Remoción de tutor 530/2016, para que la Comunidad Autónoma de Castilla y León asuma la tutela de Margarita, el Juzgado de 1ª. Instancia e Instrucción nº 3, de Ávila (920359022-Aurora), nos envía Providencia, de fecha 26/10/2017, indicándonos que van a remitir las actuaciones al Decanato de Valladolid, para que, por segunda vez, se requiera a la Fundación de Acción Social y Tutela de Castilla y León, asuma o no el cargo de la tutela de Margarita y preste Audiencia, dado que Feclem no aceptó el cargo y en el caso de no aceptarlo explique los motivos por los que no lo acepta. Hablo con el Decanato de Valladolid (Alfonso 983459574) y me dicen que allí no ha llegado ninguna documentación al respecto. Vuelvo a llamar al Juzgado de Ávila y hablo con Aurora. Me dice que igual es que no lo han enviado y que tienen una compañera de baja, que puede ser el motivo, debido al volúmen de trabajo del Juzgado. Me indica que va a intentar encargarse ella personalmente. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro) Lo pongo en conocimineto de Soraya y le indico que vamos a hacer la consulta a Curro sobre cómo proceder.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2017-11-21','- sigue ingresado en UME PLASENCIA desde el 16 de octubre de 2017 . Se lo informo a Pepa Ugalde, al parecer el expete está en Bajoz. está pte. valoracion de grado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTOR'and edp.apellido1='GALAN'and apellido2='ANDRADA'),'2017-11-22','ARCHIVO Se cierra el expte. Se recibe firmeza el 22/11/2017. Se nombra tutor a su hermano D. Alfonso Galán Andrada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2017-11-22','(Pedro)Llamada de Dª JUlia, madre de José Mª. +++Les es muy oneroso el ir a ver a su hijo. +++Necsita ropa: se le explica que esa petición debe venir del centro. +++Quiere que pueda salir a su casa, porque si no se pone muy nervioso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PAULA'and edp.apellido1='SOLANA'and apellido2='GUERRA'),'2017-11-22','-VUELVO A CONTACTAR CON VALENTINA PARA RETOMAR EL CASO. HA CONTACTADO CON LILIANA PERO NO COINCIDEN EN EL INGRESO. QUIERE IR AL DOMICILIO A VERIFICAR CIERTAS INFORMACIONES. SOLICITO A FUTUEX QUE SE PONGA EN CONTACTO CON VALENTINA PARA IR JUNTAS A LA VISITA Y OBTENER MÁS INFORMACION . QUEDAMOS PTE. EL INGRESO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2017-11-22','(Pedro)Conversación con el Juzgado nº 5 de Cáceres (DPA 246/17). +++Si en la declaración realizada por D. Manuel se hace constar que está incapacitado, será el Juzgado el que pedirá la Sentencia al Juzgado que la dictó. Nosotros desconociamos dicha situación y no hemos pedido nada al respecto hasta el momento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='PEREZ'and apellido2='SANTOS'),'2017-11-22','HABLAMOS CON JESÚS IGLESIAS (691482871) PRESIDENTE DE LA COMUNIDAD DE LA VIVIENDA DE JOSEFA. LE COMUNICAMOS QUE VAMOS A PAGAR LOS 681€ DE DEUDA DE COMUNIDAD DESDE EL 2014 A 2017. QUEDAMOS PENDIENTES DE QUE NOS ENVIE LA NUEVA CANTIDAD A PAGAR A PARTIR DE ENERO 2018 PARA HACER UNA ORDEN DE TRANSFERNCIA PERMANENTE. (M. JOSE)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2017-11-21','(Pedro)Conversación con José A. Pulido, T. Soc. de los Pisos Tutelados de Almoharín (654-222195). +++Vanesa es muy reacia a permanecer el piso. +++Han tratado de negociar con ella una salida al mes para pasar un fin de semana con su madre, pero lo cierto es que se está yendo con ella todos los fines de semana (su madre trabaja en Miajadas cuidando a una señora). +++Pone un sin fin de excisas para no querer estar en el piso: que la habitación es pequeña (la cambiaron a otra individual y más grande), que se le quita el teléfono por la noche, que tiene poco dinero de bolsillo (se le entrega todo el que queda tras pagar la plaza), etc. Lo que ocurre realmente es que no quiere estar ni en este ni en ningún centro, porque además ella se considera con capacidades muy superiores a las de los demás residentes. +++José A. decide que van a esperar un posco más a ver cómo evoluciona. Le propongo que emita un Informe a la gerencia territorial para que sea conocedora de la situación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2017-11-22','Iciar: Recibimos adjudicación de abogado de oficio - José Luis Malpartida Villegas, y de procuradora Beatriz Morales Vecino para J.M.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2017-11-22','(Pedro) Conversación con Toni (Futuex). +++Acudirán a Valdecaballeros para poner la casa en manos de alguna inmobiliaria de la zona: +++++Pedirán presupuesto para tasarla. +++++Posteriormente, si es asumible, venderla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2017-11-22','Correo-e de Toni, Futuex: +++ sobre el tema de Isabel Muñoz que reside en en residencia mayores de Jaraicejo y que está ingresada desde hoy para histerectomía en el virgen de la montaña, la delegada ha estado allí, tal y como comentamos, y mañana estará también para la intervención. Ha preguntado, Alicia, los dias de hospitalización y se tendría drenaje o necesitaría de algún cuidado especial, y comentan desde el hospital que puede estar sola. Además Isabel es lo que ha indicado. Ellos, desde el hospital, le controlan medicación, ya tienen la pauta, dicen que al día siguiente de la operación normalmente ya se levantara ella sola y todo. Alicia les he dicho que estará sola y en principio no hay problema ellos se encargarán de medicación y todo, aun no tienen la lista de quirófano de mañana pero le han preguntado al medico y dicen que no va a ser la primera asique sobre las 10 quizás, será la hora de la intervención.','2');
