insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-11-24','Iciar: Hablamos con Vodafone -607123000- para pasar teléfono móvil 606021075 de B. de contrato a prepago. Hay que pagar una penalización por permanencia de 11,24€ y los plazos del aparato de 55€ antes de poder pasar a prepago. Una vez hecho podremos hacer el paso telefónicamente. La gestión de la penalización la hacen en el momento nº solicitud I76715861, lo pasarán en próxima factura. El pago de los plazos nos llaman para confirmar. Se tiene que dar un código de 4 dígitos,que será la clave que habrá que dar, le doy 6800 (nuestro código postal para recordar) para cualquier contratación o para pagar los plazos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2017-11-24','Iciar. hablo con la residencia de Jaraicejo- 699036400- para informarles que según el jefe de Ginecología - José A. Lojas ext 56318- a Isabel le dan el alta mañana o pasado. Comento la posibilidad de que vayan a recogerla. La enfermera de la residencia llama al San Pedro para ver si le ponen ambulancia y cuándo exactamente le dan el alta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2017-11-24','Iciar. Hablo con Jazztel -t/c 1565-. Tiene contratada una linea fija 924 95 51 03 y 6 líneas móviles adicionales. La factura de 27/10 asciende a 524,96€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2017-11-24','Iciar. Inés, la enfermera de Jaraicejo nos llama para informarnos que ha hablado con el hospital y mañana sábado después de la comida darán el alta a Isabel. Desde la Residencia ya han acordado con la persona que normalmente la lleva al médico en Plasencia para que vaya a recogerla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='REDONDO'and apellido2='GOMEZ'),'2017-11-24','ARCHIVO EXPEDIENTE Se recibe DIOR, junto con el testimonio de la Sentencia de Incapacitación y nombramiento de tutor a su sobrino, D. JUAN CARLOS RODRIGO REDONDO, por parte del Jzdo. nº. 2 de Castuera.***************************************************Con fecha 24/07/2017, se solicitó confirmación de firmeza al Jzdo. anteriormente expuesto. Contestó, mediante DIOR, que aún no había adquirido dicha firmeza.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='VALADES'and apellido2='DIAZ'),'2017-11-27','(Pedro). Visita de Isabel. 8:45h. +++Quiere la extra de Navidad para : +++++gafas. +++++arreglarse lo juanetes. Ya le propusieron operarse hace algún tiempo pero no quiso entonces. +++ACUERDO: +++++Traerá todos los comprobantes de la deudas que dice tener. Incialmente comenta que son de dos tiendas: de un "chino" y de una tienda de ropa. TRAS INSISTIR EN ELLO, refiere "...Pues te voy a traer todas las deudas que tengo, porque creo que son más (con una sonrisa "mordad")". +++++Una vez vistos los comprobantes de deuda, aquellos que se considerenb justificables se pagaraán con la autorización de una extra por dicho importe total para que sea abonado por Isabel (no quiere que sea de otra forma) y luego NOS TRAERÁ DICHOS COMPROBANTES CON LA CORRESPONDIENTE IDICCACIÓN DE PAGADOS. +++++Aquellas deudas que no se consideren justificables, deberá abonarlas de su mensualidad.','2');
