insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2017-11-28','-VISITAMOS A CARMEN EN SU DOMICILIO , NOS ABRE LA PUERTA PERO NO NOS INVITA A ENTRAR . HABLAMOS UNOS MINUTOS CON ELLA . ESTÁ HACIENDO GESTIONES PARA VENDR LA CASA DE C/ MACON POR SU CUENTA . SE LE INSISTE EN QUE NO PUEDE HACER ESTA GESTION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GABRIEL'and edp.apellido1='SOBRINO'and apellido2='TARDIO'),'2017-11-30','Vuelvo a hablar hoy con el Juzgado de Villanueva, en relación con el Internamiento involuntario. Me dicen que va a fijarse el día 5 de diciembre para que lo vea el forense en Villanueva. Le digo que adelante la fecha. Después me llama el Juzgado y me dice que el forense va a reconocerlo al Hospital de Don Benito hoy mismo. Le envío al Juzgado certificado del Cadex, para que se lo envíe al forense. Hablo con Fiscalía de Villanueva para que agilice lo que pueda. Hablo con Jesús, trabajador social del Hospital de Don Benito, me dice que Francisco ya va andando por los pasillos, pero que pueden alargar el alta hasta que tenga que irse al Juzgado de Villanueva el dia 5, día en el que el Juzgado probablemente dicte el Auto autorizándonos para que sea ingresado y así no tenga que irse a su casa. Se le ha diagnosticado un linfoma y va a tener que recibir quimio. Me envía Informe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO'and edp.apellido1='BLANCO'and apellido2='LUQUE'),'2017-11-30','Nos envían propuesa de venta de varias fincas, incluidas en la herencia de los padres de Diego, El piojal y La Asomá. Acreditar documentalmente la propiedad es difícil porque no coinciden datos de catastro y registro de la propiedad. Hablo con Claudio, hermano y me indica que es debido a que hubo acuerdos, ventas de partes de fincas entre ascendientes, que no se modificaron en el catastro y que al margen, no va compensarles venderlas por el poco dinero que obtendrían, una finca la querían vender por 5.076 euros y la otra por 2.400 euros. Habría que hacer una tasación de las fincas, para pedir autorización judicial, más los gastos de notaría. Son 5 hermanos. En principio no quieren seguir con la venta de estas fincas. Me indica que las relaciones familiares no son muy buenas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2017-11-30','Hemos pedido autorización judicial para gastos extraordinarios de 1350 euros, cantidad a la que ha sido condenada su hija, María Carolina Raya Montaña, para evitar su ingreso en prisión. Hemos recibido Diligencia de Ordenación, trasladando la solicitud a la Fiscalía para que informe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='JIMENEZ'and apellido2='RUIZ'),'2017-11-30','En relación con el ingreso involuntario de Francisco, vuelvo a llamar al Juzgado de Villanueva, para insistir en el Expediente que lleva enviado desde noviembre de 2016. Hablo con la Secretaria del Juzgado. Me indican que en principio el reconocimiento forense fijado para el día 5 de diciembre, lo han adelantado a hoy. El forense irá al Hospital a reconocerlo. Posteriormente, Francisco tendrá que ir al Juzgado ese día, o si lo adelantan cuando nos digan, para que se dicte el Auto de internamiento y así, el traslado desde el Hospital de Don Benito se haga directamente al centro donde tengamos plaza. Hablo con Fiscalía a los efectos que se ponga en contacto con el Juzgado de Villanueva para intentar agilizar este proceso. Jesús, el Trabajador Social del Hospital de Don Benito nos envía Informe Social que remitimos a su vez al Juzgado de Villanueva. En el Hospital, le han detectado un linfoma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='JIMENEZ'and apellido2='RUIZ'),'2017-11-29','-SOLICITO CAMBIO PIA A PLAZA RESIDENCIAL DE MAYORES POR EMPEORAMIENTO , SE LE HA DETECTADO LINFOMA Y ESTÁ INGRESADO EN HOSPITAL DON BENITO . - TS . DEL HOSPITAL JESUS ( 86647)','2');
