insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2017-12-02','SALIDA En 02/12/2017. "Desde la entidad confirmamos que Mª. Antonia tiene previsto hacer un viaje a Madrid por motivos familiares el próximo sábado 02/12/2017. Mª. Antonia estará acompañada por sus primas y tía con quienes convive y se relaciona en la actualidad". P. I. Zafra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2017-12-01','LLAMA MARIVÍ DEL CENTRO SOCIOSANITARIO PARA INFORMAR QUE JUAN SALDRÁ DEL 5 AL 7 DE DICIEMBRE PORQUE EL PSIQUIATRA LE HA DADO PASE. LE DARÁN 150€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='JIMENEZ'and apellido2='RUIZ'),'2017-12-04','(Pedro) Converación con Jesús, T. Soc. del H. Don Benito-Vva (86647). +++Francisco se encuentra bien. +++Finalmente no se le va a hacer la prueba por el linfoma para determinar el diagnóstico, dado que el mismo está claro en base a las pruebas de hematología. +++El tratamiento se le pondrá, una vez que salga de alta, cuando se le cite en consulta. +++Estamos pendientes de la autorización judicial. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con May: presentación del caso. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Envío por fax (924-174310) de la solicitud de cambio de PIA a Pilar Álvarez (Jefa de Sección Dependencia IV). ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Nueva conversación con Pilar: ya están trabajando para la asignación de plaza para mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='VALADES'and apellido2='DIAZ'),'2017-12-04','(Pedro). Visita de Isabel (8:35). +++Solamente quería entregar justificantes de las deudas que dice tener. +++Quiere que le demos la paga extra para pagarlas ella misma. +++Confirmar con Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GUTIERREZ'and apellido2='ALMARZA'),'2017-12-04','Remiten desde la Residencia la Granadilla exhorto del Juzgado de 1ª Instancia nº 4 de Mérida para la solicitud de nuevo abogado por jubilación del anterior.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2017-12-01','(Pedro). Reunión en CSS Mérida con la Comsiión de acceso a UME. Ingresará el lunes, 04 de diciembre en UME. Gestiones por realizar: +++Cancelar el contrato de alquiler. +++Autorizar a UME 90€/mes para gastos personales. +++Dar de baja línea de teléfono, internet, etc. también suministros caso de estar a su nombre. +++Limpieza del piso: su madre se encargará de solicitar presupuesto a empresas de limpieza y desinfección que nos enviará a la Comisión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2017-12-04','Ingresa hoy,lunes, 04 de diciembre en UME del CSS Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2017-12-05','(Pedro). Conversación con Isabel (Psicóloga). Pisos Supervisados de Zafra.924-563092. +++NO se adapta al Centro, con picos de agresividad y autoagres. +++Ingresó en la UHB de Llerena el 30 de noviembre ante la última crisis manifestada. SE MANTIENE EL INGRESO EN ESTOS MOMENTOS. +++Considera que Josefa tiene un perfil de salud mental más que de discapacidad. +++ENVIARÁ INFORME DE SITUACIÓN A LA TERRITORIAL DEL SEPAD EN BADAJOZ y a la CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='SANCHEZ'and apellido2='LIRON'),'2017-12-05','(Pedro). Intento hablar con Mateo, T. Soc. SSB de Torre de Santa María (927-388127). +++Está de vacaciones hasta el martes que viene.Volver a llamar. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a Rosa, Directora de la Residencia de Torre de Santa María (927-389074). +++D. Antonio se encuentra perfectamente integrado en el centro y muy contento con los residentes y personal que lo atiende. +++++FÍSICAMENTE se encuentra bien, pero tienen que acudir con frecuencia a Cáceres dado el problema de próstata que tiene. Lo han ciatado ahora para dentro de 8 meses. +++VISITAS: Lo visita su hermano D. Luis Fernando, que a veces acude con su mujer y su hijo. +++++Rosa refiere que en la última visita el hermano se enfadó mucho con él y con el centro porque se había gastado mucho dinero en ropa (en la tienda habían ido haciendo una cuenta a nombre de D. Antonio y la última factura recogía el gasto de los dos últimos años). "Yo no entiendo -dice Rosa- por qué se tuvo que enfadar. El dinero es de D. Antonio y la ropa que se le ha comprado la necesitaba.Además, cuando viene a visitarlo es D. Antonio el que siempre paga en la cafetería, pero no solo lo de su hermano, también lo de su mujer y su hijo...Como yo digo, si cuando su hermano fallezca todo va a ser para él, no sé por qué se enfada" +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++CONVERSACIÓN CON D. ANTONIO. +++"Yo NO ME QUIERO IR DE AQUÍ, porque estoy muy contento con Rosa y con Ana que me compra la ropa y estoy muy bien atendido. Por eso NO ME QUIERO IR DE AQUÍ. pero lo que sí quiero es que, en vez de pagarle a Rosa 700€ (la plaza) le paguéis 750€ y los 50€ de más al mes que me los administre ella para poder tomarme un café, etc. (Preguntado por si consumía alcohol) No bebo nada desde hace años, cuando me separe de mi mujer." +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Nueva conversación con Rosa, con las siguientes indicaciones: +++Cualquier necesidad que D. Antonio tenga se le comunica a la Comisión. No tiene por qué estar sin algo que necesite teniendo su dinero (le parezca lo que le parezca a los demás). +++++PRESUPUESTO MENSUAL DE GASTOS ORDINARIOS: se le indica a Rosa que elaboren un presupuesto mensual con los gastos habituales (tabaco, café, peluquertía, podología, etc.) y nos lo envíe para valorarlo y autorizarlo en su caso, de forma que ella lo administre a lo largo del mes (es lo que demanda D. Antonio). +++++GASTOS EXTRAORDINARIOS: se indica a Rosa que, en caso de gastos como compra de ropa, gafas, etc., se ponga en contacto con la Comisión presentando uno o varios presupuestos (según concepto) para valorar y en su caso autorizar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN'and edp.apellido1='GUTIERREZ'and apellido2='RONCERO'),'2017-12-05','(Pedro) Llama Julian preguntando por la venta del piso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='SANCHEZ'and apellido2='LIRON'),'2017-12-04','Desde hace unos días llama D. Luis Fernando Sánchez Lirón (629-074025), hermano de D. Antonio, con la siguinete y única demanda: "Me quiero llevar a mi hermano a la Residencia Privada de Navalmoral de la Mata y me lo quiero llevar lo antes posible...".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='JIMENEZ'and apellido2='RUIZ'),'2017-12-05','Ingreso de D. Francisco hoy, 4 de diciembre, en el Centro Residencial de Mayores "Felipe Trigo".','2');
